$_tipsdb['CGIPriority'] = new DAttrHelp("Prioridad CGI", 'Especifica la prioridad del proceso de aplicación externa. El valor va de <span class=&quot;lst-inline-token lst-inline-token--value&quot;>-20</span> a <span class=&quot;lst-inline-token lst-inline-token--value&quot;>20</span>. Un número menor significa una prioridad mayor.<br/><br/>Un proceso CGI no puede tener una prioridad mayor que la del servidor web. Si esta prioridad se establece en un número menor que la del servidor, se usará la prioridad del servidor para este valor.', '', 'entero', '');

