$_tipsdb['adminUserName'] = new DAttrHelp("Nombre de Usuario", 'Especifica el nombre de inicio de sesion de la consola WebAdmin. Use de 1 a 25 caracteres: letras, digitos, punto, guion bajo o guion.', '', '', '');

$_tipsdb['allowBrowse'] = new DAttrHelp("Accesible", 'Especifica si se puede acceder a este contexto. Establezca <span class=&quot;lst-inline-token lst-inline-token--value&quot;>No</span> para denegar el acceso. Puede usar esta funcion para proteger el directorio especificado contra visitas. Puede usarla al actualizar contenido para este contexto o cuando haya datos especiales en este directorio.', '', 'Seleccionar desde botones de opción', '');

$_tipsdb['allowQuic'] = new DAttrHelp("Abrir puerto HTTP3/QUIC (UDP)", 'Permite el uso del protocolo de red HTTP3/QUIC para los virtual hosts asignados a este listener. Para que esta opcion tenga efecto, &quot;Habilitar HTTP3/QUIC&quot; tambien debe establecerse en <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Yes</span> a nivel de servidor. El valor predeterminado es <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Yes</span>.', 'Cuando esta opcion se establece en <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Yes</span>, HTTP3/QUIC aun puede deshabilitarse en el nivel de virtual host mediante la opcion &quot;Habilitar HTTP3/QUIC&quot;.', '', '');

$_tipsdb['allowSetUID'] = new DAttrHelp("Permitir Set UID", 'Especifica si se permite el bit set UID para scripts CGI. Si el bit set UID esta permitido y habilitado para un script CGI, sin importar en nombre de que usuario se inicio el script CGI, el ID de usuario del proceso CGI cambiara al ID de usuario del propietario del script CGI.<br/>El valor predeterminado es &quot;Off&quot;.', ' No permita scripts CGI Set UID siempre que sea posible, ya que es inherentemente un riesgo de seguridad.', 'Seleccionar desde botones de opción', '');

$_tipsdb['allowSymbolLink'] = new DAttrHelp("Seguir enlaces simbolicos", 'Especifica si se deben seguir enlaces simbolicos en este virtual host. La opcion <span class=&quot;lst-inline-token lst-inline-token--value&quot;>IF OWNER MATCH</span> seguira un enlace simbolico solo si tiene el mismo propietario. Esta opcion reemplaza la configuracion predeterminada de nivel de servidor.', ' Para mayor seguridad, deshabilite esta funcion. Para mejor rendimiento, habilitela.', 'Seleccionar de la lista desplegable', '');

$_tipsdb['antiddos_blocked_ip'] = new DAttrHelp("IP bloqueada por Anti-DDoS", 'Lista de direcciones IP separadas por comas y bloqueadas por la protección Anti-DDoS. Cada dirección termina con un punto y coma y un código de motivo que indica por qué se bloqueó la dirección IP.<br/><br/>Códigos de motivo posibles: <ul>   <li><span class=&quot;lst-inline-token lst-inline-token--value&quot;>A</span>: BOT_UNKNOWN</li>   <li><span class=&quot;lst-inline-token lst-inline-token--value&quot;>B</span>: BOT_OVER_SOFT</li>   <li><span class=&quot;lst-inline-token lst-inline-token--value&quot;>C</span>: BOT_OVER_HARD</li>   <li><span class=&quot;lst-inline-token lst-inline-token--value&quot;>D</span>: BOT_TOO_MANY_BAD_REQ</li>   <li><span class=&quot;lst-inline-token lst-inline-token--value&quot;>E</span>: BOT_CAPTCHA</li>   <li><span class=&quot;lst-inline-token lst-inline-token--value&quot;>F</span>: BOT_FLOOD</li>   <li><span class=&quot;lst-inline-token lst-inline-token--value&quot;>G</span>: BOT_REWRITE_RULE</li>   <li><span class=&quot;lst-inline-token lst-inline-token--value&quot;>H</span>: BOT_TOO_MANY_BAD_STATUS</li>   <li><span class=&quot;lst-inline-token lst-inline-token--value&quot;>I</span>: BOT_BRUTE_FORCE</li> </ul><br/><br/>La lista completa de IP bloqueadas también está disponible en el archivo de informe de estadísticas en tiempo real definido en &quot;Directorio de salida de estadisticas&quot;.', '', '&lt;blocked_ip_address&gt;;&lt;reason_code&gt;', '1.0.100.50;E, 1.0.100.60;D, 1.0.100.70;F');

$_tipsdb['appServerContext'] = new DAttrHelp("Contexto de servidor de aplicaciones", 'Un contexto de servidor de aplicaciones ofrece una forma sencilla de configurar una aplicacion Ruby Rack/Rails, WSGI o Node.js. Para agregar una aplicacion mediante un contexto de servidor de aplicaciones, solo se requiere montar la URL y el directorio raiz de la aplicacion. No hace falta definir una aplicacion externa, agregar un manejador 404 ni configurar reglas de reescritura, etc.', '', '', '');

$_tipsdb['appType'] = new DAttrHelp("Tipo de aplicacion", 'El tipo de aplicacion usado para este contexto. Se admiten Rack/Rails, WSGI o Node.js.', '', '', '');

$_tipsdb['appserverEnv'] = new DAttrHelp("Modo de ejecución", 'Especifica el modo en que se ejecutará la aplicación: &quot;Development&quot;, &quot;Production&quot; o &quot;Staging&quot;. El valor predeterminado es &quot;Production&quot;.', '', 'Seleccionar de la lista desplegable', '');

$_tipsdb['as_location'] = new DAttrHelp("Ubicacion", 'Especifica la ubicacion correspondiente de este contexto en el sistema de archivos.<br/><br/>Valor predeterminado: $DOC_ROOT + &quot;URI&quot;', '', 'Puede ser una ruta absoluta o una ruta relativa a $SERVER_ROOT, $VH_ROOT o $DOC_ROOT. $DOC_ROOT es la ruta relativa predeterminada y puede omitirse.<br/><br/>Si &quot;URI&quot; es una expresion regular, la subcadena coincidente puede usarse para formar la cadena &quot;Root&quot;. La subcadena coincidente puede referenciarse con los valores &quot;$1&quot; - &quot;$9&quot;. &quot;$0&quot; y &quot;&&quot; pueden usarse para referenciar toda la cadena coincidente. Ademas, puede establecerse una cadena de consulta agregando &quot;?&quot; seguido de la cadena de consulta. Tenga cuidado. &quot;&&quot; debe escaparse como &quot;\&&quot; en la cadena de consulta.', 'Una URI simple como <span class=&quot;lst-inline-token lst-inline-token--value&quot;>/examples/</span> con &quot;Ubicacion&quot; establecido en <span class=&quot;lst-inline-token lst-inline-token--value&quot;>/home/john/web_examples</span> mapeara la solicitud &quot;/examples/foo/bar.html&quot; al archivo &quot;/home/john/web_examples/foo/bar.html&quot;.<br/>Para simular mod_userdir de Apache, establezca URI en <span class=&quot;lst-inline-token lst-inline-token--value&quot;>exp: ^/~([A-Za-z0-9]+)(.*)</span>, establezca &quot;Ubicacion&quot; en <span class=&quot;lst-inline-token lst-inline-token--value&quot;>/home/$1/public_html$2</span>. Con esta configuracion, una solicitud de URI /~john/foo/bar.html se mapeara al archivo /home/john/public_html/foo/bar.html.');

$_tipsdb['as_startupfile'] = new DAttrHelp("Archivo de inicio", 'La ubicacion del archivo usado para iniciar la aplicacion, relativa al directorio raiz de la aplicacion.<br/><br/>Los nombres predeterminados de archivo de inicio incluyen &#039;config.ru&#039; para Rack/Rails, &#039;wsgi.py&#039; y &#039;passenger_wsgi.py&#039; para WSGI, y &#039;app.js&#039; para NodeJS.', '', 'Ruta relativa al directorio raiz de la aplicacion', '');

$_tipsdb['authName'] = new DAttrHelp("Nombre de autenticacion", 'Especifica un nombre alternativo para el realm de autorizacion del contexto actual. Si no se especifica, se usara el nombre de realm original. El nombre de autenticacion se muestra en la ventana emergente de login del navegador.', '', '', '');

$_tipsdb['autoFix503'] = new DAttrHelp("Corregir automaticamente error 503", 'Especifica si se debe intentar corregir el error &quot;503 Service Unavailable&quot; reiniciando el servidor de forma graceful. Un error &quot;503&quot; suele estar causado por aplicaciones externas defectuosas y un reinicio del servidor web a menudo puede corregir temporalmente el error. Si esta habilitado, el servidor se reiniciara automaticamente cuando haya mas de 30 errores &quot;503&quot; en un periodo de 30 segundos.<br/><br/>Valor predeterminado: <span class=&quot;lst-inline-token lst-inline-token--value&quot;>No</span>', '', 'Seleccionar desde botones de opción', '');

$_tipsdb['autoIndex'] = new DAttrHelp("Índice automático", 'Especifica si se genera un índice de directorio al vuelo cuando los archivos de índice indicados en &quot;Archivos indice&quot; no están disponibles en un directorio. Esta opción se puede personalizar a nivel de virtual host y de contexto, y se hereda a lo largo del árbol de directorios hasta que se sobrescribe explícitamente. Puede personalizar la página de índice generada. Consulte los How-tos del wiki en línea.', ' Se recomienda desactivar Índice automático siempre que sea posible para evitar revelar datos confidenciales.', 'Seleccionar desde botones de opción', '');

$_tipsdb['autoIndexURI'] = new DAttrHelp("URI de índice automático", 'Especifica la URI que se usará para generar la página de índice cuando los archivos de índice indicados en &quot;Archivos indice&quot; no estén disponibles en un directorio. LiteSpeed web server usa un script externo para generar la página de índice, lo que proporciona la máxima flexibilidad de personalización. El script predeterminado produce una página de índice con el mismo aspecto que la de Apache. Para personalizar la página de índice generada, consulte los How-tos del wiki en línea. El directorio que se va a indexar se pasa al script mediante una variable de entorno &quot;LS_AI_PATH&quot;.', '', 'URI', '');

$_tipsdb['autoLoadHtaccess'] = new DAttrHelp("Carga automatica desde .htaccess", 'Carga automaticamente reglas rewrite contenidas en el archivo .htaccess de un directorio al acceder por primera vez a ese directorio si aun no existe un HttpContext para ese directorio que use la directiva <b>rewritefile</b>. Una vez cargado inicialmente, debe realizarse un reinicio graceful para que cualquier cambio posterior en ese archivo .htaccess tenga efecto.<br/><br/>La opcion de nivel Virtual Host reemplaza la opcion de nivel Servidor. Valores predeterminados:<br/><br/><b>Nivel Servidor:</b> No<br/><br/><b>Nivel VH:</b> Heredar configuracion de nivel Servidor', '', 'Seleccionar desde botones de opción', '');

$_tipsdb['autoStart'] = new DAttrHelp("Iniciar por el servidor", 'Especifica si desea que el servidor web inicie la aplicacion automaticamente. Solo las aplicaciones FastCGI y LSAPI que se ejecutan en la misma maquina pueden iniciarse automaticamente. La IP de &quot;Direccion&quot; debe ser una IP local. Iniciar mediante LiteSpeed CGI Daemon en lugar de un proceso principal del servidor ayudara a reducir la sobrecarga del sistema.<br/><br/>Valor predeterminado: Yes (Through CGI Daemon)', '', 'Seleccionar de la lista desplegable', '');

$_tipsdb['backlog'] = new DAttrHelp("Backlog", 'Especifica el backlog del socket de escucha. Obligatorio si &quot;Iniciar por el servidor&quot; esta habilitado.', '', 'Número entero', '');

$_tipsdb['banPeriod'] = new DAttrHelp("Periodo de bloqueo (segs)", 'Especifica durante cuánto tiempo se rechazarán nuevas conexiones desde una IP si, después de transcurrir &quot;Periodo de gracia (segs)&quot;, el número de conexiones sigue siendo superior a &quot;Límite flexible de conexiones&quot;. Si las IP se bloquean repetidamente, sugerimos aumentar el periodo de bloqueo para endurecer la penalización por abuso.', '', 'Número entero', '');

$_tipsdb['binPath'] = new DAttrHelp("Ruta binaria", 'La ubicacion del binario de la aplicacion App Server.', '', '', '');

$_tipsdb['blockBadReq'] = new DAttrHelp("Bloquear solicitudes incorrectas", 'Bloquea las IP que siguen enviando solicitudes HTTP con formato incorrecto durante &quot;Periodo de bloqueo (segs)&quot;. El valor predeterminado es <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Yes</span>. Esto ayuda a bloquear ataques de botnets que envían solicitudes basura repetidamente.', '', 'Seleccionar desde botones de opción', '');

$_tipsdb['brStaticCompressLevel'] = new DAttrHelp("Nivel de compresión Brotli (archivo estático)", 'Especifica el nivel de compresión Brotli aplicado a archivos estáticos. Va de <span class=&quot;lst-inline-token lst-inline-token--value&quot;>0</span> (deshabilitado) a <span class=&quot;lst-inline-token lst-inline-token--value&quot;>11</span> (más alto).<br/><br/>Cuando se establece en <span class=&quot;lst-inline-token lst-inline-token--value&quot;>0</span>, la compresión brotli se deshabilita globalmente.<br/><br/>Valor predeterminado: 5', ' Ahorra ancho de banda de red. Las respuestas basadas en texto, como archivos html, css y javascript, se benefician más y, en promedio, pueden comprimirse a la mitad de su tamaño original.', 'Número entre 0 y 11.', '');

$_tipsdb['bubbleWrap'] = new DAttrHelp("Contenedor Bubblewrap", 'Establézcalo en <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Enabled</span> si desea iniciar procesos CGI (incluidos programas PHP) en un sandbox de bubblewrap. Consulte <a href="   https://wiki.archlinux.org/title/Bubblewrap " target="_blank" rel="noopener noreferrer">   https://wiki.archlinux.org/title/Bubblewrap </a> para obtener detalles sobre el uso de bubblewrap. Bubblewrap debe estar instalado en su sistema antes de usar este ajuste.<br/><br/>Este ajuste no se puede activar a nivel de virtual host si está establecido en &quot;Disabled&quot; a nivel de servidor.<br/><br/>Valores predeterminados:<br/><b>Nivel de servidor:</b> Disabled<br/><b>Nivel de VH:</b> Heredar el ajuste de nivel de servidor', '', 'Seleccionar de la lista desplegable', '');

$_tipsdb['bubbleWrapCmd'] = new DAttrHelp("Comando Bubblewrap", 'El comando completo de uso de bubblewrap, incluido el propio programa bubblewrap. Puede encontrar más información para configurar este comando aquí: <a href="   https://openlitespeed.org/kb/bubblewrap-in-openlitespeed/ " target="_blank" rel="noopener noreferrer">   https://openlitespeed.org/kb/bubblewrap-in-openlitespeed/ </a>. Si no se especifica, se usará el comando predeterminado listado abajo.<br/><br/>Valor predeterminado: <span class=&quot;lst-inline-token lst-inline-token--command&quot;>/bin/bwrap --ro-bind /usr /usr --ro-bind /lib /lib --ro-bind-try /lib64 /lib64 --ro-bind /bin /bin --ro-bind /sbin /sbin --dir /var --dir /tmp --proc /proc --symlink ../tmp var/tmp --dev /dev --ro-bind-try /etc/localtime /etc/localtime --ro-bind-try /etc/ld.so.cache /etc/ld.so.cache --ro-bind-try /etc/resolv.conf /etc/resolv.conf --ro-bind-try /etc/ssl /etc/ssl --ro-bind-try /etc/pki /etc/pki --ro-bind-try /etc/man_db.conf /etc/man_db.conf --ro-bind-try /home/$USER /home/$USER --bind-try /var/lib/mysql/mysql.sock /var/lib/mysql/mysql.sock --bind-try /home/mysql/mysql.sock /home/mysql/mysql.sock --bind-try /tmp/mysql.sock /tmp/mysql.sock  --unshare-all --share-net --die-with-parent --dir /run/user/$UID ‘$PASSWD 65534’ ‘$GROUP 65534’</span>', '', '', '');

$_tipsdb['certChain'] = new DAttrHelp("Certificado encadenado", 'Especifica si el certificado es o no un certificado encadenado. El archivo que almacena una cadena de certificados debe estar en formato PEM, y los certificados deben estar en orden encadenado, desde el nivel mas bajo (el certificado real del cliente o servidor) hasta la CA de nivel mas alto (raiz).', '', 'Seleccionar desde botones de opción', '');

$_tipsdb['certFile'] = new DAttrHelp("Archivo de certificado", 'El nombre de archivo del certificado SSL.', ' El archivo de certificado debe colocarse en un directorio seguro que permita acceso de solo lectura al usuario con el que se ejecuta el servidor.', 'Nombre de archivo que puede ser una ruta absoluta o una ruta relativa a $SERVER_ROOT.', '');

$_tipsdb['cgiContext'] = new DAttrHelp("Contexto CGI", 'Un contexto CGI define los scripts de un directorio determinado como scripts CGI. Este directorio puede estar dentro o fuera de la raiz de documentos. Cuando se solicita un archivo de este directorio, el servidor siempre intentara ejecutarlo como script CGI, sea ejecutable o no. De esta forma, el contenido de los archivos bajo un contexto CGI siempre queda protegido y no puede leerse como contenido estatico. Se recomienda colocar todos los scripts CGI en un directorio y configurar un contexto CGI para acceder a ellos.', '', '', '');

$_tipsdb['cgiResource'] = new DAttrHelp("Ajustes CGI", 'Los siguientes ajustes controlan los procesos CGI. Los limites de memoria y procesos tambien sirven como valores predeterminados para otras aplicaciones externas si no se han establecido limites explicitamente para esas aplicaciones.', '', '', '');

$_tipsdb['cgi_path'] = new DAttrHelp("Ruta", 'Especifica la ubicacion de los scripts CGI.', '', 'La ruta puede ser un directorio que contiene un grupo de scripts CGI, como <span class=&quot;lst-inline-token lst-inline-token--value&quot;>$VH_ROOT/myapp/cgi-bin/</span>. En este caso, el contexto &quot;URI&quot; debe terminar con &quot;/&quot;, como <span class=&quot;lst-inline-token lst-inline-token--value&quot;>/app1/cgi/</span>. La Ruta tambien puede especificar un solo script CGI, como <span class=&quot;lst-inline-token lst-inline-token--value&quot;>$VH_ROOT/myapp/myscript.pl</span>. Este script debe tener el &quot;URI&quot; correspondiente <span class=&quot;lst-inline-token lst-inline-token--value&quot;>/myapp/myscript.pl</span>.', '');

$_tipsdb['cgidSock'] = new DAttrHelp("Socket del demonio CGI", 'Dirección de socket única usada para comunicarse con el demonio CGI. LiteSpeed Server usa un demonio CGI independiente para iniciar scripts CGI con el mejor rendimiento y seguridad. Si necesita cambiar esta ubicación, especifique aquí un socket de dominio Unix.<br/><br/>Valor predeterminado: <span class=&quot;lst-inline-token lst-inline-token--value&quot;>uds://$SERVER_ROOT/admin/lscgid/.cgid.sock</span>', '', 'UDS://ruta', 'UDS://tmp/lshttpd/cgid.sock');

$_tipsdb['cgroups'] = new DAttrHelp("cgroups", 'Función del kernel Linux que limita, contabiliza y aísla el uso de recursos (CPU, memoria, I/O de disco, red, etc.) de un conjunto de procesos. Debe estar usando cgroups v2, lo cual se determina por la existencia del archivo <span class=&quot;lst-inline-token lst-inline-token--value&quot;>/sys/fs/cgroup/cgroup.controllers</span>.<br/><br/>Establecer esto en <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Disabled</span> a nivel de servidor deshabilitará este ajuste en todo el servidor. En todos los demás casos, el ajuste de nivel de servidor se puede sobrescribir a nivel de virtual host.<br/><br/>Valores predeterminados:<br/><b>Nivel de servidor:</b> Off<br/><b>Nivel de VH:</b> Heredar el ajuste de nivel de servidor', '', 'Seleccionar de la lista desplegable', '');

$_tipsdb['checkSymbolLink'] = new DAttrHelp("Comprobar enlaces simbólicos", 'Especifica si se deben comprobar los enlaces simbólicos contra &quot;Directorios con acceso denegado&quot; cuando &quot;Seguir enlaces simbólicos&quot; está activado. Si se habilita, la ruta real canónica del recurso referido por una URL se comprobará contra los directorios de acceso denegado configurables. Se denegará el acceso si cae dentro de un directorio de acceso denegado.', ' Para mayor seguridad, habilite esta opción. Para obtener mejor rendimiento, deshabilítela.', 'Seleccionar desde botones de opción', '');

$_tipsdb['ciphers'] = new DAttrHelp("Cifrados", 'Especifica la suite de cifrados que se usara al negociar el handshake SSL. LSWS admite suites de cifrado implementadas en SSL v3.0, TLS v1.0, TLS v1.2 y TLS v1.3.', ' Recomendamos dejar este campo en blanco para usar nuestro cifrado predeterminado, que sigue las mejores practicas de cifrado SSL.', 'Cadena de especificaciones de cifrado separadas por dos puntos.', 'ECDHE-RSA-AES128-SHA256:RC4:HIGH:!MD5:!aNULL:!EDH');

$_tipsdb['clientVerify'] = new DAttrHelp("Verificacion de cliente", ' Especifica el tipo de autenticacion de certificado de cliente. Los tipos disponibles son: <ul> <li><b>None:</b> no se requiere certificado de cliente.</li> <li><b>Optional:</b> el certificado de cliente es opcional.</li> <li><b>Require:</b> el cliente debe tener un certificado valido.</li> <li><b>Optional_no_ca:</b> igual que optional.</li> </ul> El valor predeterminado es &quot;None&quot;.', '&quot;None&quot; o &quot;Require&quot; son recomendados.', 'Seleccionar de la lista desplegable', '');

$_tipsdb['compilerflags'] = new DAttrHelp("Opciones del compilador", 'Agregue opciones adicionales del compilador, como opciones de compilador optimizadas.', '', 'Las opciones admitidas son CFLAGS, CXXFLAGS, CPPFLAGS, LDFLAGS. Use un espacio para separar diferentes opciones. Use comillas simples (no comillas dobles) para los valores de opciones.', 'CFLAGS=&#039;-O3 -msse2 -msse3 -msse4.1 -msse4.2 -msse4 -mavx&#039;');

$_tipsdb['compressibleTypes'] = new DAttrHelp("Tipos comprimibles", 'Especifica qué tipos MIME pueden comprimirse. Deje este ajuste sin establecer o introduzca <span class=&quot;lst-inline-token lst-inline-token--value&quot;>default</span> para usar la lista predeterminada integrada del servidor, que ya debería cubrir la mayoría de los tipos MIME.<br/><br/>Valor predeterminado: <span class=&quot;lst-inline-token lst-inline-token--value&quot;>text/*,application/x-javascript,application/javascript,application/xml,image/svg+xml,application/rss+xml, application/json,application/vnd.ms-fontobject,application/x-font,application/x-font-opentype, application/x-font-truetype,application/x-font-ttf,font/eot,font/opentype,font/otf,font/ttf,image/x-icon, image/vnd.microsoft.icon,application/xhtml+xml</span>', ' Permita solo tipos que se beneficien de la compresión GZIP/Brotli. Los archivos binarios, como imágenes gif/png/jpeg y archivos flash, no se benefician de la compresión.', 'Lista de tipos MIME separada por comas. Se permiten el comodín &quot;*&quot; y el signo de negación &quot;!&quot;, como text/*, !text/js.', 'Si desea comprimir text/* pero no text/css, puede usar una regla como <span class=&quot;lst-inline-token lst-inline-token--value&quot;>text/*, !text/css</span>. &quot;!&quot; excluirá ese tipo MIME.');

$_tipsdb['configFile'] = new DAttrHelp("Archivo de configuracion", 'El nombre de archivo y directorio de configuracion para este virtual host. El archivo de configuracion debe estar bajo el directorio $SERVER_ROOT/conf/vhosts/.', '$SERVER_ROOT/conf/vhosts/$VH_NAME/vhconf.conf es recomendado', 'Nombre de archivo que puede ser una ruta absoluta o una ruta relativa a $SERVER_ROOT.', '');

$_tipsdb['configureparams'] = new DAttrHelp("Parámetros de configuración", 'Parámetros de configuración para la compilación de PHP. Los parámetros específicos de Apache y el valor &quot;--prefix&quot; se eliminarán automáticamente, y &quot;--with-litespeed&quot; se agregará automáticamente al hacer clic en Next Step. (El prefijo se puede establecer en el campo anterior.) Así puede copiar y pegar los parámetros de configuración desde la salida de phpinfo() de una compilación PHP existente y funcional.', '', 'Serie de opciones separadas por espacios (con o sin comillas dobles)', '');

$_tipsdb['connTimeout'] = new DAttrHelp("Timeout de conexión (seg)", 'Especifica el tiempo máximo de inactividad de conexión permitido durante el procesamiento de una solicitud. La conexión se cerrará si ha estado inactiva, es decir sin actividad de I/O, durante este periodo.', ' Establézcalo tan bajo como pueda para ayudar a recuperar conexiones muertas durante un posible ataque DoS.', 'Número entero', '');

$_tipsdb['consoleSessionTimeout'] = new DAttrHelp("Tiempo de espera de sesion (s)", 'Personaliza la duracion del tiempo de espera de sesion de la consola WebAdmin. El valor predeterminado es 60 segundos.', ' Defina un valor adecuado para produccion, normalmente inferior a 300 segundos.', 'Número entero', '');

$_tipsdb['cpuAffinity'] = new DAttrHelp("Afinidad de CPU", 'La afinidad de CPU vincula un proceso a una o mas CPU (nucleos). Es beneficioso que un proceso use siempre la misma CPU porque asi puede aprovechar los datos que quedan en la cache de CPU. Si el proceso se mueve a otra CPU, no se usa la cache de CPU y se requiere sobrecarga innecesaria.<br/><br/>La opcion Afinidad de CPU controla con cuantas CPU (nucleos) se asociara un proceso de servidor. El valor minimo es <span class=&quot;lst-inline-token lst-inline-token--value&quot;>0</span>, que deshabilita esta funcion. El valor maximo es el numero de nucleos del servidor. Por lo general, <span class=&quot;lst-inline-token lst-inline-token--value&quot;>1</span> es la mejor opcion porque crea el uso mas estricto de afinidad de CPU y aprovecha mejor la cache de CPU.<br/><br/>Valor predeterminado: 0', '', 'Valor entero de 0 a 64. (0 deshabilitara esta funcion)', '');

$_tipsdb['crlFile'] = new DAttrHelp("Archivo de revocacion de cliente", ' Especifica el archivo que contiene archivos CRL de CA codificados en PEM que enumeran certificados de cliente revocados. Puede usarse como alternativa o ademas de &quot;Ruta de revocacion de cliente&quot;.', '', 'Nombre de archivo que puede ser una ruta absoluta o una ruta relativa a $SERVER_ROOT.', '');

$_tipsdb['crlPath'] = new DAttrHelp("Ruta de revocacion de cliente", ' Especifica el directorio que contiene archivos CRL de CA codificados en PEM para certificados de cliente revocados. Los archivos de este directorio deben estar codificados en PEM. Se accede a estos archivos mediante nombres de archivo hash, hash-value.rN. Consulte la documentacion de openSSL o Apache mod_ssl sobre la creacion del nombre de archivo hash.', '', 'ruta', '');

$_tipsdb['ctxType'] = new DAttrHelp("Tipo de contexto", 'El tipo de contexto creado determina su uso. <br/><br/> El contexto <b>Static</b> puede mapear una URI a un directorio dentro o fuera del document root. <br/> El contexto <b>LiteSpeed SAPI</b> asocia una URI con una aplicacion LSAPI. <br/> El contexto <b>Proxy</b> permite que este virtual host actue como proxy inverso transparente hacia un servidor web externo o servidor de aplicaciones. <br/> El contexto <b>Fast CGI</b> es un punto de montaje de una aplicacion Fast CGI. <br/> El contexto <b>SCGI</b> asocia una URI con una aplicacion SCGI. <br/> El contexto <b>CGI</b> especifica un directorio que solo contiene scripts CGI. <br/> El contexto <b>Redirect</b> configura una URI de redireccion interna o externa. <br/> El contexto <b>Load Balancer</b> asigna un cluster distinto para ese contexto. <br/> El contexto <b>Java Web App</b> importa automaticamente una Aplicacion Java predefinida en un motor servlet compatible con AJPv13. <br/> El contexto <b>Servlet</b> importa un servlet especifico dentro de una aplicacion web. <br/> El contexto <b>App Server</b> se usa para aplicaciones Rack/Rails, WSGI y Node.js. <br/> El contexto <b>uWSGI</b> asocia una URI con una aplicacion uWSGI. <br/> El contexto <b>Module handler</b> es un punto de montaje de modulos de tipo handler.', '', '', '');

$_tipsdb['defaultCharsetCustomized'] = new DAttrHelp("Charset predeterminado personalizado", 'Especifica un juego de caracteres que se usara cuando &quot;Agregar charset predeterminado&quot; este en <span class=&quot;lst-inline-token lst-inline-token--value&quot;>On</span>. Es opcional. El valor predeterminado es <span class=&quot;lst-inline-token lst-inline-token--value&quot;>iso-8859-1</span>. Esta entrada no tiene efecto cuando &quot;Agregar charset predeterminado&quot; esta en <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Off</span>.', '', 'Nombre de un juego de caracteres.', 'utf-8');

$_tipsdb['defaultType'] = new DAttrHelp("Tipo MIME predeterminado", 'Cuando se especifica, este tipo se usara cuando no se pueda determinar el mapeo de tipo MIME por el sufijo de un documento o si no hay sufijo. Si no se especifica, se usara el valor predeterminado <span class=&quot;lst-inline-token lst-inline-token--value&quot;>application/octet-stream</span>.', '', 'MIME-type', '');

$_tipsdb['destinationuri'] = new DAttrHelp("URI de destino", 'Especifica la ubicacion de destino de la redireccion. Si esta URI redirigida se mapea a una URI en otro contexto de redireccion, se redirigira de nuevo.', '', 'Esta URI puede ser una URI relativa del mismo sitio web que empieza con &quot;/&quot;, o una URI absoluta que apunta a otro sitio web y empieza con &quot;http(s)://&quot;. Si &quot;URI&quot; contiene expresiones regulares, el destino puede referenciar las variables coincidentes, como $1 o $2.', '');

$_tipsdb['disableInitLogRotation'] = new DAttrHelp("Deshabilitar rotacion inicial de logs", 'Especifica si se debe habilitar/deshabilitar la rotacion del archivo de log de errores del servidor al inicio. La rotacion inicial de logs esta habilitada de forma predeterminada cuando se usa el valor &quot;Not Set&quot;.', '', 'Seleccionar desde botones de opción', '');

$_tipsdb['docRoot'] = new DAttrHelp("Raíz de documentos", 'Especifica la raíz de documentos de este virtual host. Se recomienda <span class=&quot;lst-inline-token lst-inline-token--value&quot;>$VH_ROOT/html</span>. En los contextos, este directorio se referencia como $DOC_ROOT.', '', 'Una ruta que puede ser absoluta, relativa a $SERVER_ROOT o relativa a $VH_ROOT.', '');

$_tipsdb['domainName'] = new DAttrHelp("Dominios", 'Especifica los nombres de dominio del mapeo. Los nombres de dominio no distinguen entre mayusculas y minusculas, y el prefijo &quot;www.&quot; se eliminara. Se permiten los caracteres comodin &quot;*&quot; y &quot;?&quot;. &quot;?&quot; representa un solo caracter. &quot;*&quot; representa cualquier numero de caracteres. No se permiten nombres de dominio duplicados.', ' Si un listener esta dedicado a un host virtual, use siempre <span class=&quot;lst-inline-token lst-inline-token--value&quot;>*</span> como nombre de dominio para evitar comprobaciones innecesarias. Los nombres de dominio con caracteres comodin (distintos del dominio catchall) deben evitarse siempre que sea posible.', 'Lista separada por comas.', 'www?.example.com<br/>&quot;*.mydomain.com&quot; coincidira con todos los subdominios de mydomain.com.<br/>&quot;*&quot; por si solo es el dominio catchall y coincidira con cualquier nombre de dominio no coincidente.');

$_tipsdb['dynReqPerSec'] = new DAttrHelp("Solicitudes dinámicas/segundo", 'Especifica el número máximo de solicitudes de contenido generado dinámicamente procedentes de una sola dirección IP que se pueden procesar por segundo, sin importar cuántas conexiones estén establecidas. Cuando se alcanza este límite, todas las solicitudes futuras de contenido dinámico se retienen hasta el siguiente segundo.<br/><br/>El límite de solicitudes para contenido estático es independiente de este límite. Este límite de solicitudes por cliente se puede establecer a nivel de servidor o de virtual host. Los ajustes de nivel de virtual host sobrescriben los ajustes de nivel de servidor.', ' Las IP o subredes de confianza no están restringidas por este límite.', 'Número entero', '');

$_tipsdb['enableCoreDump'] = new DAttrHelp("Habilitar volcado core", 'Especifica si se habilita el volcado core cuando el servidor se inicia con el usuario &quot;root&quot;. En la mayoria de los sistemas Unix modernos, por motivos de seguridad, los procesos que cambian de ID de usuario o de grupo no pueden generar un archivo core. Sin embargo, con un volcado core es mucho mas facil identificar la causa raiz de un problema. Esta opcion solo funciona en Linux kernel 2.4 o posterior. Los usuarios de Solaris deben usar el comando <span class=&quot;lst-inline-token lst-inline-token--command&quot;>coreadm</span> para controlar esta funcion.', ' Habilite esta opcion solo cuando vea <span class=&quot;lst-inline-token lst-inline-token--value&quot;>no core file created</span> en el archivo de registro del servidor. Deshabilitela inmediatamente despues de generar el archivo core. Envie un informe de error cuando se haya creado un volcado core.', 'Seleccionar desde botones de opción', '');

$_tipsdb['enableDHE'] = new DAttrHelp("Habilitar intercambio de claves DH", 'Permite usar intercambio de claves Diffie-Hellman para cifrado SSL adicional.', ' El intercambio de claves DH es mas seguro que usar solo una clave RSA. Los intercambios de claves ECDH y DH son igualmente seguros.<br/><br/> Habilitar el intercambio de claves DH aumentara la carga de CPU y es mas lento que el intercambio ECDH y RSA. Se prefiere ECDH cuando esta disponible.', 'Seleccionar desde botones de opción', '');

$_tipsdb['enableDynGzipCompress'] = new DAttrHelp("Habilitar compresión GZIP dinámica", 'Controla la compresión GZIP para respuestas generadas dinámicamente.<br/><br/>Para que este ajuste tenga efecto, &quot;Habilitar compresión&quot; debe estar en <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Yes</span>.<br/><br/>Valor predeterminado: Yes', ' Comprimir respuestas dinámicas aumenta el uso de CPU y memoria, pero ahorra ancho de banda de red.', 'Seleccionar desde botones de opción', '');

$_tipsdb['enableECDHE'] = new DAttrHelp("Habilitar intercambio de claves ECDH", 'Permite usar intercambio de claves Elliptic Curve Diffie-Hellman para cifrado SSL adicional.', ' El intercambio de claves ECDH es mas seguro que usar solo una clave RSA. Los intercambios de claves ECDH y DH son igualmente seguros.<br/><br/> Habilitar el intercambio de claves ECDH aumentara la carga de CPU y es mas lento que usar solo una clave RSA.', 'Seleccionar desde botones de opción', '');

$_tipsdb['enableExpires'] = new DAttrHelp("Habilitar Expires", 'Especifica si se debe generar un encabezado Expires para archivos estaticos. Si esta habilitado, se generara un encabezado Expires basado en &quot;Expires predeterminado&quot; y &quot;Expires por tipo&quot;.<br/><br/>Puede establecerse a nivel de servidor, virtual host y contexto. Las opciones de nivel inferior reemplazaran las de nivel superior, es decir, las opciones de contexto reemplazaran las de virtual host y las de virtual host reemplazaran las del servidor.', '', 'Seleccionar desde botones de opción', '');

$_tipsdb['enableGzipCompress'] = new DAttrHelp("Habilitar compresión", 'Habilita la compresión GZIP/Brotli para respuestas estáticas y dinámicas.<br/><br/>Valor predeterminado: Yes', ' Habilítela para ahorrar ancho de banda de red. Las respuestas basadas en texto, como archivos html, css y javascript, se benefician más y, en promedio, pueden comprimirse a la mitad de su tamaño original.', 'Seleccionar desde botones de opción', '');

$_tipsdb['enableIpGeo'] = new DAttrHelp("Habilitar busqueda GeoLocation", ' Especifica si se debe habilitar/deshabilitar la busqueda de IP Geolocation. Puede establecerse a nivel de servidor, virtual host o contexto. IP Geolocation esta deshabilitada de forma predeterminada cuando se usa el valor &quot;Not Set&quot;.', '', 'Seleccionar desde botones de opción', '');

$_tipsdb['enableLVE'] = new DAttrHelp("CloudLinux", 'Especifica si se debe habilitar Lightweight Virtual Environment (LVE) de CloudLinux cuando existe. Puede usar LiteSpeed con LVE para lograr una mejor gestion de recursos. Para mas informacion, consulte <a href="http://www.cloudlinux.com" target="_blank" rel="noopener noreferrer">http://www.cloudlinux.com</a>.', '', 'Seleccionar de la lista desplegable', '');

$_tipsdb['enableRecaptcha'] = new DAttrHelp("Habilitar CAPTCHA", 'Habilita la función CAPTCHA Protection en el nivel actual. Este ajuste debe estar en <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Yes</span> a nivel de servidor antes de que se pueda usar CAPTCHA Protection.<br/><br/>Valores predeterminados:<br/><b>Nivel de servidor:</b> <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Yes</span><br/><b>Nivel de VH:</b> Heredar el ajuste de nivel de servidor', '', 'Seleccionar desde botones de opción', '');

$_tipsdb['enableRewrite'] = new DAttrHelp("Habilitar rewrite", 'Especifica si se habilita el motor de reescritura de URL de LiteSpeed. Esta opción puede personalizarse a nivel de virtual host o contexto, y se hereda a lo largo del árbol de directorios hasta que se sobrescribe explícitamente.', '', 'Seleccionar desde botones de opción', '');

$_tipsdb['enableScript'] = new DAttrHelp("Habilitar Scripts/ExtApps", 'Especifica si se permite scripting (paginas no estaticas) en este virtual host. Si esta deshabilitado, CGI, FastCGI, LSAPI, motores Servlet y otros lenguajes de script no estaran permitidos en este virtual host. Por lo tanto, si desea usar un script handler, tambien debe habilitarlo aqui.', '', 'Seleccionar desde botones de opción', '');

$_tipsdb['enableSpdy'] = new DAttrHelp("ALPN", 'Application-Layer Protocol Negotiation(ALPN) se usa para habilitar selectivamente los protocolos de red HTTP/3 y HTTP/2.<br/><br/>Si desea deshabilitar HTTP/2 y HTTP3, marque <span class=&quot;lst-inline-token lst-inline-token--value&quot;>None</span> y deje todas las demas casillas sin marcar.<br/><br/>Valor predeterminado: todos habilitados', 'Puede establecerse en los niveles de listener y virtual host.', 'Seleccionar mediante casillas', '');

$_tipsdb['enableStapling'] = new DAttrHelp("Habilitar OCSP Stapling", 'Determina si se debe habilitar OCSP stapling, una forma mas eficiente de verificar certificados de clave publica.', '', 'Seleccionar desde botones de opción', '');

$_tipsdb['enableh2c'] = new DAttrHelp("Habilitar HTTP/2 sobre TCP en claro", 'Especifica si se debe habilitar HTTP/2 sobre conexiones TCP no cifradas. El valor predeterminado es deshabilitado.', '', 'Seleccionar desde botones de opción', '');

$_tipsdb['env'] = new DAttrHelp("Entorno", 'Especifica variables de entorno adicionales para la aplicacion externa.', '', 'Key=value. Varias variables pueden separarse con &quot;ENTER&quot;', '');

$_tipsdb['errCode'] = new DAttrHelp("Código de error", 'Especifica el código de estado HTTP de la página de error. Solo el código de estado HTTP seleccionado tendrá esta página de error personalizada.', '', 'Seleccionar de la lista desplegable', '');

$_tipsdb['errPage'] = new DAttrHelp("Paginas de error personalizadas", 'Siempre que el servidor tenga un problema al procesar una solicitud, el servidor devolvera un codigo de error y una pagina html como mensaje de error al cliente web. Los codigos de error se definen en el protocolo HTTP (consulte RFC 2616). El servidor web LiteSpeed tiene una pagina de error predeterminada integrada para cada codigo de error, pero tambien puede configurarse una pagina personalizada para cada codigo de error. Estas paginas de error pueden personalizarse aun mas para que sean unicas para cada virtual host.', '', '', '');

$_tipsdb['errURL'] = new DAttrHelp("URL", 'Especifica la URL de la página de error personalizada. El servidor reenviará la solicitud a esta URL cuando se devuelva el código de estado HTTP correspondiente. Si esta URL hace referencia a un recurso inexistente, se usará la página de error integrada. La URL puede ser un archivo estático, una página generada dinámicamente o una página de otro sitio web (una URL que empiece por &quot;http(s)://&quot;). Al hacer referencia a una página de otro sitio web, el cliente recibirá un código de estado de redirección en lugar del código de estado original.', '', 'URL', '');

$_tipsdb['expWSAddress'] = new DAttrHelp("Direccion", 'Direccion HTTP, HTTPS o Unix Domain Sockets (UDS) usada por el servidor web externo.', ' Si hace proxy a otro servidor web que se ejecuta en la misma maquina mediante una direccion IPv4/IPv6, establezca la direccion IP en <span class=&quot;lst-inline-token lst-inline-token--value&quot;>localhost</span> o <span class=&quot;lst-inline-token lst-inline-token--value&quot;>127.0.0.1</span>, para que la aplicacion externa no sea accesible desde otras maquinas.<br/> Unix Domain Sockets generalmente ofrecen mayor rendimiento que los sockets IPv4 o IPv6.', 'Direccion IPv4/IPv6(:puerto), UDS://ruta o unix:ruta. Agregue &quot;https://&quot; delante de una direccion IPv4/IPv6 si el servidor web externo usa HTTPS. El puerto es opcional para direcciones IPv4/IPv6 si el servidor web externo usa los puertos estandar 80 o 443.', '192.168.0.10<br/>127.0.0.1:5434<br/>https://10.0.8.9<br/>https://127.0.0.1:5438<br/>UDS://tmp/lshttpd/php.sock<br/>unix:/tmp/lshttpd/php.sock');

$_tipsdb['expiresByType'] = new DAttrHelp("Expires por tipo", 'Especifica configuraciones del encabezado Expires para tipos MIME individuales.', '', 'Lista separada por comas de &quot;MIME-type=A|Mseconds&quot;. El archivo expirara despues del tiempo base (A|M) mas los segundos especificados.<br/><br/>El tiempo base &quot;A&quot; establece el valor al tiempo de acceso del cliente y &quot;M&quot; al tiempo de ultima modificacion del archivo. MIME-type acepta comodin &quot;*&quot;, como image/*.', '');

$_tipsdb['expiresDefault'] = new DAttrHelp("Expires predeterminado", 'Especifica la configuracion predeterminada para generar el encabezado Expires. Esta opcion tiene efecto cuando &quot;Habilitar Expires&quot; se establece en &quot;Yes&quot;. Puede ser reemplazada por &quot;Expires por tipo&quot;. No establezca este valor predeterminado a nivel de servidor o virtual host salvo que sea necesario, ya que generara encabezados Expires para todas las paginas. La mayoria de las veces debe establecerse a nivel de contexto para ciertos directorios que no cambian con frecuencia. Si no hay configuracion predeterminada, no se generara encabezado Expires para tipos no especificados en &quot;Expires por tipo&quot;.', '', 'A|Msegundos<br/>El archivo expirara despues del tiempo base (A|M) mas los segundos especificados. El tiempo base &quot;A&quot; establece el valor al tiempo de acceso del cliente y &quot;M&quot; al tiempo de ultima modificacion del archivo.', '');

$_tipsdb['expuri'] = new DAttrHelp("URI", 'Especifica la URI para este contexto.', '', 'La URI puede ser una URI simple (que empieza con &quot;/&quot;) o una URI de expresion regular compatible con Perl (que empieza con &quot;exp:&quot;). Si una URI simple termina con &quot;/&quot;, este contexto incluira todas las sub-URI bajo esta URI. Si el contexto se mapea a un directorio del sistema de archivos, debe agregarse una &quot;/&quot; final.', '');

$_tipsdb['extAppAddress'] = new DAttrHelp("Direccion", 'Direccion de socket unica usada por la aplicacion externa. Se admiten sockets IPv4/IPv6 y Unix Domain Sockets (UDS). Los sockets IPv4/IPv6 pueden usarse para comunicacion por red. UDS solo puede usarse cuando la aplicacion externa reside en la misma maquina que el servidor.', ' Si la aplicacion externa se ejecuta en la misma maquina, se prefiere UDS. Si debe usar un socket IPv4|IPV6, establezca la direccion IP en <span class=&quot;lst-inline-token lst-inline-token--value&quot;>localhost</span> o <span class=&quot;lst-inline-token lst-inline-token--value&quot;>127.0.0.1</span>, para que la aplicacion externa no sea accesible desde otras maquinas.<br/> Unix Domain Sockets generalmente ofrecen mayor rendimiento que los sockets IPv4.', 'Direccion IPv4 o IPV6:puerto o UDS://ruta', '127.0.0.1:5434<br/>UDS://tmp/lshttpd/php.sock.');

$_tipsdb['extAppName'] = new DAttrHelp("Nombre", 'Un nombre unico para esta aplicacion externa. Se usara este nombre para hacer referencia a ella en otras partes de la configuracion.', '', '', '');

$_tipsdb['extAppPath'] = new DAttrHelp("Comando", 'Especifica la linea de comandos completa, incluidos los parametros, para ejecutar la aplicacion externa. Valor obligatorio si &quot;Iniciar por el servidor&quot; esta habilitado. Un parametro debe ir entre comillas dobles o simples si contiene espacios o tabulaciones.', '', 'Ruta completa al ejecutable con parametros opcionales.', '');

$_tipsdb['extAppPriority'] = new DAttrHelp("Prioridad", 'Especifica la prioridad del proceso de la aplicacion externa. Los valores van de <span class=&quot;lst-inline-token lst-inline-token--value&quot;>-20</span> a <span class=&quot;lst-inline-token lst-inline-token--value&quot;>20</span>. Un numero menor significa una prioridad mayor. Un proceso de aplicacion externa no puede tener una prioridad superior a la del servidor web. Si esta prioridad se establece en un numero menor que la del servidor, se usara la prioridad del servidor para este valor.', '', 'Número entero', '');

$_tipsdb['extAppType'] = new DAttrHelp("Tipo", 'Especifica el tipo de aplicacion externa. Los tipos de aplicacion se diferencian por el servicio que proporcionan o el protocolo que usan para comunicarse con el servidor. Elija entre <ul>   <li><span class=&quot;lst-inline-token lst-inline-token--value&quot;>LiteSpeed SAPI App</span>: una aplicacion que se comunica con el servidor web mediante el protocolo LSAPI.</li>   <li><span class=&quot;lst-inline-token lst-inline-token--value&quot;>Web Server (Proxy)</span>: un servidor web o servidor de aplicaciones que admite el protocolo HTTP.</li>   <li><span class=&quot;lst-inline-token lst-inline-token--value&quot;>FastCGI App</span>: una aplicacion FastCGI con rol <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Responder</span>.</li>   <li><span class=&quot;lst-inline-token lst-inline-token--value&quot;>FastCGI Authorizer</span>: una aplicacion FastCGI con rol <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Authorizer</span></li>   <li><span class=&quot;lst-inline-token lst-inline-token--value&quot;>SCGI App</span>: una aplicacion que se comunica con el servidor web mediante el protocolo SCGI.</li>   <li><span class=&quot;lst-inline-token lst-inline-token--value&quot;>Servlet Engine</span>: un motor servlet con conector AJPv13, como Tomcat.</li>   <li><span class=&quot;lst-inline-token lst-inline-token--value&quot;>Piped Logger</span>: una aplicacion que puede procesar entradas del registro de acceso recibidas en su flujo STDIN.</li>   <li><span class=&quot;lst-inline-token lst-inline-token--value&quot;>Load Balancer</span>: una aplicacion virtual que puede balancear la carga entre aplicaciones worker.</li>   <li><span class=&quot;lst-inline-token lst-inline-token--value&quot;>uWSGI</span>: una aplicacion que se comunica con el servidor web mediante el protocolo uWSGI.<.</li> </ul>', 'La mayoria de las aplicaciones usaran el protocolo LSAPI o FastCGI. LSAPI admite PHP, Ruby y Python. Perl puede usarse con FastCGI. (PHP, Ruby y Python tambien pueden configurarse para ejecutarse con FastCGI, pero funcionan mas rapido con LSAPI.) Java usa motores servlet.', 'Seleccionar de la lista desplegable', '');

$_tipsdb['extAuthorizer'] = new DAttrHelp("Autorizador", 'Especifica una aplicacion externa que puede usarse para generar decisiones de autorizado/no autorizado. Actualmente, solo esta disponible FastCGI Authorizer. Para mas detalles sobre el rol FastCGI Authorizer, visite <a href="   https://fastcgi-archives.github.io/ " target="_blank" rel="noopener noreferrer">   https://fastcgi-archives.github.io/ </a>.', '', 'Seleccionar de la lista desplegable', '');

$_tipsdb['extGroup'] = new DAttrHelp("Ejecutar como grupo", 'La aplicacion externa se ejecutara como este nombre de grupo especificado. Si no se define, se heredaran los ajustes del nivel de virtual host.<br/><br/>Valor predeterminado: Not Set', '', 'Nombre de grupo valido.', '');

$_tipsdb['extMaxIdleTime'] = new DAttrHelp("Tiempo maximo inactivo", 'Especifica el tiempo maximo de inactividad antes de que el servidor detenga una aplicacion externa y libere recursos inactivos. Cuando se establece en &quot;-1&quot;, el servidor no detendra la aplicacion externa salvo que se ejecute en modo ProcessGroup, donde las aplicaciones externas inactivas se detendran despues de 30 segundos.<br/><br/>Valor predeterminado: <span class=&quot;lst-inline-token lst-inline-token--value&quot;>-1</span>', ' Esta funcion es especialmente util en entornos de hosting masivo donde, para evitar que los scripts de aplicaciones externas de un virtual host accedan a archivos propiedad de otro virtual host, se ejecutan muchas aplicaciones diferentes al mismo tiempo en modo SetUID. Establezca este valor bajo para evitar que estas aplicaciones externas permanezcan inactivas innecesariamente.', 'Numero entero', '');

$_tipsdb['extUmask'] = new DAttrHelp("umask", 'Define el umask predeterminado para los procesos de esta aplicacion externa. Consulte <span class=&quot;lst-inline-token lst-inline-token--command&quot;> man 2 umask </span> para mas detalles. El valor predeterminado se toma del ajuste de nivel de servidor &quot;umask&quot;.', '', 'Valor en el rango valido [000]-[777].', '');

$_tipsdb['extUser'] = new DAttrHelp("Ejecutar como usuario", 'La aplicacion externa se ejecutara como este nombre de usuario especificado. Si no se define, se heredaran los ajustes del nivel de virtual host.<br/><br/>Valor predeterminado: Not Set', '', 'Nombre de usuario valido.', '');

$_tipsdb['extWorkers'] = new DAttrHelp("Workers", 'Lista de grupos de workers definidos previamente en el balanceador de carga externo.', '', 'Lista separada por comas con el formato ExternalAppType::ExternalAppName', 'fcgi::localPHP, proxy::backend1');

$_tipsdb['externalredirect'] = new DAttrHelp("Redireccion externa", 'Especifica si esta redireccion es externa. Para redireccion externa, puede especificarse &quot;Codigo de estado&quot; y &quot;URI de destino&quot; puede empezar con &quot;/&quot; o con &quot;http(s)://&quot;. Para redireccion interna, &quot;URI de destino&quot; debe empezar con &quot;/&quot;.', '', '', '');

$_tipsdb['extraHeaders'] = new DAttrHelp("Operaciones de encabezado", 'Especifica encabezados de respuesta/solicitud adicionales que se agregaran. Se pueden agregar varias directivas de encabezado, una por linea. &quot;NONE&quot; puede usarse para deshabilitar la herencia de encabezados padre. Si no se proporciona una directiva, se asume &#039;Header&#039;.', ' La sintaxis y el uso son similares a las directivas <a href="https://httpd.apache.org/docs/2.2/mod/mod_headers.html#header" target="_blank" rel="noopener noreferrer">mod_headers de Apache</a> para las operaciones admitidas.<br/><br/> La directiva &#039;Header&#039; es opcional y puede excluirse o conservarse al copiar reglas desde otro lugar sin problema.', '[Header]|RequestHeader [condition] set|append|merge|add|unset header [value] [early|env=[!]variable]', 'set Cache-control no-cache<br/>append Cache-control no-store<br/>Header set My-header cust_header_val<br/>RequestHeader set My-req-header cust_req_header_val');

$_tipsdb['extrapathenv'] = new DAttrHelp("Variables de entorno PATH adicionales", 'Valores PATH adicionales que se anexarán a las variables de entorno PATH actuales para los scripts de compilación.', '', 'valores de ruta separados por &quot;:&quot;', '');

$_tipsdb['fcgiContext'] = new DAttrHelp("Contexto FastCGI", 'Las aplicaciones FastCGI no pueden usarse directamente. Una aplicacion FastCGI debe configurarse como manejador de scripts o asignarse a una URL mediante un contexto FastCGI. Un contexto FastCGI asocia una URI con una aplicacion FastCGI.', '', '', '');

$_tipsdb['fcgiapp'] = new DAttrHelp("Aplicacion FastCGI", 'Especifica el nombre de la aplicacion FastCGI. Esta aplicacion debe definirse en la seccion &quot;Aplicaciones externas&quot; a nivel de servidor o virtual host.', '', 'Seleccionar de la lista desplegable', '');

$_tipsdb['fileETag'] = new DAttrHelp("ETag de archivo", 'Especifica si se deben usar el inode, la hora de última modificación y los atributos de tamaño de un archivo para generar la cabecera de respuesta HTTP ETag para archivos estáticos. Los tres atributos están habilitados de forma predeterminada. Si planea servir el mismo archivo desde servidores replicados, no debe incluir inode; de lo contrario, el ETag generado para un archivo será diferente en distintos servidores.', '', 'Seleccionar mediante casillas', '');

$_tipsdb['fileUpload'] = new DAttrHelp("Carga de archivos", 'Proporciona funciones de seguridad adicionales al cargar archivos mediante un Request Body Parser que analiza los archivos hacia un directorio local del servidor, donde modulos de terceros pueden escanearlos facilmente en busca de intencion maliciosa. Request Body Parser se usa cuando &quot;Pasar datos de carga por ruta de archivo&quot; esta habilitado o cuando un modulo llama a set_parse_req_body de LSIAPI en el nivel LSI_HKPT_HTTP_BEGIN. Se proporcionan ejemplos de API en el paquete fuente.', '', '', '');

$_tipsdb['followSymbolLink'] = new DAttrHelp("Seguir enlaces simbólicos", 'Especifica el ajuste predeterminado a nivel de servidor para seguir enlaces simbólicos al servir archivos estáticos.<br/><br/>Las opciones son <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Yes</span>, <span class=&quot;lst-inline-token lst-inline-token--value&quot;>If Owner Match</span> y <span class=&quot;lst-inline-token lst-inline-token--value&quot;>No</span>.<br/><br/><span class=&quot;lst-inline-token lst-inline-token--value&quot;>Yes</span> hace que el servidor siempre siga los enlaces simbólicos. <span class=&quot;lst-inline-token lst-inline-token--value&quot;>If Owner Match</span> hace que el servidor siga un enlace simbólico solo si el propietario del enlace y el del destino son el mismo. <span class=&quot;lst-inline-token lst-inline-token--value&quot;>No</span> significa que el servidor nunca seguirá un enlace simbólico. Este ajuste se puede sobrescribir en las configuraciones de virtual host, pero no se puede sobrescribir desde un archivo .htaccess.', ' Para mayor seguridad, seleccione <span class=&quot;lst-inline-token lst-inline-token--value&quot;>No</span> o <span class=&quot;lst-inline-token lst-inline-token--value&quot;>If Owner Match</span>. Para obtener mejor rendimiento, seleccione <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Yes</span>.', 'Seleccionar de la lista desplegable', '');

$_tipsdb['forceGID'] = new DAttrHelp("Forzar GID", 'Especifica un ID de grupo que se usará para todas las aplicaciones externas iniciadas en modo suEXEC. Cuando se establece en un valor distinto de cero, todas las aplicaciones externas suEXEC (CGI/FastCGI/LSAPI) usarán este ID de grupo. Esto se puede usar para impedir que una aplicación externa acceda a archivos propiedad de otros usuarios.<br/><br/>Por ejemplo, en un entorno de hosting compartido, LiteSpeed se ejecuta como el usuario &quot;www-data&quot;, grupo &quot;www-data&quot;. Cada docroot pertenece a una cuenta de usuario, con grupo &quot;www-data&quot; y modo de permisos 0750. Si Force GID se establece en &quot;nogroup&quot; (o cualquier grupo distinto de &#039;www-data&#039;), todas las aplicaciones externas suEXEC se ejecutarán como un usuario determinado pero en el grupo &quot;nogroup&quot;. Estos procesos de aplicación externa aún podrán acceder a archivos propiedad de ese usuario determinado (debido a su ID de usuario), pero no tendrán permiso de grupo para acceder a archivos de otros usuarios. El servidor, por otra parte, todavía puede servir archivos bajo cualquier docroot de usuario (debido a su ID de grupo).', ' Establézcalo lo bastante alto para excluir a todos los grupos usados por usuarios del sistema.', 'Número entero', '');

$_tipsdb['forceStrictOwnership'] = new DAttrHelp("Forzar comprobación estricta de propiedad", 'Especifica si se debe aplicar una comprobación estricta de propiedad de archivos. Si está habilitado, el servidor web comprobará si el propietario del archivo que se sirve es el mismo que el propietario del virtual host. Si es diferente, se devolverá un error 403 Access Denied. Está desactivado de forma predeterminada.', ' Para hosting compartido, habilite esta comprobación para mejorar la seguridad.', 'Seleccionar desde botones de opción', '');

$_tipsdb['forceType'] = new DAttrHelp("Forzar tipo MIME", 'Cuando se especifica, todos los archivos bajo este contexto se serviran como archivos estaticos con el tipo MIME indicado, independientemente del sufijo de archivo. Cuando se establece en <span class=&quot;lst-inline-token lst-inline-token--value&quot;>NONE</span>, se deshabilitara la configuracion heredada de force type.', '', 'Tipo MIME o NONE.', '');

$_tipsdb['gdb_groupname'] = new DAttrHelp("Nombre de grupo", 'Un nombre de grupo que contiene solo letras y números (sin caracteres especiales).', '', 'cadena', '');

$_tipsdb['gdb_users'] = new DAttrHelp("Usuarios", 'Lista de usuarios separados por espacios que pertenecen a este grupo.', '', '', '');

$_tipsdb['generalContext'] = new DAttrHelp("Contexto general", 'La configuracion de contexto se usa para definir ajustes especiales para archivos en una ubicacion determinada. Estos ajustes pueden incorporar archivos fuera de la raiz de documentos (como las directivas Alias o AliasMatch de Apache), proteger un directorio mediante realms de autorizacion, o bloquear o restringir el acceso a un directorio dentro de la raiz de documentos.', '', '', '');

$_tipsdb['geoipDBFile'] = new DAttrHelp("Ruta del archivo DB", 'Especifica la ruta a la base de datos GeoIP de MaxMind.', '', 'Ruta absoluta', '/usr/local/share/GeoIP/GeoLite2-Country.mmdb');

$_tipsdb['geoipDBName'] = new DAttrHelp("Nombre de DB", 'Nombre de base de datos GeoIP de MaxMind. A partir de GeoIP2, esta opcion es obligatoria.<br/><br/>Al actualizar de GeoIP a GeoIP2, usar los valores &quot;COUNTRY_DB&quot;, &quot;CITY_DB&quot; o &quot;ASN_DB&quot; para esta opcion completara automaticamente la variable PHP $_SERVER con algunas entradas compatibles con GeoIP (listadas abajo por valor de DB Name) para facilitar esta transicion.<br/><br/><b>CITY_DB:</b> &#039;GEOIP_COUNTRY_CODE&#039;, &#039;GEOIP_COUNTRY_NAME&#039;, &#039;GEOIP_CONTINENT_CODE&#039;, &#039;GEOIP_COUNTRY_CONTINENT&#039;, &#039;GEOIP_DMA_CODE&#039;, &#039;GEOIP_METRO_CODE&#039;, &#039;GEOIP_LATITUDE&#039;, &#039;GEOIP_LONGITUDE&#039;, &#039;GEOIP_POSTAL_CODE&#039;, y &#039;GEOIP_CITY&#039;.<br/><b>COUNTRY_DB:</b> &#039;GEOIP_COUNTRY_CODE&#039;, &#039;GEOIP_COUNTRY_NAME&#039;, &#039;GEOIP_CONTINENT_CODE&#039;, y &#039;GEOIP_COUNTRY_CONTINENT&#039;.<br/><b>ASN_DB:</b> &#039;GEOIP_ORGANIZATION&#039; y &#039;GEOIP_ISP&#039;.', '', '', 'COUNTRY_DB');

$_tipsdb['geolocationDB'] = new DAttrHelp("Base de datos GeoIP MaxMind", 'Aqui se pueden especificar varias bases de datos de geolocalizacion MaxMind. MaxMind tiene los siguientes tipos de bases de datos: Country, Region, City, Organization, ISP y Netspeed. Si se configuran varias bases de datos de tipos &quot;Country&quot;, &quot;Region&quot; y &quot;City&quot;, la ultima configuracion sera efectiva.', '', '', '');

$_tipsdb['gracePeriod'] = new DAttrHelp("Periodo de gracia (segs)", 'Especifica durante cuánto tiempo se pueden aceptar nuevas conexiones después de que el número de conexiones establecidas desde una IP supere &quot;Límite flexible de conexiones&quot;. Durante este periodo, se aceptarán nuevas conexiones si el total sigue por debajo de &quot;Límite estricto de conexiones&quot;. Una vez transcurrido este periodo, si el número de conexiones sigue por encima de &quot;Límite flexible de conexiones&quot;, la IP infractora será bloqueada durante &quot;Periodo de bloqueo (segs)&quot;.', ' Establezca un valor adecuado, lo bastante grande para descargar una página completa pero lo bastante bajo para prevenir ataques deliberados.', 'Número entero', '');

$_tipsdb['gracefulRestartTimeout'] = new DAttrHelp("Timeout de reinicio graceful (seg)", 'Durante un reinicio graceful, incluso despues de que la nueva instancia del servidor este activa, la instancia anterior continuara gestionando las solicitudes existentes. Este timeout define cuanto tiempo debe esperar la instancia anterior antes de salir. El valor predeterminado es 300 segundos. -1 significa esperar para siempre. 0 significa no esperar y abortar inmediatamente.', '', 'Número entero', '');

$_tipsdb['groupDBCacheTimeout'] = new DAttrHelp("Tiempo de espera de cache de DB de grupos (seg)", 'Especifica con que frecuencia se comprobara si la base de datos de grupos backend tiene cambios. Para mas detalles, consulte &quot;Tiempo de espera de cache de DB de usuarios (seg)&quot;.', '', 'Número entero', '');

$_tipsdb['groupDBMaxCacheSize'] = new DAttrHelp("Tamano maximo de cache de DB de grupos", 'Especifica el tamano maximo de cache de la base de datos de grupos.', ' Como una cache mas grande consumira mas memoria, un valor mayor puede o no proporcionar mejor rendimiento. Establezcalo en un tamano adecuado segun el tamano de su base de datos de usuarios y el uso del sitio.', 'Número entero', '');

$_tipsdb['gzipAutoUpdateStatic'] = new DAttrHelp("Actualizar automáticamente archivo estático", 'Especifica si el servidor debe crear/actualizar automáticamente versiones comprimidas con GZIP de archivos estáticos comprimibles. Si se establece en <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Yes</span>, cuando se solicita un archivo con un tipo MIME listado en &quot;Tipos comprimibles&quot;, el servidor puede crear o actualizar la versión comprimida correspondiente del archivo según la marca de tiempo del archivo comprimido. Este archivo comprimido se crea bajo &quot;Directorio de caché estática&quot;. El nombre de archivo se basa en un hash MD5 de la ruta del archivo original.<br/><br/>Valor predeterminado: Yes', '', 'Seleccionar desde botones de opción', '');

$_tipsdb['gzipCacheDir'] = new DAttrHelp("Directorio de caché estática", 'Especifica la ruta del directorio usado para almacenar archivos comprimidos para contenido estático.<br/><br/>Valor predeterminado: &quot;Directorio de swapping&quot;.', '', 'Ruta de directorio', '');

$_tipsdb['gzipCompressLevel'] = new DAttrHelp("Nivel de compresión GZIP (contenido dinámico)", 'Especifica el nivel de compresión GZIP aplicado al contenido dinámico. Va de <span class=&quot;lst-inline-token lst-inline-token--value&quot;>1</span> (más bajo) a <span class=&quot;lst-inline-token lst-inline-token--value&quot;>9</span> (más alto).<br/><br/>Este ajuste solo tendrá efecto cuando &quot;Habilitar compresión&quot; y &quot;Habilitar compresión GZIP dinámica&quot; estén habilitados.<br/><br/>Valor predeterminado: 6', ' Un nivel de compresión más alto usará más memoria y ciclos de CPU. Puede establecerlo en un nivel superior si su máquina tiene potencia adicional. No hay mucha diferencia entre 6 y 9, salvo que 9 usa muchos más ciclos de CPU.', 'Número entre 1 y 9.', '');

$_tipsdb['gzipMaxFileSize'] = new DAttrHelp("Tamaño máx. de archivo estático (bytes)", 'Especifica el tamaño máximo de un archivo estático para el cual el servidor creará automáticamente un archivo comprimido.<br/><br/>Valor predeterminado: 10M', ' No se recomienda que el servidor cree/actualice archivos comprimidos para archivos grandes. La compresión bloquea un proceso completo del servidor y no se pueden procesar más solicitudes hasta que se complete.', 'Número en bytes no menor que 1K.', '');

$_tipsdb['gzipMinFileSize'] = new DAttrHelp("Tamaño mín. de archivo estático (bytes)", 'Especifica el tamaño mínimo de un archivo estático para el cual el servidor creará un archivo comprimido correspondiente.<br/><br/>Valor predeterminado: 200', 'No es necesario comprimir archivos muy pequeños, ya que el ahorro de ancho de banda es insignificante.', 'Número en bytes no menor que 200.', '');

$_tipsdb['gzipStaticCompressLevel'] = new DAttrHelp("Nivel de compresión GZIP (archivo estático)", 'Especifica el nivel de compresión GZIP aplicado a archivos estáticos. Va de <span class=&quot;lst-inline-token lst-inline-token--value&quot;>1</span> (más bajo) a <span class=&quot;lst-inline-token lst-inline-token--value&quot;>9</span> (más alto).<br/><br/>Este ajuste solo tendrá efecto cuando &quot;Habilitar compresión&quot; y &quot;Actualizar automáticamente archivo estático&quot; estén habilitados.<br/><br/>Valor predeterminado: 6', '', 'Número entre 1 y 9.', '');

$_tipsdb['hardLimit'] = new DAttrHelp("Límite estricto de conexiones", 'Especifica el número máximo de conexiones concurrentes permitidas desde una sola dirección IP. Este límite siempre se aplica y un cliente nunca podrá superarlo. Los clientes HTTP/1.0 suelen intentar abrir tantas conexiones como necesiten para descargar contenido incrustado al mismo tiempo. Este límite debe ser lo bastante alto para que los clientes HTTP/1.0 aún puedan acceder al sitio. Use &quot;Límite flexible de conexiones&quot; para establecer el límite de conexiones deseado.<br/><br/>El límite recomendado está entre <span class=&quot;lst-inline-token lst-inline-token--value&quot;>20</span> y <span class=&quot;lst-inline-token lst-inline-token--value&quot;>50</span>, según el contenido de su página web y la carga de tráfico.', ' Un número menor permitirá atender a más clientes distintos.<br/> Las IP o subredes de confianza no se ven afectadas.<br/> Establezca un valor alto cuando realice pruebas de benchmark con un gran número de máquinas cliente concurrentes.', 'Número entero', '');

$_tipsdb['httpdWorkers'] = new DAttrHelp("Numero de workers", 'Especifica el numero de workers httpd.', ' Establezca un numero adecuado para sus necesidades. Agregar mas workers no necesariamente significa mejor rendimiento.', 'Valor entero entre 1 y 16.', '');

$_tipsdb['inBandwidth'] = new DAttrHelp("Ancho de banda entrante (bytes/s)", 'El rendimiento entrante máximo permitido desde una sola dirección IP, sin importar cuántas conexiones estén establecidas. El ancho de banda real puede terminar siendo ligeramente superior a este ajuste por razones de eficiencia. El ancho de banda se asigna en unidades de 1KB. Establezca <span class=&quot;lst-inline-token lst-inline-token--value&quot;>0</span> para deshabilitar el throttling. Los límites de ancho de banda por cliente (bytes/s) se pueden establecer a nivel de servidor o de virtual host, donde los ajustes de nivel de virtual host sobrescriben los de nivel de servidor.', ' Las IP o subredes de confianza no se ven afectadas.', 'Número entero', '');

$_tipsdb['inMemBufSize'] = new DAttrHelp("Tamano del buffer de E/S de memoria", 'Especifica el tamano maximo de buffer usado para almacenar el cuerpo de la solicitud y su respuesta generada dinamicamente. Cuando se alcanza este limite, el servidor empezara a crear archivos temporales de swapping bajo &quot;Directorio de swapping&quot;.', ' Establezca un tamano de buffer suficientemente grande para alojar todas las solicitudes/respuestas concurrentes y evitar swapping de memoria a disco. Si hay actividad frecuente de E/S en el directorio swap, de forma predeterminada /tmp/lshttpd/swap/, este tamano de buffer es demasiado bajo y LiteSpeed esta haciendo swapping a disco.', 'Número entero', '');

$_tipsdb['indexFiles'] = new DAttrHelp("Archivos indice", 'Especifica los nombres de archivos indice que se buscaran secuencialmente cuando una URL se mapee a un directorio. Puede personalizarlo a nivel de servidor, virtual host y contexto.', ' Configure solo los archivos indice que necesite.', 'Lista separada por comas de nombres de archivo indice.', '');

$_tipsdb['indexUseServer'] = new DAttrHelp("Usar archivos de índice del servidor", 'Especifica si se usan los ajustes de archivos de índice del servidor. Si se establece en <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Yes</span>, solo se usarán los ajustes del servidor. Si se establece en <span class=&quot;lst-inline-token lst-inline-token--value&quot;>No</span>, no se usarán los ajustes del servidor. Si se establece en <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Addition</span>, se pueden agregar archivos de índice adicionales a la lista de archivos de índice del servidor para este virtual host. Si desea deshabilitar los archivos de índice para este virtual host, puede establecer el valor en <span class=&quot;lst-inline-token lst-inline-token--value&quot;>No</span> y dejar vacío el campo de archivos de índice.', '', 'Seleccionar de la lista desplegable', '');

$_tipsdb['initTimeout'] = new DAttrHelp("Tiempo de espera de solicitud inicial (s)", 'Especifica el tiempo maximo en segundos que el servidor esperara a que la aplicacion externa responda a la primera solicitud en una conexion nueva establecida. Si el servidor no recibe datos de la aplicacion externa dentro de este limite, marcara esta conexion como incorrecta. Esto ayuda a identificar problemas de comunicacion con aplicaciones externas lo antes posible. Si algunas solicitudes tardan mas en procesarse, aumente este limite para evitar mensajes de error 503.', '', 'Número entero', '');

$_tipsdb['installpathprefix'] = new DAttrHelp("Prefijo de ruta de instalación", 'Establece el valor de la opción de configuración &quot;--prefix&quot;. La ubicación de instalación predeterminada está bajo el directorio de instalación de LiteSpeed Web Server.', 'LiteSpeed Web Server puede usar varias versiones de PHP al mismo tiempo. Si instala varias versiones, debe darles prefijos diferentes.', 'ruta', '/usr/local/lsws/lsphp5');

$_tipsdb['instances'] = new DAttrHelp("Instancias", 'Especifica el numero maximo de instancias de la aplicacion externa que creara el servidor. Es obligatorio si &quot;Iniciar por el servidor&quot; esta habilitado. La mayoria de aplicaciones FastCGI/LSAPI solo pueden procesar una solicitud por instancia de proceso y, para esos tipos de aplicaciones, las instancias deben coincidir con el valor de &quot;Maximo de conexiones&quot;. Algunas aplicaciones FastCGI/LSAPI pueden crear varios procesos hijo para manejar varias solicitudes simultaneamente. Para estos tipos de aplicaciones, las instancias deben establecerse en &quot;1&quot; y usarse variables de entorno para controlar cuantos procesos hijo puede crear la aplicacion.', '', 'Número entero', '');

$_tipsdb['internalmodule'] = new DAttrHelp("Módulo interno", 'Especifique si el módulo es interno, enlazado estáticamente, en lugar de ser una biblioteca externa .so.', '', 'Seleccionar desde botones de opción', '');

$_tipsdb['ip2locDBCache'] = new DAttrHelp("Tipo de cache de DB", 'El metodo de cache usado. El valor predeterminado es <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Memory</span>.', '', 'Seleccionar de la lista desplegable', '');

$_tipsdb['ip2locDBFile'] = new DAttrHelp("Ruta del archivo DB IP2Location", 'La ubicacion de un archivo de base de datos valido.', '', 'Nombre de archivo que puede ser una ruta absoluta o una ruta relativa a $SERVER_ROOT.', '');

$_tipsdb['javaServletEngine'] = new DAttrHelp("Motor Servlet", 'Especifica el nombre del motor servlet que sirve esta aplicacion web. Los motores servlet deben definirse en la seccion &quot;Aplicaciones externas&quot; a nivel de servidor o virtual host.', '', 'Seleccionar de la lista desplegable', '');

$_tipsdb['javaWebAppContext'] = new DAttrHelp("Contexto de aplicación web Java", 'Muchas instalaciones Java usan el motor de servlets para servir tambien contenido estatico. Sin embargo, ningun motor de servlets es tan eficiente como LiteSpeed Web Server para estos procesos. Para mejorar el rendimiento general, LiteSpeed Web Server puede configurarse como servidor de puerta de enlace, sirviendo contenido estatico y reenviando las solicitudes dinamicas de paginas Java al motor de servlets.<br/><br/>LiteSpeed Web Server requiere que se definan ciertos contextos para ejecutar una aplicacion Java. Un contexto de aplicacion web Java crea automaticamente todos los contextos requeridos segun el archivo de configuracion de la aplicacion web Java (WEB-INF/web.xml).<br/><br/>Tenga en cuenta estos puntos al configurar un contexto de aplicacion web Java:<br/><ul> <li>Debe configurarse una aplicacion externa <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Servlet Engine</span> en la seccion &quot;Aplicaciones externas&quot; antes de crear el contexto de aplicacion web Java.</li> <li>Tambien debe definirse un &quot;Manejador de scripts&quot; para archivos .jsp.</li> <li>Si la aplicacion web esta empaquetada en un archivo .war, este debe expandirse. El servidor no puede acceder a archivos comprimidos.</li> <li>Para los mismos recursos, debe usarse la misma URL tanto si se accede a traves de LiteSpeed Web Server como mediante el servidor HTTP integrado del motor de servlets.<br/>Por ejemplo,   Tomcat 4.1 esta instalado en /opt/tomcat. Los archivos de la aplicacion web &quot;examples&quot;   se encuentran en /opt/tomcat/webapps/examples/. Mediante el servidor HTTP integrado de Tomcat,   se accede a la aplicacion web &quot;examples&quot; con una URI como &quot;/examples/***&quot;.   Por lo tanto, el contexto de aplicacion web Java correspondiente debe configurarse asi:   &quot;URI&quot; = <span class=&quot;lst-inline-token lst-inline-token--value&quot;>/examples/</span>, &quot;Ubicacion&quot; = <span class=&quot;lst-inline-token lst-inline-token--value&quot;>/opt/tomcat/webapps/examples/</span>.</li>   </ul>', '', '', '');

$_tipsdb['javaWebApp_location'] = new DAttrHelp("Ubicacion", 'Especifica el directorio que contiene los archivos de esta aplicacion web. Es el directorio que contiene &quot;WEB-INF/web.xml&quot;.<br/><br/>Valor predeterminado: $DOC_ROOT + &quot;URI&quot;', '', 'ruta', '');

$_tipsdb['jsonReports'] = new DAttrHelp("Generar informes JSON", 'Genera archivos de informe adicionales con formato JSON, con extension .json, en el directorio /tmp/lshttpd.<br/><br/>Valor predeterminado: <span class=&quot;lst-inline-token lst-inline-token--value&quot;>No</span>', ' Esto es util para desarrolladores de aplicaciones que deseen integrar informes de estado y tiempo real de LiteSpeed en sus aplicaciones usando herramientas estandar de procesamiento JSON integradas en la mayoria de lenguajes de programacion.', 'Seleccionar desde botones de opción', 'Cuando se establece en <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Yes</span>, se crearan archivos de informe .status.json y .rtreport.json, .rtreport.2.json, etc., ademas de los archivos habituales .status y .rtreport, .rtreport.2, etc.');

$_tipsdb['keepAliveTimeout'] = new DAttrHelp("Timeout Keep-Alive (seg)", 'Especifica el tiempo máximo de inactividad entre solicitudes de una conexión keep-alive. Si no se recibe una nueva solicitud durante este periodo, la conexión se cerrará. Este ajuste solo se aplica a conexiones HTTP/1.1. Las conexiones HTTP/2 tienen timeouts keep-alive largos por diseño y no se ven afectadas por este ajuste.', ' Recomendamos establecer este valor solo lo bastante largo para esperar solicitudes posteriores de un cliente cuando una página referencia más recursos que deben cargarse. No lo establezca demasiado largo esperando que la siguiente página se sirva sobre la conexión keep-alive. Mantener muchas conexiones keep-alive inactivas desperdicia recursos del servidor y puede ser aprovechado por ataques (D)DoS. <span class=&quot;lst-inline-token lst-inline-token--value&quot;>2-5</span> segundos es un rango razonable para la mayoría de las aplicaciones. LiteSpeed es muy eficiente en un entorno sin keep-alive.', 'Número entero', '');

$_tipsdb['keyFile'] = new DAttrHelp("Archivo de clave privada", 'El nombre de archivo de la clave privada SSL. El archivo de clave no debe estar cifrado.', ' El archivo de clave privada debe colocarse en un directorio seguro que permita acceso de solo lectura al usuario con el que se ejecuta el servidor.', 'Nombre de archivo que puede ser una ruta absoluta o una ruta relativa a $SERVER_ROOT.', '');

$_tipsdb['lbContext'] = new DAttrHelp("Contexto de balanceo", 'Como otras aplicaciones externas, las aplicaciones worker del balanceador de carga no pueden usarse directamente. Deben asignarse a una URL mediante un contexto. Un contexto de balanceador de carga asocia una URI para que sea balanceada por los workers del balanceador de carga.', '', '', '');

$_tipsdb['lbapp'] = new DAttrHelp("Load Balancer", 'Especifica el nombre del load balancer que se asociara a este contexto. Este load balancer es una aplicacion virtual y debe definirse en la seccion &quot;Aplicaciones externas&quot; a nivel de servidor o virtual host.', '', 'Seleccionar de la lista desplegable', '');

$_tipsdb['listenerBinding'] = new DAttrHelp("Enlace", 'Especifica a que proceso hijo de lshttpd se asigna el listener. Se pueden usar procesos hijo diferentes para atender solicitudes a listeners diferentes asociando manualmente un listener con un proceso. De forma predeterminada, un listener se asigna a todos los procesos hijo.', '', 'Seleccionar mediante casillas', '');

$_tipsdb['listenerIP'] = new DAttrHelp("Direccion IP", 'Especifica la IP de este listener. Se muestran todas las direcciones IP disponibles. Las direcciones IPv6 se encierran entre &quot;[ ]&quot;.<br/><br/>Para escuchar en todas las direcciones IPv4, seleccione <span class=&quot;lst-inline-token lst-inline-token--value&quot;>ANY</span>. Para escuchar en todas las direcciones IPv4 e IPv6, seleccione <span class=&quot;lst-inline-token lst-inline-token--value&quot;>[ANY]</span>.<br/><br/>Para atender clientes IPv4 e IPv6, debe usarse una direccion IPv6 asignada a IPv4 en lugar de una direccion IPv4 simple. Una direccion IPv6 asignada a IPv4 se escribe como [::FFFF:x.x.x.x].', ' Si la maquina tiene varias IP en subredes diferentes, puede seleccionar una IP especifica para permitir solo trafico desde la subred correspondiente.', 'Seleccionar de la lista desplegable', '');

$_tipsdb['listenerModules'] = new DAttrHelp("Módulos de listener", 'Los datos de configuracion de modulos del listener se heredan, de forma predeterminada, de la configuracion de modulos del servidor. Los modulos del listener se limitan a los hooks de capa 4 TCP/IP.', '', '', '');

$_tipsdb['listenerName'] = new DAttrHelp("Nombre del listener", 'Un nombre unico para este listener.', '', '', '');

$_tipsdb['listenerPort'] = new DAttrHelp("Puerto", 'Especifica el puerto TCP del listener. Solo el superusuario (&quot;root&quot;) puede usar puertos inferiores a <span class=&quot;lst-inline-token lst-inline-token--value&quot;>1024</span>. El puerto <span class=&quot;lst-inline-token lst-inline-token--value&quot;>80</span> es el puerto HTTP predeterminado. El puerto <span class=&quot;lst-inline-token lst-inline-token--value&quot;>443</span> es el puerto HTTPS predeterminado.', '', 'Número entero', '');

$_tipsdb['listenerSecure'] = new DAttrHelp("Seguro", 'Especifica si este es un listener seguro (SSL). Para listeners seguros, los ajustes SSL adicionales deben configurarse correctamente.', '', 'Seleccionar desde botones de opción', '');

$_tipsdb['lmap'] = new DAttrHelp("Mapeos de hosts virtuales", 'Muestra los mapeos establecidos actualmente desde un listener concreto hacia hosts virtuales. El nombre del host virtual aparece entre corchetes y va seguido de los nombres de dominio coincidentes para este listener.', 'Si un host virtual no se cargó correctamente (errores fatales en la configuración del host virtual), no se mostrará el mapeo a ese host virtual.', '', '');

$_tipsdb['lname'] = new DAttrHelp("Nombre - Listener", 'El nombre único que identifica este listener. Es el &quot;Nombre del listener&quot; especificado al configurar el listener.', '', '', '');

$_tipsdb['location'] = new DAttrHelp("Ubicacion", 'Especifica la ubicacion correspondiente de este contexto en el sistema de archivos.<br/><br/>Valor predeterminado: $DOC_ROOT + &quot;URI&quot;', '', 'Puede ser una ruta absoluta o una ruta relativa a $SERVER_ROOT, $VH_ROOT o $DOC_ROOT. $DOC_ROOT es la ruta relativa predeterminada y puede omitirse.<br/><br/>Si &quot;URI&quot; es una expresion regular, la subcadena coincidente puede usarse para formar la cadena &quot;Root&quot;. La subcadena coincidente puede referenciarse con los valores &quot;$1&quot; - &quot;$9&quot;. &quot;$0&quot; y &quot;&&quot; pueden usarse para referenciar toda la cadena coincidente. Ademas, puede establecerse una cadena de consulta agregando &quot;?&quot; seguido de la cadena de consulta. Tenga cuidado. &quot;&&quot; debe escaparse como &quot;\&&quot; en la cadena de consulta.', 'Una URI simple como <span class=&quot;lst-inline-token lst-inline-token--value&quot;>/examples/</span> con &quot;Ubicacion&quot; establecido en <span class=&quot;lst-inline-token lst-inline-token--value&quot;>/home/john/web_examples</span> mapeara la solicitud &quot;/examples/foo/bar.html&quot; al archivo &quot;/home/john/web_examples/foo/bar.html&quot;.<br/>Para simular mod_userdir de Apache, establezca URI en <span class=&quot;lst-inline-token lst-inline-token--value&quot;>exp: ^/~([A-Za-z0-9]+)(.*)</span>, establezca &quot;Ubicacion&quot; en <span class=&quot;lst-inline-token lst-inline-token--value&quot;>/home/$1/public_html$2</span>. Con esta configuracion, una solicitud de URI /~john/foo/bar.html se mapeara al archivo /home/john/public_html/foo/bar.html.');

$_tipsdb['logUseServer'] = new DAttrHelp("Usar el registro del servidor", 'Especifica si los mensajes de registro de este host virtual se colocarán en el archivo de registro del servidor en lugar de crear su propio archivo de registro.', '', 'Seleccionar desde botones de opción', '');

$_tipsdb['log_compressArchive'] = new DAttrHelp("Comprimir archivo", 'Especifica si se deben comprimir los archivos de registro rotados para ahorrar espacio en disco.', 'Los archivos de registro se comprimen muy bien y se recomienda activar esta opción para reducir el uso de disco de registros antiguos.', 'Seleccionar desde botones de opción', '');

$_tipsdb['log_debugLevel'] = new DAttrHelp("Nivel de depuración", 'Especifica el nivel de registro de depuración. &quot;Nivel de registro&quot; debe estar configurado como <span class=&quot;lst-inline-token lst-inline-token--value&quot;>DEBUG</span> para usar esta función. El registro de depuración está desactivado cuando &quot;Debug Level&quot; se establece en <span class=&quot;lst-inline-token lst-inline-token--value&quot;>NONE</span>, aunque &quot;Nivel de registro&quot; esté configurado como <span class=&quot;lst-inline-token lst-inline-token--value&quot;>DEBUG</span>. &quot;Alternar registro de depuración&quot; puede usarse para controlar el nivel de depuración en un servidor activo sin reiniciarlo.', ' Importante: configure siempre este valor como <span class=&quot;lst-inline-token lst-inline-token--value&quot;>NONE</span> si no necesita registros de depuración detallados. El registro de depuración activo degradará gravemente el rendimiento del servicio y puede saturar el espacio en disco en muy poco tiempo. El registro de depuración incluye información detallada de cada solicitud y respuesta.<br/><br/>Se recomienda configurar Log Level como <span class=&quot;lst-inline-token lst-inline-token--value&quot;>DEBUG</span> y Debug Level como <span class=&quot;lst-inline-token lst-inline-token--value&quot;>NONE</span>. Con esta configuración no llenará el disco duro con registros de depuración, pero podrá usar la acción &quot;Alternar registro de depuración&quot; para controlar la salida de depuración.', 'Seleccionar de la lista desplegable', '');

$_tipsdb['log_enableStderrLog'] = new DAttrHelp("Activar registro stderr", 'Especifica si se debe escribir en el registro al recibir salida stderr de procesos iniciados por el servidor.<br/><br/>Si está activado, los mensajes stderr se registrarán en el mismo directorio que el registro del servidor con el nombre fijo &quot;stderr.log&quot;. Si está desactivado, toda la salida stderr se descartará.<br/><br/>Funciones como error_log() de PHP que no escriben directamente en stderr (descriptor de archivo 2) no se ven afectadas por esta configuración y escribirán en el archivo definido por la directiva PHP ini &#039;error_log&#039; o en el archivo &quot;error.log&quot; del servidor con la etiqueta &#039;[STDERR]&#039; si esa directiva no está definida.', 'Actívelo si necesita depurar aplicaciones externas configuradas, por ejemplo PHP, Ruby, Java, Python o Perl.', 'Seleccionar desde botones de opción', '');

$_tipsdb['log_fileName'] = new DAttrHelp("Nombre de archivo", 'Especifica la ruta del archivo de registro.', ' Coloque el archivo de registro en un disco separado.', 'Nombre de archivo que puede ser una ruta absoluta o una ruta relativa a $SERVER_ROOT.', '');

$_tipsdb['log_keepDays'] = new DAttrHelp("Días de conservación", 'Especifica cuántos días se conservará en disco el archivo de registro de acceso. Solo se eliminarán los archivos de registro rotados que sean más antiguos que el número de días especificado. El archivo de registro actual no se modificará, independientemente de cuántos días de datos contenga. Si no desea eliminar automáticamente registros obsoletos y muy antiguos, establezca este valor en <span class=&quot;lst-inline-token lst-inline-token--value&quot;>0</span>.', '', 'Número entero', '');

$_tipsdb['log_logLevel'] = new DAttrHelp("Nivel de registro", 'Especifica el nivel de registro que se incluirá en el archivo de registro. Los niveles disponibles (de mayor a menor) son: <span class=&quot;lst-inline-token lst-inline-token--value&quot;>ERROR</span>, <span class=&quot;lst-inline-token lst-inline-token--value&quot;>WARNING</span>, <span class=&quot;lst-inline-token lst-inline-token--value&quot;>NOTICE</span>, <span class=&quot;lst-inline-token lst-inline-token--value&quot;>INFO</span> y <span class=&quot;lst-inline-token lst-inline-token--value&quot;>DEBUG</span>. Solo se registrarán los mensajes con nivel mayor o igual que la configuración actual.', ' Usar el nivel de registro <span class=&quot;lst-inline-token lst-inline-token--value&quot;>DEBUG</span> no afecta al rendimiento, salvo que &quot;Nivel de depuración&quot; esté configurado con un nivel distinto de <span class=&quot;lst-inline-token lst-inline-token--value&quot;>NONE</span>. Se recomienda configurar Log Level como <span class=&quot;lst-inline-token lst-inline-token--value&quot;>DEBUG</span> y Debug Level como <span class=&quot;lst-inline-token lst-inline-token--value&quot;>NONE</span>. Con esta configuración no llenará el disco duro con registros de depuración, pero podrá usar la acción &quot;Alternar registro de depuración&quot; para controlar la salida de depuración. Esta acción puede activar o desactivar el registro de depuración sobre la marcha y es útil para depurar servidores de producción ocupados.', 'Seleccionar de la lista desplegable', '');

$_tipsdb['log_rollingSize'] = new DAttrHelp("Tamaño de rotación (bytes)", 'Especifica cuándo debe rotarse el archivo de registro actual. Cuando el tamaño del archivo supera el límite de rotación, el archivo de registro activo se renombra como log_name.mm_dd_yyyy(.sequence) en el mismo directorio y se crea un nuevo archivo de registro activo. El tamaño real del archivo rotado puede ser ligeramente mayor que este límite. Establézcalo en <span class=&quot;lst-inline-token lst-inline-token--value&quot;>0</span> para desactivar la rotación de registros.', 'Agregue &quot;K&quot;, &quot;M&quot; o &quot;G&quot; al número para kilobytes, megabytes y gigabytes.', 'Número entero', '');

$_tipsdb['loggerAddress'] = new DAttrHelp("Direccion del registrador remoto (Opcional)", 'Especifica la direccion de socket opcional para este registrador canalizado. Configure este valor cuando el registrador se alcance mediante un socket de red o Unix Domain Socket. Dejelo vacio para un registrador canalizado local iniciado desde la ruta de comando configurada.', '', 'Direccion IPv4:puerto, hostname:puerto, [direccion IPv6]:puerto, UDS://ruta o unix:ruta', '127.0.0.1:1514<br/>logger.example.com:1514<br/>UDS://tmp/lshttpd/logger.sock');

$_tipsdb['loginHistoryRetention'] = new DAttrHelp("Retencion del historial de inicio de sesion (dias)", 'Especifica cuantos dias se conservan los registros del historial de inicio de sesion antes de eliminar las entradas antiguas. Valor predeterminado si no se define: 90 dias.', 'Conserve historial suficiente para auditoria y diagnostico, pero evite retener mas datos de los que realmente necesita.', 'Número entero', '');

$_tipsdb['loginThrottle'] = new DAttrHelp("Limitación de inicio de sesión", 'Configure la limitacion de inicios de sesion de la consola WebAdmin y la retencion de los registros relacionados con inicios de sesion y auditoria.', '', '', '');

$_tipsdb['lsapiContext'] = new DAttrHelp("Contexto LSAPI", 'Las aplicaciones externas no pueden usarse directamente. Deben configurarse como manejador de scripts o asignarse a una URL mediante un contexto. Un contexto LiteSpeed SAPI asocia una URI con una aplicacion LSAPI (LiteSpeed Server Application Programming Interface). Actualmente PHP, Ruby y Python tienen modulos LSAPI. LSAPI, al estar desarrollado especificamente para LiteSpeed web server, es la forma mas eficiente de comunicarse con LiteSpeed web server.', '', '', '');

$_tipsdb['lsapiapp'] = new DAttrHelp("Aplicacion LiteSpeed SAPI", 'Especifica el nombre de la aplicacion LiteSpeed SAPI que se conectara a este contexto. Esta aplicacion debe definirse en la seccion &quot;Aplicaciones externas&quot; a nivel de servidor o virtual host.', '', 'Seleccionar de la lista desplegable', '');

$_tipsdb['lsrecaptcha'] = new DAttrHelp("Proteccion CAPTCHA", 'CAPTCHA Protection es un servicio proporcionado como forma de mitigar una carga pesada del servidor. CAPTCHA Protection se activara despues de que ocurra una de las siguientes situaciones. Una vez activo, todas las solicitudes de clientes NON TRUSTED(segun configuracion) seran redirigidas a una pagina de validacion CAPTCHA. Despues de la validacion, el cliente sera redirigido a la pagina deseada.<br/><br/>Las siguientes situaciones activaran CAPTCHA Protection:<br/>1. El recuento de solicitudes concurrentes del servidor o vhost supera el limite de conexion configurado.<br/>2. Anti-DDoS esta habilitado y un cliente accede a una url de forma sospechosa. El cliente se redirigira primero a CAPTCHA en lugar de ser denegado cuando se active.<br/>3. Se proporciona un nuevo entorno de regla de rewrite para activar CAPTCHA mediante RewriteRules. &#039;verifycaptcha&#039; puede establecerse para redirigir clientes a CAPTCHA. Un valor especial &#039;: deny&#039; puede establecerse para denegar al cliente si fallo demasiadas veces. Por ejemplo, [E=verifycaptcha] siempre redirigira a CAPTCHA hasta que se verifique. [E=verifycaptcha: deny] redirigira a CAPTCHA hasta que se alcance Max Tries, despues de lo cual el cliente sera denegado.', '', '', '');

$_tipsdb['lstatus'] = new DAttrHelp("Estado - Listener", 'El estado actual de este listener. El estado es <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Running</span> o <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Error</span>.', 'Si el listener está en estado <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Error</span>, puede ver el registro del servidor para saber por qué.', '', '');

$_tipsdb['mappedListeners'] = new DAttrHelp("Listeners mapeados", 'Especifica los nombres de todos los listeners a los que se mapea esta plantilla. Se agregará a los listeners especificados en este campo un mapeo de listener a virtual host para los virtual hosts miembros de esta plantilla. Este mapeo asociará listeners con virtual hosts según los nombres de dominio y aliases definidos en las configuraciones individuales de los virtual hosts miembros.', '', 'lista separada por comas', '');

$_tipsdb['maxCGIInstances'] = new DAttrHelp("Máx. instancias CGI", 'Especifica el número máximo de procesos CGI concurrentes que el servidor puede iniciar. Para cada solicitud a un script CGI, el servidor debe iniciar un proceso CGI independiente. En un sistema Unix, el número de procesos concurrentes es limitado. Un exceso de procesos concurrentes degradará el rendimiento de todo el sistema y es una forma de realizar un ataque DoS. LiteSpeed Server canaliza las solicitudes a scripts CGI y limita los procesos CGI concurrentes para garantizar rendimiento y fiabilidad óptimos. El límite estricto es <span class=&quot;lst-inline-token lst-inline-token--value&quot;>2000</span>.', ' Un límite mayor no necesariamente se traduce en un rendimiento más rápido. En la mayoría de los casos, un límite menor ofrece mejor rendimiento y seguridad. Un límite mayor solo ayudará cuando la latencia de I/O sea excesiva durante el procesamiento CGI.', 'Número entero', '');

$_tipsdb['maxCachedFileSize'] = new DAttrHelp("Tamaño máx. de archivo pequeño en caché (bytes)", 'Especifica el archivo estático más grande que se almacenará en caché en un búfer de memoria preasignado. Los archivos estáticos se pueden servir de cuatro formas: caché de búfer en memoria, caché mapeada en memoria, lectura/escritura normal y sendfile(). Los archivos cuyo tamaño sea menor que este ajuste se sirven desde la caché de búfer en memoria. Los archivos cuyo tamaño sea mayor que este ajuste, pero menor que &quot;Tamaño máx. de archivo MMAP (bytes)&quot;, se servirán desde la caché mapeada en memoria. Los archivos cuyo tamaño sea mayor que &quot;Tamaño máx. de archivo MMAP (bytes)&quot; se servirán mediante lectura/escritura normal o sendfile(). Es óptimo servir archivos estáticos menores de 4K desde la caché de búfer en memoria.', '', 'Número entero', '');

$_tipsdb['maxConnections'] = new DAttrHelp("Máx. conexiones", 'Especifica el número máximo de conexiones concurrentes que el servidor puede aceptar. Esto incluye conexiones TCP simples y conexiones SSL. Una vez alcanzado el límite máximo de conexiones concurrentes, el servidor cerrará las conexiones Keep-Alive cuando completen las solicitudes activas.', 'Cuando el servidor se inicia con el usuario &quot;root&quot;, intentará ajustar automáticamente los límites de descriptores de archivo por proceso; sin embargo, si esto falla, es posible que deba aumentar este límite manualmente.', 'Número entero', '');

$_tipsdb['maxConns'] = new DAttrHelp("Maximo de conexiones", 'Especifica el numero maximo de conexiones concurrentes que pueden establecerse entre el servidor y una aplicacion externa. Este ajuste controla cuantas solicitudes puede procesar simultaneamente una aplicacion externa; sin embargo, el limite real tambien depende de la propia aplicacion externa. Aumentar este valor no ayudara si la aplicacion externa no es lo bastante rapida o no puede escalar a un gran numero de solicitudes concurrentes.', ' Definir un valor alto no se traduce directamente en mayor rendimiento. Establecer el limite en un valor que no sobrecargue la aplicacion externa proporcionara el mejor rendimiento/throughput.', 'Número entero', '');

$_tipsdb['maxDynRespHeaderSize'] = new DAttrHelp("Tamaño máx. de cabecera de respuesta dinámica (bytes)", 'Especifica el tamaño máximo de la cabecera de una respuesta generada dinámicamente. El límite estricto es <span class=&quot;lst-inline-token lst-inline-token--value&quot;>131072</span> bytes o 128K.<br/><br/>Valor predeterminado: <span class=&quot;lst-inline-token lst-inline-token--value&quot;>32768</span> o <span class=&quot;lst-inline-token lst-inline-token--value&quot;>32K</span>', ' Establézcalo razonablemente bajo para ayudar a reconocer respuestas incorrectas generadas dinámicamente por aplicaciones externas.', 'Número entero', '');

$_tipsdb['maxDynRespSize'] = new DAttrHelp("Tamaño máx. del cuerpo de respuesta dinámica (bytes)", 'Especifica el tamaño máximo del cuerpo de una respuesta generada dinámicamente.', ' Establezca el límite razonablemente bajo para ayudar a identificar respuestas incorrectas. No es raro que scripts mal formados contengan un bucle infinito que lleva a respuestas de tamaño infinito.', 'Número entero', '');

$_tipsdb['maxKeepAliveReq'] = new DAttrHelp("Máx. solicitudes Keep-Alive", 'Especifica el número máximo de solicitudes que se pueden servir mediante una sesión keep-alive (persistente). La conexión se cerrará cuando se alcance este límite. También puede establecer este límite para cada virtual host.', ' Establezca un valor razonablemente alto. Un valor de &quot;1&quot; o &quot;0&quot; deshabilitará keep-alive.', 'Número entero', '');

$_tipsdb['maxMMapFileSize'] = new DAttrHelp("Tamaño máx. de archivo MMAP (bytes)", 'Especifica el archivo estático más grande que se mapeará en memoria (MMAP). Los archivos estáticos se pueden servir de cuatro formas: caché de búfer en memoria, caché mapeada en memoria, lectura/escritura normal y sendfile(). Los archivos cuyo tamaño sea menor que &quot;Tamaño máx. de archivo pequeño en caché (bytes)&quot; se sirven desde la caché de búfer en memoria. Los archivos cuyo tamaño sea mayor que &quot;Tamaño máx. de archivo pequeño en caché (bytes)&quot;, pero menor que el tamaño máx. de archivo MMAP, se servirán desde la caché mapeada en memoria. Los archivos cuyo tamaño sea mayor que el tamaño máx. de archivo MMAP se servirán mediante lectura/escritura normal o sendfile(). Dado que el servidor tiene un espacio de direcciones de 32 bits (2GB), no se recomienda mapear en memoria archivos muy grandes.', '', 'Número entero', '');

$_tipsdb['maxMindDBEnv'] = new DAttrHelp("Variables de entorno", 'Asigna los resultados de busquedas en la base de datos a variables de entorno.', '', 'Variable_Name mapped_DB_data<br/><br/>Una entrada por linea. La ruta a los datos puede usar claves de mapa o indices de arreglo basados en 0, ambos separados por /.', 'COUNTRY_CODE COUNTRY_DB/country/iso_code<br/>REGION_CODE  CITY_DB/subdivisions/0/iso_code');

$_tipsdb['maxReqBodySize'] = new DAttrHelp("Tamaño máx. del cuerpo de solicitud (bytes)", 'Especifica el tamaño máximo del cuerpo de una solicitud HTTP. Para un sistema operativo de 32 bits, <span class=&quot;lst-inline-token lst-inline-token--value&quot;>2GB</span> es el límite estricto. Para un sistema operativo de 64 bits, es virtualmente ilimitado.', ' Para ayudar a prevenir ataques DoS, intente restringir este límite a solo lo que realmente se necesita. Su espacio de intercambio debe tener suficiente espacio libre para acomodar este límite.', 'Número entero', '');

$_tipsdb['maxReqHeaderSize'] = new DAttrHelp("Tamaño máx. de cabecera de solicitud (bytes)", 'Especifica el tamaño máximo de una cabecera de solicitud HTTP, incluida la URL de solicitud. El límite estricto es <span class=&quot;lst-inline-token lst-inline-token--value&quot;>131072</span> bytes o 128K.<br/><br/>Valor predeterminado: <span class=&quot;lst-inline-token lst-inline-token--value&quot;>32768</span> o <span class=&quot;lst-inline-token lst-inline-token--value&quot;>32K</span>', ' Establézcalo razonablemente bajo para reducir el uso de memoria y ayudar a identificar solicitudes falsas y ataques DoS.<br/>4-8K es suficiente para la mayoría de los sitios web en circunstancias normales.', 'Número entero', '');

$_tipsdb['maxReqURLLen'] = new DAttrHelp("Longitud máx. de URL de solicitud (bytes)", 'Especifica el tamaño máximo de una URL de solicitud. URL es la dirección de texto completa usada para acceder a un recurso del servidor, incluida la cadena de consulta. El límite estricto es <span class=&quot;lst-inline-token lst-inline-token--value&quot;>65530</span> bytes. Valores mayores, como <span class=&quot;lst-inline-token lst-inline-token--value&quot;>64K</span> (6 bytes más), se tratarán como si se hubiera usado <span class=&quot;lst-inline-token lst-inline-token--value&quot;>65530</span>.<br/><br/>Valor predeterminado: <span class=&quot;lst-inline-token lst-inline-token--value&quot;>8192</span> o <span class=&quot;lst-inline-token lst-inline-token--value&quot;>8K</span>.', ' Establézcalo razonablemente bajo para reducir el uso de memoria y ayudar a identificar solicitudes falsas y ataques DoS.<br/>2-3K es suficiente para la mayoría de los sitios web, salvo que se use el método HTTP GET con cadenas de consulta grandes en lugar de POST.', 'Número entero', '');

$_tipsdb['maxSSLConnections'] = new DAttrHelp("Máx. conexiones SSL", 'Especifica el número máximo de conexiones SSL concurrentes que aceptará el servidor. Dado que el total de conexiones SSL y no SSL concurrentes no puede superar el límite especificado por &quot;Máx. conexiones&quot;, el número real de conexiones SSL concurrentes permitidas debe ser inferior a este límite.', '', 'Número entero', '');

$_tipsdb['memHardLimit'] = new DAttrHelp("Límite estricto de memoria (bytes)", 'Muy similar a &quot;Límite flexible de memoria (bytes)&quot;, excepto que el límite flexible puede elevarse hasta el límite estricto desde dentro de un proceso de usuario. El límite estricto se puede establecer a nivel de servidor o a nivel de una aplicación externa individual. El límite de nivel de servidor se usará si no se establece a nivel de aplicación individual.<br/><br/>Se usará el valor predeterminado del sistema operativo si el valor falta en ambos niveles o se establece en <span class=&quot;lst-inline-token lst-inline-token--value&quot;>0</span>.', ' No ajuste este límite en exceso. Puede producir errores 503 si su aplicación necesita más memoria.', 'Número entero', '');

$_tipsdb['memSoftLimit'] = new DAttrHelp("Límite flexible de memoria (bytes)", 'Especifica el límite de consumo de memoria, en bytes, para un proceso de aplicación externa o una aplicación externa iniciada por el servidor.<br/><br/>El propósito principal de este límite es evitar un uso excesivo de memoria por errores de software o ataques intencionales, no imponer un límite al uso normal. Asegúrese de dejar margen suficiente; de lo contrario, su aplicación puede fallar y se puede devolver un error 503. Se puede establecer a nivel de servidor o a nivel de una aplicación externa individual. El límite de nivel de servidor se usará si no se establece a nivel de aplicación individual.<br/><br/>Se usará el ajuste predeterminado del sistema operativo si el valor falta en ambos niveles o se establece en <span class=&quot;lst-inline-token lst-inline-token--value&quot;>0</span>.', ' No ajuste este límite en exceso. Puede producir errores 503 si su aplicación necesita más memoria.', 'Número entero', '');

$_tipsdb['memberVHRoot'] = new DAttrHelp("Raíz del virtual host miembro", 'Especifica el directorio raíz de este virtual host. Si se deja en blanco, se usará la raíz predeterminada de virtual host para esta plantilla.<br/><br/>Nota: Esto <b>NO</b> es la raíz de documentos. Se recomienda colocar todos los archivos relacionados con el virtual host (como configuración de virtual host, archivos de registro, archivos html, scripts CGI, etc.) bajo este directorio. La raíz de virtual host puede referenciarse como $VH_ROOT.', '', 'ruta', '');

$_tipsdb['mime'] = new DAttrHelp("Configuracion MIME", 'Especifica el archivo que contiene la configuracion MIME para este servidor. Siempre es relativo a la raiz real cuando se proporciona una ruta absoluta en modo chroot. Haga clic en el nombre de archivo para ver/editar las entradas MIME detalladas.', 'Haga clic en el nombre de archivo para editar la configuracion MIME.', 'Nombre de archivo que puede ser una ruta absoluta o una ruta relativa a $SERVER_ROOT.', '');

$_tipsdb['mimesuffix'] = new DAttrHelp("Sufijos", 'Puede listar varios sufijos para el mismo tipo MIME, usando comas para separarlos.', '', '', '');

$_tipsdb['mimetype'] = new DAttrHelp("Tipo MIME", 'Un tipo MIME consta de un tipo y subtipo con el formato &quot;type/subtype&quot;.', '', '', '');

$_tipsdb['minGID'] = new DAttrHelp("GID mínimo", 'Especifica el ID de grupo mínimo permitido para ejecutar aplicaciones externas cuando se ejecutan como un grupo especificado. Se denegará la ejecución de un script externo con un ID de grupo inferior al valor especificado aquí.', ' Establézcalo lo bastante alto para excluir a todos los grupos usados por usuarios del sistema.', 'Número entero', '');

$_tipsdb['minUID'] = new DAttrHelp("UID mínimo", 'Especifica el ID de usuario mínimo permitido para ejecutar aplicaciones externas cuando se ejecutan como un usuario especificado. Se denegará la ejecución de un script externo con un ID de usuario inferior al valor especificado aquí.', ' Establézcalo lo bastante alto para excluir a todos los usuarios del sistema/privilegiados.', 'Número entero', '');

$_tipsdb['modParams'] = new DAttrHelp("Parámetros del módulo", 'Defina los parámetros del módulo. Los parámetros del módulo los define el desarrollador del módulo.<br/><br/>El valor establecido a nivel de servidor se asignará globalmente como valor predeterminado. El usuario puede sobrescribir este ajuste en los niveles de listener, host virtual o contexto. Si no se define en ninguno de esos niveles, el valor se heredará del nivel superior siguiente.', '', 'Especificada por la interfaz del módulo.', '');

$_tipsdb['moduleContext'] = new DAttrHelp("Contexto de módulo", 'Un contexto de manejador de modulo asocia una URI con un modulo registrado. Los modulos deben registrarse en la pestana Configuracion de modulos del servidor.', '', '', '');

$_tipsdb['moduleEnabled'] = new DAttrHelp("Habilitar módulo", 'Habilita los hooks del módulo globalmente. Este ajuste puede sobrescribirse en los niveles de listener y host virtual.<br/><br/>Valor predeterminado: <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Yes</span>', '', 'Seleccionar desde botones de opción', '');

$_tipsdb['moduleEnabled_lst'] = new DAttrHelp("Habilitar módulo", 'Habilita los hooks del módulo a nivel de listener. Este ajuste solo tendrá efecto si el módulo tiene hooks de nivel TCP/IP (L4_BEGSESSION, L4_ENDSESSION, L4_RECVING, L4_SENDING).<br/><br/>Valor predeterminado: heredar ajuste de nivel de servidor', '', 'Seleccionar desde botones de opción', '');

$_tipsdb['moduleEnabled_vh'] = new DAttrHelp("Habilitar módulo", 'Habilita los hooks del módulo a nivel de host virtual. Este ajuste solo tendrá efecto si el módulo tiene hooks de nivel HTTP.<br/><br/>Valor predeterminado: heredar ajuste de nivel de servidor', '', 'Seleccionar desde botones de opción', '');

$_tipsdb['moduleNameSel'] = new DAttrHelp("Modulo", 'Nombre del modulo. El modulo debe registrarse bajo la pestana Server Module Configuration. Una vez registrado, el nombre del modulo estara disponible en el menu desplegable para las configuraciones de Listener y Virtual Host.', '', 'Seleccionar de la lista desplegable', '');

$_tipsdb['modulename'] = new DAttrHelp("Módulo", 'Nombre de un módulo externo o interno que se cargará al iniciar el servidor.<br/><br/><b>Externo</b><br/>El valor usado para módulos externos debe coincidir con el nombre del archivo &quot;.so&quot; del módulo en $SERVER_ROOT/modules/modulename.so para que la aplicación del servidor pueda cargarlo. Esto requiere reiniciar el servidor después de registrar un módulo nuevo.<br/><br/><b>Interno</b><br/>El valor usado para módulos internos debe coincidir con el nombre de módulo usado al compilarlo. Por ejemplo, debe establecerse en &quot;cache&quot; para el módulo de caché interno incluido con el servidor.', '', 'cadena', '');

$_tipsdb['namespace'] = new DAttrHelp("Contenedor Namespace", 'Establézcalo en <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Enabled</span> si desea iniciar procesos CGI (incluidos programas PHP) en un sandbox de contenedor namespace. Solo se usa cuando &quot;Contenedor Bubblewrap&quot; está establecido en <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Disabled</span>.<br/><br/>Cuando no está <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Disabled</span> a nivel de servidor, este valor de ajuste se puede sobrescribir a nivel de virtual host.<br/><br/>Valores predeterminados:<br/><b>Nivel de servidor:</b> <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Disabled</span><br/><b>Nivel de virtual host:</b> Heredar el ajuste de nivel de servidor', '', 'Seleccionar de la lista desplegable', '');

$_tipsdb['namespaceConf'] = new DAttrHelp("Archivo de plantilla Namespace", 'Ruta a un archivo de configuración existente que contiene una lista de directorios que se montarán junto con los métodos usados para montarlos. Cuando &quot;Contenedor Namespace&quot; está establecido en <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Enabled</span> y este valor no está definido, se usarán los siguientes ajustes predeterminados seguros de configuración:<br/><br/><span class=&quot;lst-inline-token lst-inline-token--value&quot;> $HOMEDIR/.lsns/tmp /tmp,tmp<br/>/usr,ro-bind<br/>/lib,ro-bind<br/>/lib64,ro-bind-try<br/>/bin,ro-bind<br/>/sbin,ro-bind<br/>/var,dir<br/>/var/www,ro-bind-try<br/>/proc,proc<br/>../tmp var/tmp,symlink<br/>/dev,dev<br/>/etc/localtime,ro-bind-try<br/>/etc/ld.so.cache,ro-bind-try<br/>/etc/resolv.conf,ro-bind-try<br/>/etc/ssl,ro-bind-try<br/>/etc/pki,ro-bind-try<br/>/etc/man_db.conf,ro-bind-try<br/>/usr/local/bin/msmtp /etc/alternatives/mta,ro-bind-try<br/>/usr/local/bin/msmtp /usr/sbin/exim,ro-bind-try<br/>$HOMEDIR,bind-try<br/>/var/lib/mysql/mysql.sock,bind-try<br/>/home/mysql/mysql.sock,bind-try<br/>/tmp/mysql.sock,bind-try<br/>/run/mysqld/mysqld.sock,bind-try<br/>/var/run/mysqld.sock,bind-try<br/>/run/user/$UID,bind-try<br/>$PASSWD<br/>$GROUP<br/>/etc/exim.jail/$USER.conf $HOMEDIR/.msmtprc,copy-try<br/>/etc/php.ini,ro-bind-try<br/>/etc/php-fpm.conf,ro-bind-try<br/>/etc/php-fpm.d,ro-bind-try<br/>/var/run,ro-bind-try<br/>/var/lib,ro-bind-try<br/>/etc/imunify360/user_config/,ro-bind-try<br/>/etc/sysconfig/imunify360,ro-bind-try<br/>/opt/plesk/php,ro-bind-try<br/>/opt/alt,bind-try<br/>/opt/cpanel,bind-try<br/>/opt/psa,bind-try<br/>/var/lib/php/sessions,bind-try </span>', '', 'Una ruta absoluta o una ruta relativa a $SERVER_ROOT.', '');

$_tipsdb['namespaceConfVhAdd'] = new DAttrHelp("Archivo adicional de plantilla de namespace", 'Ruta a un archivo de configuracion existente que contiene una lista de directorios que se montaran junto con los metodos usados para montarlos. Si &quot;Archivo de plantilla Namespace&quot; tambien esta establecido en el nivel de Servidor, se usaran ambos archivos.', '', 'Una ruta que puede ser absoluta, relativa a $SERVER_ROOT o relativa a $VH_ROOT.', '');

$_tipsdb['nodeBin'] = new DAttrHelp("Ruta de Node", 'Ruta al ejecutable de Node.js.', '', 'Ruta absoluta', '');

$_tipsdb['nodeDefaults'] = new DAttrHelp("Ajustes predeterminados de apps Node.js", 'Configuraciones predeterminadas para aplicaciones Node.js. Estos ajustes pueden sobrescribirse a nivel de contexto.', '', '', '');

$_tipsdb['note'] = new DAttrHelp("Notas", 'Agregue notas para usted.', '', '', '');

$_tipsdb['ocspCACerts'] = new DAttrHelp("Certificados CA de OCSP", 'Especifica la ubicacion del archivo donde se almacenan los certificados de autoridad de certificacion (CA) de OCSP. Estos certificados se usan para comprobar las respuestas del OCSP responder (y asegurarse de que esas respuestas no sean falsificadas ni comprometidas de otra forma). Este archivo debe contener toda la cadena de certificados. Si este archivo no contiene el certificado raiz, LSWS deberia poder encontrar el certificado raiz en el directorio del sistema sin que usted lo agregue al archivo; pero, si esta validacion falla, debe intentar agregar su certificado raiz a este archivo.<br/><br/>Esta opcion es opcional. Si no se establece, el servidor comprobara automaticamente &quot;Archivo de certificados CA&quot;.', '', 'Nombre de archivo que puede ser una ruta absoluta o una ruta relativa a $SERVER_ROOT.', '');

$_tipsdb['ocspRespMaxAge'] = new DAttrHelp("Edad maxima de respuesta OCSP (seg)", 'Esta opcion establece la edad maxima permitida para una respuesta OCSP. Si una respuesta OCSP es mas antigua que esta edad maxima, el servidor contactara al OCSP responder para obtener una nueva respuesta. El valor predeterminado es <span class=&quot;lst-inline-token lst-inline-token--value&quot;>86400</span>. La edad maxima puede desactivarse estableciendo este valor en <span class=&quot;lst-inline-token lst-inline-token--value&quot;>-1</span>.', '', 'Entero de segundos', '');

$_tipsdb['ocspResponder'] = new DAttrHelp("OCSP Responder", 'Especifica la URL del OCSP responder que se usara. Si no se establece, el servidor intentara contactar al OCSP responder detallado en el certificado emisor de la autoridad de certificacion. Algunos certificados emisores pueden no tener especificada una URL de OCSP responder.', '', 'URL que empieza con <span class=&quot;lst-inline-token lst-inline-token--value&quot;>http://</span>', '<span class=&quot;lst-inline-token lst-inline-token--value&quot;>http://rapidssl-ocsp.geotrust.com </span>');

$_tipsdb['opsAuditRetainFiles'] = new DAttrHelp("Archivos retenidos del registro de actividad", 'Especifica el numero maximo de archivos de auditoria de operaciones que se conservaran para la consola WebAdmin. Valor predeterminado si no se define: 30 archivos.', 'Aumente este valor si necesita un rastro de auditoria mas largo, pero recuerde que mas archivos usaran mas espacio en disco.', 'Número entero', '');

$_tipsdb['outBandwidth'] = new DAttrHelp("Ancho de banda saliente (bytes/s)", 'El rendimiento saliente máximo permitido hacia una sola dirección IP, sin importar cuántas conexiones estén establecidas. El ancho de banda real puede terminar siendo ligeramente superior a este ajuste por razones de eficiencia. El ancho de banda se asigna en unidades de 4KB. Establezca <span class=&quot;lst-inline-token lst-inline-token--value&quot;>0</span> para deshabilitar el throttling. Los límites de ancho de banda por cliente (bytes/s) se pueden establecer a nivel de servidor o de virtual host, donde los ajustes de nivel de virtual host sobrescriben los de nivel de servidor.', ' Establezca el ancho de banda en unidades de 8KB para obtener mejor rendimiento.<br/><br/> Las IP o subredes de confianza no se ven afectadas.', 'Número entero', '');

$_tipsdb['pcKeepAliveTimeout'] = new DAttrHelp("Tiempo de keepalive de conexion", 'Especifica el tiempo maximo en segundos durante el que se mantiene abierta una conexion persistente inactiva.<br/><br/>Cuando se establece en &quot;-1&quot;, la conexion nunca expirara. Cuando se establece en 0 o mas, la conexion se cerrara despues de que pase este tiempo en segundos.', '', 'Número entero', '');

$_tipsdb['perClientConnLimit'] = new DAttrHelp("Throttling por cliente", 'Estos ajustes de control de conexiones se basan en la IP del cliente. Ayudan a mitigar ataques DoS (Denial of Service) y DDoS (Distributed Denial of Service).', '', '', '');

$_tipsdb['persistConn'] = new DAttrHelp("Conexion persistente", 'Especifica si se mantiene abierta la conexion despues de procesar una solicitud. Las conexiones persistentes pueden aumentar el rendimiento, pero algunas aplicaciones FastCGI externas no admiten completamente las conexiones persistentes. El valor predeterminado es &quot;On&quot;.', '', 'Seleccionar desde botones de opción', '');

$_tipsdb['phpIniOverride'] = new DAttrHelp("Anulación de php.ini", 'Se usa para sobrescribir ajustes de php.ini en el contexto actual (nivel de virtual host o nivel de contexto).<br/><br/>Las directivas admitidas son:<br/>php_value<br/>php_flag<br/>php_admin_value<br/>php_admin_flag<br/><br/>Todas las demás líneas/directivas se ignorarán.', '', 'La sintaxis de anulación es similar a Apache: una lista de directivas y sus valores separada por saltos de línea, con cada directiva precedida por php_value, php_flag, php_admin_value o php_admin_flag según corresponda.', 'php_value include_path &quot;.:/usr/local/lib/php&quot;<br/>php_admin_flag engine on<br/>php_admin_value open_basedir &quot;/home&quot;');

$_tipsdb['pid'] = new DAttrHelp("PID", 'PID (ID de proceso) del proceso actual del servidor.', 'El PID cambiará cada vez que se reinicie el servidor.', '', '');

$_tipsdb['procHardLimit'] = new DAttrHelp("Límite estricto de procesos", 'Muy similar a &quot;Limite blando de procesos&quot;, excepto que el límite flexible puede elevarse hasta el límite estricto desde dentro de un proceso de usuario. El límite estricto se puede establecer a nivel de servidor o a nivel de una aplicación externa individual. El límite de nivel de servidor se usará si no se establece a nivel de aplicación individual. Se usará el valor predeterminado del sistema operativo si el valor falta en ambos niveles o se establece en <span class=&quot;lst-inline-token lst-inline-token--value&quot;>0</span>.', '', 'Número entero', '');

$_tipsdb['procSoftLimit'] = new DAttrHelp("Limite blando de procesos", 'Limita el numero total de procesos que pueden crearse en nombre de un usuario. Todos los procesos existentes se contaran contra este limite, no solo los procesos nuevos que se inicien.<br/><br/>El limite puede establecerse a nivel de servidor o a nivel de aplicacion externa individual. El limite de nivel de servidor se usara si no se establece a nivel de aplicacion individual. Se usara el valor predeterminado del sistema operativo si este valor es 0 o falta en ambos niveles.', 'Los scripts PHP pueden solicitar la creacion de procesos. El objetivo principal de este limite es actuar como ultima linea de defensa para evitar fork bombs y otros ataques causados por procesos PHP que crean otros procesos.<br/><br/>Establecer este ajuste demasiado bajo puede perjudicar gravemente la funcionalidad. Por tanto, el ajuste se ignorara por debajo de ciertos niveles.<br/><br/>Cuando <b>Run On Start Up</b> se establece en &quot;Yes (Daemon mode)&quot;, el limite real de procesos sera superior a este ajuste para asegurarse de que los procesos padre no queden limitados.', 'Número entero', '');

$_tipsdb['proxyContext'] = new DAttrHelp("Contexto proxy", 'Un contexto proxy habilita este host virtual como servidor proxy inverso transparente. Este servidor proxy puede ejecutarse delante de cualquier servidor web o servidor de aplicaciones que admita el protocolo HTTP. El servidor web externo para el que este host virtual actua como proxy debe definirse en &quot;Aplicaciones externas&quot; antes de configurar un contexto proxy.', '', '', '');

$_tipsdb['proxyProtocol'] = new DAttrHelp("Protocolo PROXY", 'Lista de IP/subredes para proxies front-end que se comunican con este servidor usando el protocolo PROXY. Una vez establecido, el servidor usará el protocolo PROXY para conexiones entrantes desde las IP/subredes listadas, o recurrirá a una conexión normal si el protocolo PROXY no está disponible.<br/><br/>Se aplica a conexiones HTTP, HTTPS, HTTP2 y websocket.', '', 'Lista delimitada por comas de direcciones IP o subredes.', '');

$_tipsdb['proxyWebServer'] = new DAttrHelp("Servidor web", 'Especifica el nombre del servidor web externo. Este servidor web externo debe definirse en la seccion &quot;Aplicaciones externas&quot; a nivel de servidor o virtual host.', '', 'Seleccionar de la lista desplegable', '');

$_tipsdb['quicBasePLPMTU'] = new DAttrHelp("Valor base de PLPMTU", 'El valor máximo de PLPMTU (tamaño máximo de paquete sin cabeceras), en bytes, que QUIC usará de forma predeterminada. Establecerlo en <span class=&quot;lst-inline-token lst-inline-token--value&quot;>0</span> permitirá que QUIC elija el tamaño.<br/><br/>Este ajuste debe ser menor que &quot;Valor máx. de PLPMTU&quot;.<br/><br/>Valor predeterminado: 0', '', '0 o número entero entre 1200 y 65527', '');

$_tipsdb['quicCfcw'] = new DAttrHelp("Ventana de control de flujo de conexión", 'El tamaño inicial del búfer asignado para una conexión QUIC. El valor predeterminado es <span class=&quot;lst-inline-token lst-inline-token--value&quot;>1.5M</span>.', 'Un tamaño de ventana mayor usará más memoria.', 'Número entre 64K y 512M', '');

$_tipsdb['quicCongestionCtrl'] = new DAttrHelp("Control de congestión", 'Algoritmo de control de congestión usado. Puede establecerse manualmente o dejarse a la biblioteca QUIC en uso seleccionando la opción &quot;Default&quot;.<br/><br/>Valor predeterminado: Default', '', 'Seleccionar de la lista desplegable', '');

$_tipsdb['quicEnable'] = new DAttrHelp("Habilitar HTTP3/QUIC", 'Habilita el protocolo de red HTTP3/QUIC en todo el servidor. El valor predeterminado es <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Yes</span>.', 'Cuando este ajuste está en <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Yes</span>, HTTP3/QUIC aún se puede deshabilitar a nivel de listener mediante el ajuste &quot;Abrir puerto HTTP3/QUIC (UDP)&quot;, o a nivel de virtual host mediante el ajuste &quot;Habilitar HTTP3/QUIC&quot;.', 'Seleccionar desde botones de opción', '');

$_tipsdb['quicEnableDPLPMTUD'] = new DAttrHelp("Habilitar DPLPMTUD", 'Habilita Datagram Packetization Layer Path Maximum Transmission Unit Discovery (DPLPMTUD).<br/><br/><b>   <a href="     https://tools.ietf.org/html/rfc8899   " target="_blank" rel="noopener noreferrer">     Background on DPLPMTUD (RFC 8899)   </a> </b><br/><br/>Valor predeterminado: Yes', '', 'Seleccionar desde botones de opción', '');

$_tipsdb['quicHandshakeTimeout'] = new DAttrHelp("Tiempo de Espera de Handshake (segs)", 'El tiempo en segundos que se concede a una nueva conexión QUIC para completar su handshake; después de este tiempo, la conexión se aborta. El valor predeterminado es <span class=&quot;lst-inline-token lst-inline-token--value&quot;>10</span>.', '', 'Número entero entre 1 y 15', '');

$_tipsdb['quicIdleTimeout'] = new DAttrHelp("Tiempo de Espera de Inactividad (segs)", 'El tiempo en segundos después del cual se cerrará una conexión QUIC inactiva. El valor predeterminado es <span class=&quot;lst-inline-token lst-inline-token--value&quot;>30</span>.', '', 'Número entero entre 10 y 30', '');

$_tipsdb['quicMaxCfcw'] = new DAttrHelp("Ventana máx. de control de flujo de conexión", 'Especifica el tamaño máximo que se permite alcanzar a un búfer de ventana de control de flujo de conexión debido al autoajuste de ventana.<br/><br/>El valor predeterminado es <span class=&quot;lst-inline-token lst-inline-token--value&quot;>0</span>, lo que significa que se usa el valor de &quot;Ventana de control de flujo de conexión&quot; y no se realiza autoajuste.', 'Un tamaño de ventana mayor usará más memoria.', '0 o un número entre 64K y 512M', '');

$_tipsdb['quicMaxPLPMTU'] = new DAttrHelp("Valor máx. de PLPMTU", 'El límite superior de sondeo de PLPMTU (tamaño máximo de paquete sin cabeceras), en bytes. Este ajuste se usa para limitar el &quot;tamaño máximo de paquete&quot; en el espacio de búsqueda DPLPMTUD. Establecerlo en <span class=&quot;lst-inline-token lst-inline-token--value&quot;>0</span> permitirá que QUIC elija el tamaño (de forma predeterminada LSQUIC asume que MTU es 1,500 bytes (Ethernet)).<br/><br/>Este ajuste debe ser mayor que &quot;Valor base de PLPMTU&quot;.<br/>Valor predeterminado: 0', '', '0 o número entero entre 1200 y 65527', '');

$_tipsdb['quicMaxSfcw'] = new DAttrHelp("Ventana máx. de control de flujo de stream", 'Especifica el tamaño máximo que se permite alcanzar a una ventana de control de flujo de stream debido al autoajuste de ventana.<br/><br/>El valor predeterminado es <span class=&quot;lst-inline-token lst-inline-token--value&quot;>0</span>, lo que significa que se usa el valor de &quot;Ventana de control de flujo de stream&quot; y no se realiza autoajuste.', 'Un tamaño de ventana mayor usará más memoria.', '0 o un número entre 64K y 128M', '');

$_tipsdb['quicMaxStreams'] = new DAttrHelp("Máx. streams concurrentes por conexión", 'El número máximo de streams concurrentes permitidos por conexión QUIC. El valor predeterminado es <span class=&quot;lst-inline-token lst-inline-token--value&quot;>100</span>.', '', 'Número entero entre 10 y 1000', '');

$_tipsdb['quicSfcw'] = new DAttrHelp("Ventana de control de flujo de stream", 'La cantidad inicial de datos que una conexión QUIC está dispuesta a recibir por stream. El valor predeterminado es <span class=&quot;lst-inline-token lst-inline-token--value&quot;>1M</span>.', 'Un tamaño de ventana mayor usará más memoria.', 'Número entre 64K y 128M', '');

$_tipsdb['quicShmDir'] = new DAttrHelp("Directorio SHM QUIC", 'Especifica el directorio usado para guardar datos QUIC en memoria compartida.<br/><br/>De forma predeterminada se usará el directorio SHM predeterminado del servidor, <span class=&quot;lst-inline-token lst-inline-token--value&quot;>/dev/shm</span>.', 'Se recomienda una partición basada en RAM, como <span class=&quot;lst-inline-token lst-inline-token--value&quot;>/dev/shm</span>.', 'Ruta', '');

$_tipsdb['quicVersions'] = new DAttrHelp("Versiones HTTP3/QUIC", 'Lista de versiones HTTP3/QUIC habilitadas. Este ajuste solo debe usarse para limitar la compatibilidad HTTP3/QUIC a las versiones listadas y es mejor dejarlo en blanco.', 'Se recomienda dejar este ajuste en blanco para que se aplique automáticamente la mejor configuración.', 'Lista separada por comas', 'h3-29, h3-Q050');

$_tipsdb['railsDefaults'] = new DAttrHelp("Configuración predeterminada de Rack/Rails", 'Configuraciones predeterminadas para aplicaciones Rack/Rails. Estos ajustes pueden sobrescribirse a nivel de contexto.', '', '', '');

$_tipsdb['rcvBufSize'] = new DAttrHelp("Tamaño de búfer de recepción (bytes)", 'El tamaño del búfer de recepción de cada socket TCP. <span class=&quot;lst-inline-token lst-inline-token--value&quot;>512K</span> es el tamaño máximo permitido del búfer.', ' Se recomienda dejar este valor como &quot;Not Set&quot; o establecerlo en 0 para usar el tamaño de búfer predeterminado del sistema operativo.<br/> Un búfer de recepción grande aumentará el rendimiento al procesar solicitudes entrantes con cargas grandes, por ejemplo cargas de archivos.<br/> Establecerlo en un valor menor reducirá el rendimiento y el uso de memoria por socket, permitiendo al servidor tener más sockets concurrentes cuando la memoria sea un cuello de botella.', 'Número entero', '');

$_tipsdb['realm'] = new DAttrHelp("Realm", 'Especifica el realm de autorizacion para este contexto. Cuando se especifica, deben proporcionarse un nombre de usuario y una contrasena validos para acceder a este contexto. &quot;Realms de autorizacion&quot; se configuran en la seccion &quot;Host virtual - Seguridad&quot;. Esta opcion usa el &quot;Nombre del realm&quot; de cada realm.', '', 'Seleccionar de la lista desplegable', '');

$_tipsdb['realmName'] = new DAttrHelp("Nombre del realm", 'Especifica un nombre unico para el realm de autorizacion.', '', '', '');

$_tipsdb['realms'] = new DAttrHelp("Realms de autorizacion", 'Lista todos los realms de autorizacion para este virtual host. Los realms de autorizacion se usan para impedir que usuarios no autorizados accedan a paginas web protegidas. Un realm es un directorio de usuarios que contiene nombres de usuario y contrasenas con clasificaciones de grupo opcionales. La autorizacion se realiza a nivel de contexto. Como distintos contextos pueden compartir el mismo realm (base de datos de usuarios), los realms se definen por separado de los contextos que los usan. Puede hacer referencia a un realm por estos nombres en la configuracion de contexto.', '', '', '');

$_tipsdb['realtimerpt'] = new DAttrHelp("Estadísticas en tiempo real", 'El enlace Real-Time Statistics lleva a una página con un informe de estado del servidor en tiempo real. Es una herramienta cómoda para supervisar el sistema.<br/><br/>El informe muestra una instantánea de las estadísticas del servidor. La frecuencia de actualización de esta instantánea se controla mediante la lista desplegable Refresh Interval en la esquina superior derecha.<br/><br/>El informe contiene las siguientes secciones: <ul><li>Server Health muestra estadísticas básicas del servidor, tiempo activo, carga e IP bloqueadas por Anti-DDoS.</li>   <li>Server muestra estadísticas actuales de rendimiento de tráfico, conexiones y solicitudes.</li>  <li>Virtual Host muestra estados de procesamiento de solicitudes y estados de aplicaciones externas para cada host virtual.</li>  <li>External Application muestra las aplicaciones externas que se están ejecutando y sus estadísticas de uso. El proceso demonio CGI lscgid siempre se ejecuta como una aplicación externa.</li> </ul><br/><br/>Muchas filas de Real-Time Statistics incluyen un icono de gráfico. Al hacer clic en este icono se abre un gráfico de las estadísticas de esa fila actualizado en tiempo real.<br/><br/>En la sección Server, junto a Requests, hay un enlace llamado (Details). Este enlace lleva a Requests Snapshot, donde puede ver información detallada sobre qué clientes hacen ciertos tipos de solicitudes o qué aspectos del sitio generan cuellos de botella. Los campos del área azul permiten filtrar la instantánea para aislar partes concretas del servidor o buscar clientes que realizan ciertas acciones.', '', '', '');

$_tipsdb['recaptchaAllowedRobotHits'] = new DAttrHelp("Accesos de robots permitidos", 'Número de accesos cada 10 segundos que se permite pasar a los ‘good bots’. Los bots aún serán limitados cuando el servidor esté bajo carga.<br/><br/>El valor predeterminado es <span class=&quot;lst-inline-token lst-inline-token--value&quot;>3</span>.', '', 'Número entero', '');

$_tipsdb['recaptchaBotWhiteList'] = new DAttrHelp("Lista blanca de bots", 'Lista de user agents personalizados a los que se permite el acceso. Estarán sujetos a las limitaciones de ‘good bots’, incluido allowedRobotHits.', '', 'Lista de user agents, uno por línea. Se admite regex.', '');

$_tipsdb['recaptchaMaxTries'] = new DAttrHelp("Máx. intentos", 'Max Tries especifica el número máximo de intentos de CAPTCHA permitidos antes de denegar al visitante.<br/><br/>El valor predeterminado es <span class=&quot;lst-inline-token lst-inline-token--value&quot;>3</span>.', '', 'Número entero', '');

$_tipsdb['recaptchaRegConnLimit'] = new DAttrHelp("Límite de conexiones", 'El número de conexiones concurrentes (SSL y no SSL) necesario para activar CAPTCHA. CAPTCHA continuará usándose hasta que el recuento de conexiones concurrentes caiga por debajo de este número.<br/><br/>El valor predeterminado es <span class=&quot;lst-inline-token lst-inline-token--value&quot;>15000</span>.', '', 'Número entero', '');

$_tipsdb['recaptchaSecretKey'] = new DAttrHelp("Clave secreta", 'La clave privada asignada por los servicios reCAPTCHA o hCaptcha.<br/><br/>Al usar reCAPTCHA, se usará una clave secreta predeterminada si no se establece una (no recomendado).', '', '', '');

$_tipsdb['recaptchaSiteKey'] = new DAttrHelp("Clave de sitio", 'La clave pública asignada por los servicios reCAPTCHA o hCaptcha.<br/><br/>Al usar reCAPTCHA, se usará una clave de sitio predeterminada si no se establece una (no recomendado).', '', '', '');

$_tipsdb['recaptchaSslConnLimit'] = new DAttrHelp("Límite de conexiones SSL", 'El número de conexiones SSL concurrentes necesario para activar CAPTCHA. CAPTCHA continuará usándose hasta que el recuento de conexiones concurrentes caiga por debajo de este número.<br/><br/>El valor predeterminado es <span class=&quot;lst-inline-token lst-inline-token--value&quot;>10000</span>.', '', 'Número entero', '');

$_tipsdb['recaptchaType'] = new DAttrHelp("Tipo de CAPTCHA", 'Especifique el tipo de CAPTCHA que se usará con los pares de claves.<br/>Si no se ha proporcionado un par de claves y este ajuste está en <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Not Set</span>, se usará un par de claves predeterminado de tipo CAPTCHA <span class=&quot;lst-inline-token lst-inline-token--value&quot;>reCAPTCHA Invisible</span>.<br/><br/><span class=&quot;lst-inline-token lst-inline-token--value&quot;>reCAPTCHA Checkbox</span> mostrará un CAPTCHA con casilla de verificación para que el visitante valide. (requiere &quot;Clave de sitio&quot;, &quot;Clave secreta&quot;)<br/><br/><span class=&quot;lst-inline-token lst-inline-token--value&quot;>reCAPTCHA Invisible</span> intentará validar el CAPTCHA automáticamente y, si tiene éxito, redirigirá a la página deseada. (requiere &quot;Clave de sitio&quot;, &quot;Clave secreta&quot;)<br/><br/><span class=&quot;lst-inline-token lst-inline-token--value&quot;>hCaptcha</span> se puede usar para admitir el proveedor CAPTCHA <a href="https://www.hcaptcha.com" target="_blank" rel="noopener noreferrer">hCaptcha</a>. (requiere &quot;Clave de sitio&quot;, &quot;Clave secreta&quot;)<br/><br/>El valor predeterminado es <span class=&quot;lst-inline-token lst-inline-token--value&quot;>reCAPTCHA Invisible</span>.', '', 'Seleccionar de la lista desplegable', '');

$_tipsdb['recaptchaVhReqLimit'] = new DAttrHelp("Limite de solicitudes concurrentes", 'El numero de solicitudes concurrentes necesario para activar CAPTCHA. CAPTCHA seguira usandose hasta que el recuento de solicitudes concurrentes caiga por debajo de este numero.<br/><br/>El valor predeterminado es <span class=&quot;lst-inline-token lst-inline-token--value&quot;>15000</span>.', '', 'Número entero', '');

$_tipsdb['redirectContext'] = new DAttrHelp("Contexto de redirección", 'Un contexto de redireccion puede usarse para reenviar una URI o un grupo de URIs a otra ubicacion. La URI de destino puede estar en el mismo sitio web (una redireccion interna) o ser una URI absoluta que apunte a otro sitio web (una redireccion externa).', '', '', '');

$_tipsdb['renegProtection'] = new DAttrHelp("Proteccion contra renegociacion SSL", 'Especifica si se debe habilitar la Proteccion contra renegociacion SSL para defenderse de ataques basados en handshake SSL. El valor predeterminado es &quot;Yes&quot;.', 'Esta opcion puede habilitarse en los niveles de listener y virtual host.', 'Seleccionar desde botones de opción', '');

$_tipsdb['required'] = new DAttrHelp("Require (usuarios/grupos autorizados)", 'Especifica que usuario/grupo puede acceder a este contexto. Esto permite usar una base de datos de usuarios/grupos (especificada en &quot;Realm&quot;) en varios contextos, pero permitir que solo ciertos usuarios/grupos de esa base de datos accedan a este contexto.', '', 'La sintaxis es compatible con la directiva Require de Apache. Por ejemplo: <ul> <li><span class=&quot;lst-inline-token lst-inline-token--value&quot;>user username [username ...]</span><br/>Solo los usuarios listados pueden acceder a este contexto.</li> <li> <span class=&quot;lst-inline-token lst-inline-token--value&quot;>group groupid [groupid ...]</span><br/>Solo los usuarios pertenecientes a los grupos listados pueden acceder a este contexto.</li> </ul> Si esta opcion no se especifica, todos los usuarios validos podran acceder a este recurso.', '');

$_tipsdb['requiredPermissionMask'] = new DAttrHelp("Máscara de permisos requerida", 'Especifica la máscara de permisos requerida para los archivos estáticos que servirá el servidor. Por ejemplo, si solo se deben servir archivos legibles por todos, establezca el valor en <span class=&quot;lst-inline-token lst-inline-token--value&quot;>0004</span>. Consulte <span class=&quot;lst-inline-token lst-inline-token--command&quot;>man 2 stat</span> para ver todos los valores.', '', 'números octales', '');

$_tipsdb['respBuffer'] = new DAttrHelp("Buffering de respuesta", 'Especifica si se almacenan en buffer las respuestas recibidas de aplicaciones externas. Si se detecta un script &quot;nph-&quot; (Non-Parsed-Header), el buffering se desactiva para respuestas con cabeceras HTTP completas.', '', 'Seleccionar de la lista desplegable', '');

$_tipsdb['restart'] = new DAttrHelp("Aplicar cambios/Graceful Restart", 'Al hacer clic en <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Graceful Restart</span>, se iniciará un nuevo proceso del servidor. Para <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Graceful Restart</span>, el proceso anterior solo saldrá después de que terminen todas sus solicitudes (o se alcance el límite &quot;Timeout de reinicio graceful (seg)&quot;).<br/><br/>Los cambios de configuración se aplican en el siguiente reinicio. <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Graceful Restart</span> aplicará estos cambios sin tiempo de inactividad del servidor.', 'Graceful restart tarda menos de 2 segundos en generar un nuevo proceso del servidor.', '', '');

$_tipsdb['restrained'] = new DAttrHelp("Restringido", 'Especifica si se puede acceder a archivos fuera de la raiz de este virtual host ($VH_ROOT) a traves de este sitio web. Si se establece en <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Yes</span>, solo se podra acceder a archivos bajo $VH_ROOT y se denegara el acceso a enlaces simbolicos o contextos que apunten a archivos o directorios fuera de $VH_ROOT. Sin embargo, esto no limita la accesibilidad de los scripts CGI. Es util en entornos de hosting compartido. &quot;Seguir enlaces simbolicos&quot; puede establecerse en <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Yes</span> para permitir que los usuarios usen enlaces simbolicos bajo $VH_ROOT, pero no nada fuera de $VH_ROOT.', ' Activelo en entornos de hosting compartido.', 'Seleccionar desde botones de opción', '');

$_tipsdb['restrictedDirPermissionMask'] = new DAttrHelp("Máscara de permisos restringida para directorios de scripts", 'Especifica la máscara de permisos restringida de los directorios padre de archivos de script que el servidor no servirá. Por ejemplo, para prohibir servir scripts PHP en un directorio escribible por grupo y por todos, establezca la máscara en <span class=&quot;lst-inline-token lst-inline-token--value&quot;>022</span>. El valor predeterminado es <span class=&quot;lst-inline-token lst-inline-token--value&quot;>000</span>. Esta opción se puede usar para evitar servir scripts bajo un directorio de archivos cargados.<br/><br/>Consulte <span class=&quot;lst-inline-token lst-inline-token--command&quot;>man 2 stat</span> para ver todos los valores.', '', 'números octales', '');

$_tipsdb['restrictedPermissionMask'] = new DAttrHelp("Máscara de permisos restringida", 'Especifica la máscara de permisos restringida para archivos estáticos que el servidor no servirá. Por ejemplo, para prohibir servir archivos ejecutables, establezca la máscara en <span class=&quot;lst-inline-token lst-inline-token--value&quot;>0111</span>.<br/><br/>Consulte <span class=&quot;lst-inline-token lst-inline-token--command&quot;>man 2 stat</span> para ver todos los valores.', '', 'números octales', '');

$_tipsdb['restrictedScriptPermissionMask'] = new DAttrHelp("Máscara de permisos restringida para scripts", 'Especifica la máscara de permisos restringida para archivos de script que el servidor no servirá. Por ejemplo, para prohibir servir scripts PHP que sean escribibles por grupo y por todos, establezca la máscara en <span class=&quot;lst-inline-token lst-inline-token--value&quot;>022</span>. El valor predeterminado es <span class=&quot;lst-inline-token lst-inline-token--value&quot;>000</span>.<br/><br/>Consulte <span class=&quot;lst-inline-token lst-inline-token--command&quot;>man 2 stat</span> para ver todos los valores.', '', 'números octales', '');

$_tipsdb['retryTimeout'] = new DAttrHelp("Tiempo de reintento (s)", 'Especifica el periodo de tiempo que el servidor espera antes de volver a intentar usar una aplicacion externa que tuvo un problema de comunicacion previo.', '', 'Número entero', '');

$_tipsdb['reusePort'] = new DAttrHelp("Habilitar REUSEPORT", 'Usa la opcion de socket SO_REUSEPORT para distribuir el trafico entrante entre varios workers. Este ajuste solo es efectivo para licencias con multiples workers. Cuando esta habilitado, todos los workers se enlazan automaticamente a este listener y se ignora la configuracion de &quot;Enlace&quot;.<br/><br/>Valor predeterminado: activado', '', 'Seleccionar desde botones de opción', '');

$_tipsdb['rewriteBase'] = new DAttrHelp("Base rewrite", 'Especifica la URL base para las reglas rewrite.', '', 'URL', '');

$_tipsdb['rewriteInherit'] = new DAttrHelp("Heredar rewrite", 'Especifica si se deben heredar reglas rewrite de contextos padre. Si rewrite esta habilitado y no se hereda, se usaran la base rewrite y las reglas rewrite definidas en este contexto.', '', 'Seleccionar desde botones de opción', '');

$_tipsdb['rewriteLogLevel'] = new DAttrHelp("Nivel de registro", 'Especifica el nivel de detalle de la salida de depuración del motor de reescritura. Este valor va de <span class=&quot;lst-inline-token lst-inline-token--value&quot;>0</span> a <span class=&quot;lst-inline-token lst-inline-token--value&quot;>9</span>. <span class=&quot;lst-inline-token lst-inline-token--value&quot;>0</span> deshabilita el registro. <span class=&quot;lst-inline-token lst-inline-token--value&quot;>9</span> produce el registro más detallado. El registro de errores del servidor y del virtual host &quot;Nivel de registro&quot; debe configurarse al menos en <span class=&quot;lst-inline-token lst-inline-token--value&quot;>INFO</span> para que esta opción tenga efecto. Es útil al probar reglas de reescritura.', '', 'Número entero', '');

$_tipsdb['rewriteMapLocation'] = new DAttrHelp("Ubicación", 'Especifica la ubicación del rewrite map usando la sintaxis <span class=&quot;lst-inline-token lst-inline-token--value&quot;>MapType:MapSource</span>.<br/>El motor de reescritura de LiteSpeed admite tres tipos de rewrite maps: <ul> 	<li><b>Texto plano estándar</b> <blockquote> 		<b>MapType:</b> txt;<br/>		<b>MapSource:</b> ruta de archivo a un archivo ASCII plano válido. </blockquote> 		Cada línea de este archivo debe contener dos elementos separados por espacios en blanco. El primer elemento es la clave y el segundo es el valor. Se pueden agregar comentarios con un signo inicial &quot;<span class=&quot;lst-inline-token lst-inline-token--value&quot;>#</span>&quot;. 	</li> 	<li><b>Texto plano aleatorizado</b> <blockquote> 		<b>MapType:</b> rnd;<br/>		<b>MapSource:</b> ruta de archivo de un archivo ASCII plano válido. </blockquote> 		El formato del archivo es similar al de texto plano estándar, excepto que el segundo elemento puede contener varias opciones separadas por un signo &quot;<span class=&quot;lst-inline-token lst-inline-token--value&quot;>|</span>&quot; y elegidas aleatoriamente por el motor de reescritura. 	</li> 	<li><b>Función interna</b> <blockquote> 	    <b>MapType:</b> int;<br/>		<b>MapSource:</b> función interna de cadena </blockquote> 		Hay 4 funciones disponibles: 		<ul> 			<li><b>toupper:</b> convierte la clave de búsqueda a mayúsculas.</li> 			<li><b>tolower:</b> convierte la clave de búsqueda a minúsculas.</li> 			<li><b>escape:</b> aplica codificación URL a la clave de búsqueda.</li> 			<li><b>unescape:</b> aplica decodificación URL a la clave de búsqueda.</li> 		</ul> 	</li> 	Los siguientes tipos de mapa disponibles en Apache no se han implementado en LiteSpeed:<br/>Hash File y External Rewriting Program. </ul> La implementación del motor de reescritura de LiteSpeed sigue las especificaciones del motor de reescritura de Apache. Para más detalles sobre rewrite map, consulte <a href="http://httpd.apache.org/docs/current/mod/mod_rewrite.html" target="_blank" rel="noopener noreferrer">documentación mod_rewrite de Apache</a>.', '', 'Cadena', '');

$_tipsdb['rewriteMapName'] = new DAttrHelp("Nombre", 'Especifica un nombre único para el rewrite map a nivel de virtual host. Este nombre será usado por una referencia de mapeo en las reglas de reescritura. Al referenciar este nombre, debe usarse una de las siguientes sintaxis: <blockquote><code> $\{MapName:LookupKey\}<br/>$\{MapName:LookupKey|DefaultValue\} </code></blockquote><br/>La implementación del motor de reescritura de LiteSpeed sigue las especificaciones del motor de reescritura de Apache. Para más detalles sobre rewrite maps, consulte <a href="http://httpd.apache.org/docs/current/mod/mod_rewrite.html" target="_blank" rel="noopener noreferrer">documentación mod_rewrite de Apache</a>.', '', 'cadena', '');

$_tipsdb['rewriteRules'] = new DAttrHelp("Reglas de reescritura", 'Especifica una lista de reglas de reescritura a nivel de virtual host.<br/><br/>NO agregue aquí reglas de reescritura de nivel de raíz de documentos. Si tiene reglas de reescritura de nivel de raíz de documentos desde .htaccess, debe crear en su lugar un contexto estático con uri &quot;/&quot; y agregar allí las reglas de reescritura.<br/><br/>Una regla de reescritura consta de una directiva <span class=&quot;lst-inline-token lst-inline-token--value&quot;>RewriteRule</span> y, opcionalmente, puede ir precedida por varias directivas <span class=&quot;lst-inline-token lst-inline-token--value&quot;>RewriteCond</span>. <ul>   <li>Cada directiva debe ocupar una sola línea.</li>   <li>     <span class=&quot;lst-inline-token lst-inline-token--value&quot;>RewriteCond</span> y <span class=&quot;lst-inline-token lst-inline-token--value&quot;>RewriteRule</span> siguen la sintaxis de directivas rewrite de Apache. Simplemente copie y pegue directivas rewrite desde sus archivos de configuración de Apache.   </li>   <li>     Hay pequeñas diferencias entre las implementaciones de LiteSpeed y Apache mod_rewrite:     <ul>       <li>         <span class=&quot;lst-inline-token lst-inline-token--value&quot;>%\{LA-U:variable\}</span> y <span class=&quot;lst-inline-token lst-inline-token--value&quot;>%\{LA-F:variable\}</span> son ignoradas por el motor de reescritura de LiteSpeed       </li>       <li>         Se agregan dos nuevas variables de servidor al motor de reescritura de LiteSpeed: <span class=&quot;lst-inline-token lst-inline-token--value&quot;>%\{CURRENT_URI\}</span> representa la URI actual que procesa el motor de reescritura y <span class=&quot;lst-inline-token lst-inline-token--value&quot;>%\{SCRIPT_NAME\}</span> tiene el mismo significado que la variable de entorno CGI correspondiente.       </li>       <li>         El motor de reescritura de LiteSpeed dejará de procesar reglas de reescritura después de encontrar una marca <span class=&quot;lst-inline-token lst-inline-token--value&quot;>[L]</span> para evitar bucles, mientras que Apache mod_rewrite dejará de procesar reglas de reescritura solo para la iteración actual. Este comportamiento es similar al de la marca <span class=&quot;lst-inline-token lst-inline-token--value&quot;>[END]</span> en Apache mod_rewrite.       </li>     </ul>   </li> </ul><br/>La implementación del motor de reescritura de LiteSpeed sigue las especificaciones del motor de reescritura de Apache. Para más detalles sobre las reglas de reescritura, consulte <a href="https://httpd.apache.org/docs/current/mod/mod_rewrite.html" target="_blank" rel="noopener noreferrer">   documentación mod_rewrite de Apache </a> y <a href="https://httpd.apache.org/docs/current/rewrite/" target="_blank" rel="noopener noreferrer">   guía de reescritura de URL de Apache </a>.', '', 'cadena', '');

$_tipsdb['rubyBin'] = new DAttrHelp("Ruta de Ruby", 'Ruta al ejecutable de Ruby. Normalmente es /usr/bin/ruby o /usr/local/bin/ruby, según dónde se haya instalado Ruby.', '', 'Ruta absoluta', '');

$_tipsdb['runOnStartUp'] = new DAttrHelp("Ejecutar al iniciar", 'Especifica si se inicia la aplicacion externa durante el arranque del servidor. Solo se aplica a aplicaciones externas que pueden administrar sus propios procesos hijo y cuyo valor &quot;Instancias&quot; esta establecido en &quot;1&quot;.<br/><br/>Si se habilita, los procesos externos se crearan al iniciar el servidor en lugar de en tiempo de ejecucion.<br/><br/>Al seleccionar &quot;Yes (Detached mode)&quot;, todos los procesos separados pueden reiniciarse a nivel de servidor o de virtual host tocando el archivo &#039;.lsphp_restart.txt&#039; bajo $SERVER_ROOT/admin/tmp/ o el directorio $VH_ROOT/ respectivamente.<br/><br/>Valor predeterminado: Yes (Detached mode)', ' Si el proceso externo configurado tiene una sobrecarga de inicio significativa, como una app Rails, esta opcion debe habilitarse para reducir el tiempo de respuesta de la primera pagina.', 'Seleccionar desde botones de opción', '');

$_tipsdb['runningAs'] = new DAttrHelp("Ejecutando como", 'Especifica el usuario/grupo con el que se ejecuta el proceso del servidor. Esto se establece usando los parametros &quot;--with-user&quot; y &quot;--with-group&quot; al ejecutar el comando configure antes de la instalacion. Para restablecer estos valores, debe volver a ejecutar configure y reinstalar.', ' El servidor no debe ejecutarse como un usuario privilegiado como &quot;root&quot;. Es critico que el servidor este configurado para ejecutarse con una combinacion de usuario/grupo no privilegiada que no tenga acceso de login/shell. Un usuario/grupo <span class=&quot;lst-inline-token lst-inline-token--value&quot;>nobody</span> suele ser una buena opcion.', '', '');

$_tipsdb['scgiContext'] = new DAttrHelp("Contexto SCGI", 'Las aplicaciones SCGI no pueden usarse directamente. Una aplicacion SCGI debe configurarse como manejador de scripts o asignarse a una URL mediante un contexto SCGI. Un contexto SCGI asocia una URI con una aplicacion SCGI.', '', '', '');

$_tipsdb['scgiapp'] = new DAttrHelp("Aplicacion SCGI", 'Especifica el nombre de la aplicacion SCGI. Esta aplicacion debe definirse en la seccion &quot;Aplicaciones externas&quot; a nivel de servidor o virtual host.', '', 'Seleccionar de la lista desplegable', '');

$_tipsdb['servAction'] = new DAttrHelp("Acciones", 'Desde este menú hay cinco acciones disponibles: <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Graceful Restart</span>, <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Toggle Debug Logging</span>, <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Server Log Viewer</span>, <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Real-Time Statistics</span> y <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Compile PHP</span>. <ul><li>&quot;Aplicar cambios/Graceful Restart&quot; reinicia el proceso del servidor de forma graceful sin interrumpir las solicitudes en curso.</li> 	<li>&quot;Alternar registro de depuración&quot; activa o desactiva el registro de depuración.</li> 	<li>&quot;Visor de registros del servidor&quot; permite ver el registro del servidor mediante el visor de registros.</li> 	<li>&quot;Estadísticas en tiempo real&quot; permite ver el estado del servidor en tiempo real.</li> 	<li>Compile PHP permite compilar PHP para LiteSpeed Web Server.</li> </ul>', 'La utilidad de shell <span class=&quot;lst-inline-token lst-inline-token--command&quot;>$SERVER_ROOT/bin/lswsctrl</span> también puede usarse para controlar los procesos del servidor, pero requiere un shell de inicio de sesión.', '', '');

$_tipsdb['servModules'] = new DAttrHelp("Módulos del servidor", 'La configuracion de modulos del servidor define globalmente los datos de configuracion de los modulos. Una vez definidos, los listeners y los hosts virtuales tienen acceso a los modulos y a sus configuraciones.<br/><br/>Todos los modulos que deban procesarse deben registrarse en la configuracion del servidor. La configuracion del servidor tambien define los valores predeterminados de los datos de parametros del modulo. Estos valores pueden heredarse o sobrescribirse en la configuracion del listener y del host virtual.<br/><br/>La prioridad del modulo solo se define a nivel de servidor y la heredan las configuraciones de listener y host virtual.', '', '', '');

$_tipsdb['serverName'] = new DAttrHelp("Nombre del servidor", 'Un nombre unico para este servidor. Si esta vacio, se usara de forma predeterminada el hostname del servidor.', '', '', '');

$_tipsdb['serverPriority'] = new DAttrHelp("Prioridad", 'Especifica la prioridad de los procesos del servidor. El valor va de <span class=&quot;lst-inline-token lst-inline-token--value&quot;>-20</span> a <span class=&quot;lst-inline-token lst-inline-token--value&quot;>20</span>. Un numero menor significa mayor prioridad.', ' Normalmente, una prioridad mayor ofrece un rendimiento web ligeramente mejor en un servidor ocupado. No establezca una prioridad mayor que la de los procesos de base de datos.', 'Numero entero', '');

$_tipsdb['servletContext'] = new DAttrHelp("Contexto Servlet", 'Los servlets pueden importarse individualmente mediante contextos de servlet. Un contexto de servlet solo especifica la URI del servlet y el nombre del motor de servlets. Use esto solo cuando no quiera importar toda la aplicacion web o cuando quiera proteger servlets distintos con realms de autorizacion distintos. Esta URI tiene los mismos requisitos que para un &quot;Contexto de aplicación web Java&quot;.', '', '', '');

$_tipsdb['servletEngine'] = new DAttrHelp("Motor Servlet", 'Especifica el nombre del motor servlet que sirve esta aplicacion web. Los motores servlet deben definirse en la seccion &quot;Aplicaciones externas&quot; a nivel de servidor o virtual host.', '', 'Seleccionar de la lista desplegable', '');

$_tipsdb['setUidMode'] = new DAttrHelp("Modo Set UID de app externa", 'Especifica como se establece el ID de usuario para un proceso de aplicacion externa. Hay tres opciones disponibles: <ul><li><span class=&quot;lst-inline-token lst-inline-token--value&quot;>Server UID</span>: establece el ID de usuario/grupo de los procesos de aplicacion externa igual al ID de usuario/grupo del servidor.</li>     <li><span class=&quot;lst-inline-token lst-inline-token--value&quot;>CGI File UID</span>: establece el ID de usuario/grupo de los procesos CGI externos segun el ID de usuario/grupo del ejecutable. Esta opcion solo se aplica a CGI, no a FastCGI ni LSPHP.</li>     <li><span class=&quot;lst-inline-token lst-inline-token--value&quot;>Doc Root UID</span>: establece el ID de usuario/grupo de los procesos de aplicacion externa segun el ID de usuario/grupo del document root del virtual host actual.</li> </ul><br/><br/>Valor predeterminado: <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Server UID</span>', ' En entornos de hosting compartido, se recomienda usar los modos <span class=&quot;lst-inline-token lst-inline-token--value&quot;>CGI File UID</span> o <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Doc Root UID</span> para evitar que los archivos propiedad de un virtual host sean accedidos por scripts de aplicacion externa de otro virtual host.', 'Seleccionar de la lista desplegable', '');

$_tipsdb['shHandlerName'] = new DAttrHelp("Nombre del manejador", 'Especifica el nombre de la aplicación externa que procesa los archivos de script cuando el tipo de manejador es LSAPI app, Web Server (Proxy), Fast CGI, SCGI, Load balancer, Servlet Engine o uWSGI.', '', 'Seleccionar de la lista desplegable', '');

$_tipsdb['shType'] = new DAttrHelp("Tipo de manejador", 'Especifica el tipo de aplicación externa que procesa estos archivos de script. Los tipos disponibles son: <span class=&quot;lst-inline-token lst-inline-token--value&quot;>LSAPI app</span>, <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Web Server (Proxy)</span>, <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Fast CGI</span>, <span class=&quot;lst-inline-token lst-inline-token--value&quot;>SCGI</span>, <span class=&quot;lst-inline-token lst-inline-token--value&quot;>CGI</span>, <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Load balancer</span>, <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Servlet Engine</span>, <span class=&quot;lst-inline-token lst-inline-token--value&quot;>uWSGI</span> o <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Module Handler</span>. Excepto para los tipos de manejador <span class=&quot;lst-inline-token lst-inline-token--value&quot;>CGI</span> y <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Module Handler</span>, &quot;Nombre del manejador&quot; también debe configurarse con una aplicación externa definida previamente en la sección &quot;Aplicaciones externas&quot;.', '', 'Seleccionar de la lista desplegable', '');

$_tipsdb['shmDefaultDir'] = new DAttrHelp("Directorio SHM predeterminado", 'Cambia el directorio predeterminado de memoria compartida a la ruta especificada. Si el directorio no existe, se creará. Todos los datos SHM se almacenarán en este directorio salvo que se especifique otra cosa.', '', 'ruta', '');

$_tipsdb['showVersionNumber'] = new DAttrHelp("Firma del servidor", 'Especifica si se debe mostrar la firma del servidor y el numero de version en el valor &quot;Server&quot; del encabezado de respuesta. Hay tres opciones: cuando se establece en <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Hide Version</span>, solo se muestra <span class=&quot;lst-inline-token lst-inline-token--value&quot;>LiteSpeed</span>. Cuando se establece en <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Show Version</span>, se muestran LiteSpeed y el numero de version.  Cuando se establece en <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Hide Full Header</span>, no se mostrara todo el encabezado Server en el encabezado de respuesta.', ' Establezcalo en <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Hide Version</span> si no desea exponer el numero de version del servidor.', 'Seleccionar de la lista desplegable', '');

$_tipsdb['sname'] = new DAttrHelp("Nombre - Servidor", 'El nombre único que identifica este servidor. Es el &quot;Nombre del servidor&quot; especificado en la configuración general.', '', '', '');

$_tipsdb['sndBufSize'] = new DAttrHelp("Tamaño de búfer de envío (bytes)", 'El tamaño del búfer de envío de cada socket TCP. <span class=&quot;lst-inline-token lst-inline-token--value&quot;>512K</span> es el tamaño máximo permitido del búfer.', ' Se recomienda dejar este valor como &quot;Not Set&quot; o establecerlo en 0 para usar el tamaño de búfer predeterminado del sistema operativo.<br/> Si su sitio web sirve archivos estáticos grandes, aumente el tamaño del búfer de envío para mejorar el rendimiento.<br/> Establecerlo en un valor menor reducirá el rendimiento y el uso de memoria por socket, permitiendo al servidor tener más sockets concurrentes cuando la memoria sea un cuello de botella.', 'Número entero', '');

$_tipsdb['softLimit'] = new DAttrHelp("Límite flexible de conexiones", 'Especifica el límite flexible de conexiones concurrentes permitidas desde una IP. Este límite flexible se puede superar temporalmente durante &quot;Periodo de gracia (segs)&quot;, siempre que el número esté por debajo de &quot;Límite estricto de conexiones&quot;, pero las conexiones Keep-Alive se cerrarán lo antes posible hasta que el número de conexiones sea inferior al límite. Si el número de conexiones sigue por encima del límite después de &quot;Periodo de gracia (segs)&quot;, esa IP será bloqueada durante &quot;Periodo de bloqueo (segs)&quot;.<br/><br/>Por ejemplo, si una página contiene muchos gráficos pequeños, el navegador puede intentar abrir muchas conexiones al mismo tiempo, especialmente con clientes HTTP/1.0. Conviene permitir esas conexiones durante un periodo corto.<br/><br/>Los clientes HTTP/1.1 también pueden abrir varias conexiones para acelerar las descargas, y SSL requiere conexiones separadas de las no SSL. Asegúrese de ajustar el límite correctamente para no afectar negativamente al servicio normal. El límite recomendado está entre <span class=&quot;lst-inline-token lst-inline-token--value&quot;>5</span> y <span class=&quot;lst-inline-token lst-inline-token--value&quot;>10</span>.', ' Un número menor permitirá atender a más clientes distintos.<br/> Las IP o subredes de confianza no se ven afectadas.<br/> Establezca un valor alto cuando realice pruebas de benchmark con un gran número de máquinas cliente concurrentes.', 'Número entero', '');

$_tipsdb['sslCert'] = new DAttrHelp("Clave privada y certificado SSL", 'Cada listener SSL requiere una clave privada SSL y un certificado SSL emparejados. Varios listeners SSL pueden compartir la misma clave y certificado.<br/><br/>Puede generar claves privadas SSL usted mismo usando un paquete de software SSL, como OpenSSL. Los certificados SSL tambien pueden comprarse a una entidad emisora de certificados autorizada como VeriSign o Thawte. Tambien puede firmar el certificado usted mismo. Los certificados autofirmados no seran considerados confiables por los navegadores web y no deben usarse en sitios web publicos que contengan datos criticos. Sin embargo, un certificado autofirmado es suficiente para uso interno, por ejemplo para cifrar el trafico hacia la consola WebAdmin de LiteSpeed Web Server.', '', '', '');

$_tipsdb['sslDefaultCiphers'] = new DAttrHelp("Suite de cifrado predeterminada", 'Suite de cifrado predeterminada para certificados SSL.<br/><br/>Valor predeterminado: predeterminado interno del servidor (basado en las mejores prácticas actuales)', '', 'Cadena de especificaciones de cifrado separadas por dos puntos.', '');

$_tipsdb['sslEnableMultiCerts'] = new DAttrHelp("Habilitar múltiples certificados SSL", 'Permite que listeners/vhosts establezcan varios certificados SSL. Si se habilitan varios certificados, se espera que los certificados/claves sigan un esquema de nombres. Si el certificado se llama server.crt, otros nombres posibles son server.crt.rsa, server.crt.dsa, server.crt.ecc. Si está en &quot;Not Set&quot;, el valor predeterminado es &quot;No&quot;.', '', 'Seleccionar desde botones de opción', '');

$_tipsdb['sslOCSP'] = new DAttrHelp("OCSP Stapling", 'Online Certificate Status Protocol (OCSP) es un metodo mas eficiente para comprobar si un certificado digital es valido. Funciona comunicandose con otro servidor, el OCSP responder, para obtener la verificacion de que el certificado es valido en lugar de comprobar listas de revocacion de certificados (CRL).<br/><br/>OCSP stapling es una mejora adicional de este protocolo, que permite al servidor consultar al OCSP responder a intervalos regulares en lugar de hacerlo cada vez que se solicita un certificado. Consulte la pagina de Wikipedia sobre <a href="http://en.wikipedia.org/wiki/OCSP_Stapling" target="_blank" rel="noopener noreferrer">OCSP</a> para mas detalles.', '', '', '');

$_tipsdb['sslOcspProxy'] = new DAttrHelp("Proxy OCSP", 'Dirección de socket usada como dirección del servidor proxy para verificación OCSP. Deje este ajuste sin establecer si no usa un proxy.<br/><br/>Valor predeterminado: <span class=&quot;lst-inline-token lst-inline-token--value&quot;>not set</span>', '', 'Dirección de socket', '');

$_tipsdb['sslProtocol'] = new DAttrHelp("Version de protocolo", 'Seleccion de protocolos SSL aceptados por el listener.<br/><br/>Las opciones incluyen: <span class=&quot;lst-inline-token lst-inline-token--value&quot;>SSL v3.0</span>, <span class=&quot;lst-inline-token lst-inline-token--value&quot;>TLS v1.0</span>, <span class=&quot;lst-inline-token lst-inline-token--value&quot;>TLS v1.1</span>, <span class=&quot;lst-inline-token lst-inline-token--value&quot;>TLS v1.2</span>, <span class=&quot;lst-inline-token lst-inline-token--value&quot;>TLS v1.3</span>.', '', 'Seleccionar mediante casillas', '');

$_tipsdb['sslSessionCache'] = new DAttrHelp("Habilitar caché de sesión", 'Habilita la caché de ID de sesión usando el ajuste predeterminado de OpenSSL. El ajuste de nivel de servidor debe estar en &quot;Yes&quot; para que el ajuste de Virtual Host tenga efecto.<br/><br/>Valores predeterminados:<br/><b>Nivel de servidor:</b> Yes<br/><b>Nivel de VH:</b> Yes', '', 'Seleccionar desde botones de opción', '');

$_tipsdb['sslSessionCacheSize'] = new DAttrHelp("Tamaño de caché de sesión (bytes)", 'Establece el número máximo de IDs de sesión SSL que se almacenarán en la caché. El valor predeterminado es 1,000,000.', '', 'Número entero', '');

$_tipsdb['sslSessionCacheTimeout'] = new DAttrHelp("Timeout de caché de sesión (seg)", 'Este valor determina durante cuánto tiempo será válido un ID de sesión dentro de la caché antes de requerir una renegociación. El valor predeterminado es 3,600.', '', 'Número entero', '');

$_tipsdb['sslSessionTicketKeyFile'] = new DAttrHelp("Archivo de clave de ticket de sesión SSL", 'Permite que un administrador cree/mantenga la clave de ticket SSL. El archivo debe tener 48 bytes de longitud. Si esta opción se deja vacía, el balanceador de carga generará y rotará su propio conjunto de claves.<br/><br/>IMPORTANTE: Para mantener forward secrecy, se recomienda encarecidamente cambiar la clave cada <b>SSL Session Ticket Lifetime</b> segundos. Si esto no se puede hacer, se recomienda dejar este campo vacío.', '', 'Ruta', '');

$_tipsdb['sslSessionTicketLifetime'] = new DAttrHelp("Vida útil del ticket de sesión SSL (seg)", 'Este valor determina durante cuánto tiempo será válido un ticket de sesión antes de requerir una renegociación. El valor predeterminado es 3,600.', '', 'Número entero', '');

$_tipsdb['sslSessionTickets'] = new DAttrHelp("Habilitar tickets de sesión", 'Habilita tickets de sesión usando el ajuste predeterminado de tickets de sesión de OpenSSL. El ajuste de nivel de servidor debe estar en &quot;Yes&quot; para que el ajuste de Virtual Host tenga efecto.<br/><br/>Valores predeterminados:<br/><b>Nivel de servidor:</b> Yes<br/><b>Nivel de VH:</b> Yes', '', 'Seleccionar desde botones de opción', '');

$_tipsdb['sslStrictSni'] = new DAttrHelp("Certificado SNI estricto", 'Especifica si se debe requerir estrictamente una configuración de certificado dedicada para virtual host. Cuando está habilitado, las conexiones SSL a virtual hosts sin una configuración de certificado dedicada fallarán en lugar de usar un certificado catch-all predeterminado.<br/><br/>Valor predeterminado: <span class=&quot;lst-inline-token lst-inline-token--value&quot;>No</span>', '', 'Seleccionar desde botones de opción', '');

$_tipsdb['sslStrongDhKey'] = new DAttrHelp("Clave DH fuerte SSL", 'Especifica si se deben usar claves DH de 2048 o 1024 bits para handshakes SSL. Si se establece en &quot;Yes&quot;, se usarán claves DH de 2048 bits para claves y certificados SSL de 2048 bits. En otras situaciones se seguirán usando claves DH de 1024 bits. El valor predeterminado es &quot;Yes&quot;.<br/><br/>Versiones anteriores de Java no admiten tamaños de clave DH superiores a 1024 bits. Si se requiere compatibilidad con clientes Java, esto debe establecerse en &quot;No&quot;.', '', 'radio', '');

$_tipsdb['statDir'] = new DAttrHelp("Directorio de salida de estadisticas", 'El directorio donde se escribira el archivo de informe de Real-Time Stats. El directorio predeterminado es <b>/tmp/lshttpd/</b> .', 'Durante la operacion del servidor, el archivo .rtreport se escribira cada segundo. Para evitar escrituras de disco innecesarias, establezca esto en un RAM Disk.<br/>El archivo .rtreport puede usarse con software de monitoreo de terceros para supervisar la salud del servidor.', 'Ruta absoluta', '');

$_tipsdb['staticReqPerSec'] = new DAttrHelp("Solicitudes estáticas/segundo", 'Especifica el número máximo de solicitudes de contenido estático procedentes de una sola dirección IP que se pueden procesar en un segundo, sin importar cuántas conexiones estén establecidas.<br/><br/>Cuando se alcanza este límite, todas las solicitudes futuras se retienen hasta el siguiente segundo. Los límites de solicitudes para contenido generado dinámicamente son independientes de este límite. Los límites de solicitudes por cliente se pueden establecer a nivel de servidor o de virtual host. Los ajustes de nivel de virtual host sobrescriben los ajustes de nivel de servidor.', ' Las IP o subredes de confianza no se ven afectadas.', 'Número entero', '');

$_tipsdb['statuscode'] = new DAttrHelp("Codigo de estado", 'Especifica el codigo de estado de respuesta de la redireccion externa. Si el codigo de estado esta entre 300 y 399, puede especificarse &quot;URI de destino&quot;.', '', 'Seleccionar de la lista desplegable', '');

$_tipsdb['suexecGroup'] = new DAttrHelp("Grupo suEXEC", 'En el nivel de contexto actual, ejecuta como este grupo. Debe establecerse <b>suEXEC User</b> en el nivel de virtual host o <b>Run As User</b> en el nivel de Aplicacion externa para que <b>suEXEC Group</b> tenga efecto.<br/><br/>Esta configuracion puede reemplazarse en el nivel de Aplicacion externa mediante la opcion <b>Run As Group</b>.<br/><br/>Valor predeterminado: valor de la opcion <b>suExec User</b>', '', 'Nombre de grupo o uid valido', '');

$_tipsdb['suexecUser'] = new DAttrHelp("Usuario suEXEC", 'En el nivel de contexto actual, ejecuta como este usuario. Si se establece, este valor reemplazara la configuracion <b>ExtApp Set UID Mode</b> de nivel de virtual host.<br/><br/>Esta configuracion puede reemplazarse en el nivel de Aplicacion externa mediante la opcion <b>Run As User</b>.<br/><br/>Valor predeterminado: No establecido', '', 'Nombre de usuario o uid valido.', '');

$_tipsdb['suffix'] = new DAttrHelp("Sufijos", 'Especifica los sufijos de archivo de script que gestionará este manejador de scripts. Los sufijos deben ser únicos.', 'El servidor agregará automáticamente un tipo MIME especial (&quot;application/x-httpd-[suffix]&quot;) para el primer sufijo de la lista. Por ejemplo, se agregará el tipo MIME &quot;application/x-httpd-php53&quot; para el sufijo &quot;php53&quot;. Los sufijos posteriores deben configurarse en los ajustes de &quot;Configuracion MIME&quot;.<br/>Aunque se enumeran sufijos en este campo, los manejadores de scripts usan tipos MIME, no sufijos, para decidir qué scripts gestionar.<br/> Especifique solo los sufijos que realmente necesite.', 'Lista separada por comas; no se permite el carácter de punto &quot;.&quot;.', '');

$_tipsdb['swappingDir'] = new DAttrHelp("Directorio de swapping", 'Especifica el directorio donde deben colocarse los archivos de swapping. Cuando el servidor se inicia en modo chroot, este directorio es relativo al nuevo directorio raiz; de lo contrario, es relativo al directorio raiz real.<br/><br/>El servidor usa su propia memoria virtual para reducir el uso de memoria del sistema. La memoria virtual y el disk swapping se usan para almacenar cuerpos de solicitud grandes y respuestas generadas dinamicamente. El directorio de swapping debe colocarse en un disco con espacio suficiente.<br/><br/>Valor predeterminado: /tmp/lshttpd/swap', ' Coloque el directorio de swapping en un disco separado o aumente el tamano del buffer de E/S de memoria para eliminar el swapping.', 'Ruta absoluta', '');

$_tipsdb['templateFile'] = new DAttrHelp("Archivo de plantilla", 'Especifica la ruta al archivo de configuración de esta plantilla. El archivo debe ubicarse dentro de $SERVER_ROOT/conf/templates/ con un nombre de archivo &quot;.conf&quot;. Si el archivo indicado no existe, después de intentar guardar la plantilla aparecerá un error con el enlace &quot;CLICK TO CREATE&quot;. Este enlace generará un archivo de plantilla nuevo y vacío. Al eliminar la plantilla, la entrada se quitará de sus configuraciones, pero el archivo real de configuración de la plantilla no se eliminará.', '', 'ruta', '');

$_tipsdb['templateName'] = new DAttrHelp("Nombre de plantilla", 'Nombre único de la plantilla.', '', '', '');

$_tipsdb['templateVHAliases'] = new DAttrHelp("Alias de dominio", 'Especifica nombres alternativos para el virtual host. Todos los hostnames y direcciones IP posibles deben agregarse a esta lista. Se permiten los caracteres comodín <span class=&quot;lst-inline-token lst-inline-token--value&quot;>*</span> y <span class=&quot;lst-inline-token lst-inline-token--value&quot;>?</span> en el nombre. Agregue <span class=&quot;lst-inline-token lst-inline-token--value&quot;>:<port></span> para sitios web que no estén en el puerto 80.<br/><br/>Los aliases se usarán en las siguientes situaciones: <ol>   <li>Para coincidir con el hostname del encabezado Host al procesar una solicitud.</li>   <li>Para rellenar configuraciones de nombre de dominio/alias para complementos como FrontPage o AWstats.</li>   <li>Para configurar mapeos de listener a virtual host basados en la plantilla de virtual host.</li> </ol>', '', 'Lista separada por comas de nombres de dominio.', '');

$_tipsdb['templateVHConfigFile'] = new DAttrHelp("Archivo de configuración de VHost instanciado", 'Especifica la ubicación del archivo de configuración generado al instanciar un virtual host miembro. La variable <span class=&quot;lst-inline-token lst-inline-token--value&quot;>$VH_NAME</span> debe aparecer en la ruta para que cada virtual host tenga su propio archivo. Debe ubicarse bajo $SERVER_ROOT/conf/vhosts/. Este archivo de configuración solo se creará después de sacar un vhost miembro de la plantilla mediante instanciación.', 'Se recomienda $VH_NAME/vhconf.conf para facilitar la administración.', 'Cadena con la variable $VH_NAME y sufijo .conf', '');

$_tipsdb['templateVHDocRoot'] = new DAttrHelp("Raíz de documentos", 'Especifica la ruta única para la raíz de documentos de cada virtual host miembro. La variable <span class=&quot;lst-inline-token lst-inline-token--value&quot;>$VH_NAME</span> o <span class=&quot;lst-inline-token lst-inline-token--value&quot;>$VH_ROOT</span> debe aparecer en la ruta para que cada virtual host miembro tenga su propia raíz de documentos.', '', 'ruta con la variable $VH_NAME o $VH_ROOT', '$VH_ROOT/public_html/ o $SERVER_ROOT/$VH_NAME/public_html.');

$_tipsdb['templateVHDomain'] = new DAttrHelp("Nombre de dominio", 'Especifica el nombre de dominio principal de este virtual host miembro. Si se deja en blanco, se usará el nombre del virtual host. Debe ser un nombre de dominio completo, aunque también puede usar una dirección IP. Se recomienda agregar <span class=&quot;lst-inline-token lst-inline-token--value&quot;>:<port></span> para sitios web que no estén en el puerto 80. En configuraciones que contienen nombres de dominio, este dominio puede referenciarse con la variable <span class=&quot;lst-inline-token lst-inline-token--value&quot;>$VH_DOMAIN</span>.<br/><br/>Este nombre de dominio se usará en las siguientes situaciones: <ol>   <li>Para coincidir con el hostname del encabezado Host al procesar una solicitud.</li>   <li>Para rellenar configuraciones de nombres de dominio para complementos como FrontPage o AWstats.</li>  <li>Para configurar mapeos de listener a virtual host basados en la plantilla de virtual host.</li> </ol>', '', 'nombre de dominio', '');

$_tipsdb['templateVHName'] = new DAttrHelp("Nombre del virtual host", 'Nombre único para este virtual host. Este nombre debe ser único entre todos los virtual hosts miembros de plantilla y los virtual hosts independientes. Dentro de una configuración de ruta de directorio, este nombre puede referenciarse con la variable <span class=&quot;lst-inline-token lst-inline-token--value&quot;>$VH_NAME</span>.<br/><br/>Si también se configura un virtual host independiente con el mismo nombre, se ignorará la configuración del virtual host miembro.', '', '', '');

$_tipsdb['templateVHRoot'] = new DAttrHelp("Raíz predeterminada del virtual host", 'Especifica el directorio raíz predeterminado para los virtual hosts miembros que usan esta plantilla. La variable <span class=&quot;lst-inline-token lst-inline-token--value&quot;>$VH_NAME</span> debe aparecer en la ruta. Esto permite asignar automáticamente a cada miembro de la plantilla un directorio raíz separado basado en su nombre.', '', 'ruta', '');

$_tipsdb['throttleBlockWindow'] = new DAttrHelp("Duracion inicial del bloqueo (s)", 'Especifica el tiempo inicial, en segundos, durante el que un cliente queda bloqueado despues de alcanzar el maximo de fallos de inicio de sesion permitidos. Valor predeterminado si no se define: 900 segundos.', 'Use una duracion lo bastante larga para desalentar ataques repetidos sin causar un tiempo de bloqueo excesivo para usuarios validos.', 'Número entero', '');

$_tipsdb['throttleEnabled'] = new DAttrHelp("Habilitar limitacion de inicio de sesion", 'Habilita la limitacion de inicios de sesion para la consola WebAdmin. Cuando esta habilitada, los intentos fallidos repetidos se registran y se bloquean temporalmente para reducir los ataques de fuerza bruta contra contrasenas. Si solo esta opcion esta habilitada y los demas ajustes de limitacion quedan sin definir, se usan valores predeterminados integrados.', ' Mantenga esta opcion habilitada en produccion salvo que este diagnosticando problemas de inicio de sesion. Cuando se habilita sin valores personalizados, los valores predeterminados son 5 fallos, 900 segundos de bloqueo inicial y 14400 segundos de bloqueo maximo.', 'Seleccionar desde botones de opción', '');

$_tipsdb['throttleMaxBackoff'] = new DAttrHelp("Duracion maxima del bloqueo (s)", 'Especifica la duracion maxima del bloqueo, en segundos, cuando continuan los intentos fallidos de inicio de sesion y aumenta el retroceso de la limitacion. Valor predeterminado si no se define: 14400 segundos.', 'Defina un limite superior lo bastante fuerte para ralentizar ataques automatizados y que aun permita recuperarse en un tiempo razonable.', 'Número entero', '');

$_tipsdb['throttleMaxFailures'] = new DAttrHelp("Maximo de fallos de inicio de sesion", 'Especifica cuantos intentos de inicio de sesion fallidos consecutivos se permiten antes de bloquear al cliente. Valor predeterminado si no se define: 5.', ' Los valores mas bajos aumentan la proteccion, pero pueden bloquear antes a usuarios legitimos.', 'Número entero', '');

$_tipsdb['toggleDebugLog'] = new DAttrHelp("Alternar registro de depuración", 'Toggle Debug Logging alterna el valor de &quot;Nivel de depuración&quot; entre <span class=&quot;lst-inline-token lst-inline-token--value&quot;>NONE</span> y <span class=&quot;lst-inline-token lst-inline-token--value&quot;>HIGH</span>. Como el registro de depuración afecta al rendimiento y puede llenar rápidamente el disco duro, &quot;Nivel de depuración&quot; normalmente debe establecerse en <span class=&quot;lst-inline-token lst-inline-token--value&quot;>NONE</span> en un servidor de producción. Esta función puede usarse para activar o desactivar rápidamente el registro de depuración al diagnosticar un problema en un servidor de producción. El registro de depuración activado o desactivado de esta forma no cambia nada en la configuración del servidor.', '&quot;Alternar registro de depuración&quot; solo funcionará si &quot;Nivel de registro&quot; está configurado como <span class=&quot;lst-inline-token lst-inline-token--value&quot;>DEBUG</span>.<br/> Importante: el registro de depuración incluye información detallada de cada solicitud y respuesta. El registro de depuración activo degradará gravemente el rendimiento del servicio y puede saturar el espacio en disco en muy poco tiempo. Esta función debe usarse solo durante un periodo breve al diagnosticar problemas del servidor.', '', '');

$_tipsdb['totalInMemCacheSize'] = new DAttrHelp("Tamaño total de caché de archivos pequeños (bytes)", 'Especifica la memoria total que se puede asignar a la caché de búfer para almacenar/servir archivos estáticos pequeños.', '', 'Número entero', '');

$_tipsdb['totalMMapCacheSize'] = new DAttrHelp("Tamaño total de caché MMAP (bytes)", 'Especifica la memoria total que se puede asignar para la caché mapeada en memoria a fin de almacenar/servir archivos estáticos de tamaño medio.', '', 'Número entero', '');

$_tipsdb['tp_vhFileName'] = new DAttrHelp("Nombre de archivo usado en la plantilla", 'Especifica una ruta de archivo usada por ajustes de virtual host basados en plantilla. La variable <span class=&quot;lst-inline-token lst-inline-token--value&quot;>$VH_NAME</span> o <span class=&quot;lst-inline-token lst-inline-token--value&quot;>$VH_ROOT</span> debe aparecer en la ruta para que cada virtual host miembro resuelva a su propio archivo. Este ajuste es para archivos pertenecientes a la plantilla, como archivos de registro, no para el archivo de configuración de virtual host instanciado.', '', 'ruta con la variable $VH_NAME o $VH_ROOT', '');

$_tipsdb['umask'] = new DAttrHelp("umask", 'Establece la umask predeterminada para procesos CGI. Consulte <span class=&quot;lst-inline-token lst-inline-token--command&quot;> man 2 umask </span> para más detalles. También sirve como valor predeterminado para &quot;umask&quot; de aplicaciones externas.', '', 'valor dentro del rango válido [000]-[777].', '');

$_tipsdb['uploadPassByPath'] = new DAttrHelp("Pasar datos de carga por ruta de archivo", 'Especifica si se deben pasar o no los datos de archivo cargado por ruta. Si esta habilitado, la ruta del archivo junto con otra informacion se envia al backend handler en lugar del archivo mismo durante la carga. Esto ahorra recursos de CPU y tiempo de transferencia de archivos, pero requiere algunas actualizaciones en el backend para implementarlo. Si esta deshabilitado, el contenido del archivo se transferira al backend handler; el cuerpo de la solicitud aun se analiza en archivos.', ' Habilite esto para acelerar el procesamiento de carga de archivos si la compatibilidad hacia atras no es un problema.', 'Seleccionar desde botones de opción', '');

$_tipsdb['uploadTmpDir'] = new DAttrHelp("Ruta de archivo temporal", 'Directorio temporal donde se almacenarán los archivos que se cargan al servidor mientras trabaja el analizador del cuerpo de la solicitud. El valor predeterminado es <span class=&quot;lst-inline-token lst-inline-token--value&quot;>/tmp/lshttpd/</span>.', '', 'Ruta absoluta o ruta que empiece por $SERVER_ROOT (para niveles de servidor y VHost) o $VH_ROOT (para niveles de VHost).', '');

$_tipsdb['uploadTmpFilePermission'] = new DAttrHelp("Permiso de archivo temporal", 'Determina los permisos de archivo usados para los archivos almacenados en el directorio temporal. El ajuste de nivel de servidor es global y puede sobrescribirse a nivel de VHost.', '', 'Número octal de 3 dígitos. El valor predeterminado es 666.', '');

$_tipsdb['uri'] = new DAttrHelp("URI", 'Especifica la URI para este contexto. La URI debe empezar con &quot;/&quot;. Si una URI termina con &quot;/&quot;, este contexto incluira todas las sub-URI bajo esta URI.', '', 'URI', '');

$_tipsdb['useAIO'] = new DAttrHelp("Usar E/S asíncrona (AIO)", 'Especifica si se debe usar I/O asíncrona para servir archivos estáticos, junto con la implementación de AIO que se usará. Las opciones <span class=&quot;lst-inline-token lst-inline-token--value&quot;>LINUX AIO</span> e <span class=&quot;lst-inline-token lst-inline-token--value&quot;>io_uring</span> solo están disponibles en máquinas Linux.<br/><br/>Valor predeterminado: <span class=&quot;lst-inline-token lst-inline-token--value&quot;>No</span>', ' AIO puede ayudar a mejorar el rendimiento en servidores con una espera de I/O alta.<br/> Cuando se selecciona <span class=&quot;lst-inline-token lst-inline-token--value&quot;>io_uring</span> pero no es compatible con la máquina actual, se usará <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Linux AIO</span> en su lugar.', 'Seleccionar de la lista desplegable', '');

$_tipsdb['useIpInProxyHeader'] = new DAttrHelp("Usar IP de cliente en el encabezado", 'Especifica si se debe usar la primera direccion IP mas valida listada en el encabezado de solicitud HTTP &quot;X-Forwarded-For&quot; para todas las funciones relacionadas con direccion IP, incluida la limitacion de conexiones/ancho de banda, control de acceso y geolocalizacion IP.<br/><br/>Esta funcion es util si su servidor web esta detras de un load balancer o un servidor proxy. Si selecciona <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Trusted IP Only</span>, la IP de X-Forwarded-For se usara solo cuando la solicitud provenga de IPs confiables definidas en &quot;Lista permitida&quot; a nivel de servidor.<br/><br/><span class=&quot;lst-inline-token lst-inline-token--value&quot;>Keep Header from Trusted IP</span> es igual a <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Trusted IP Only</span>, pero el encabezado X-Forwarded-For usado para el backend no se modificara para incluir la direccion del peer que se conecta.<br/><br/><span class=&quot;lst-inline-token lst-inline-token--value&quot;>Use Last IP (for AWS ELB)</span> usara la ultima direccion IP en la lista &quot;X-Forwarded-For&quot;. Seleccione esta opcion si usa AWS Elastic Load Balancer o espera que la IP real se agregue al final de la lista &quot;X-Forwarded-For&quot;.', '', 'Seleccionar de la lista desplegable', '');

$_tipsdb['useSendfile'] = new DAttrHelp("Usar sendfile()", 'Especifica si se debe usar la llamada de sistema sendfile() para servir archivos estáticos. Los archivos estáticos se pueden servir de cuatro formas: caché de búfer en memoria, caché mapeada en memoria, lectura/escritura normal y sendfile(). Los archivos menores que &quot;Tamaño máx. de archivo pequeño en caché (bytes)&quot; se sirven desde la caché de búfer en memoria. Los archivos mayores que &quot;Tamaño máx. de archivo pequeño en caché (bytes)&quot; pero menores que &quot;Tamaño máx. de archivo MMAP (bytes)&quot; se servirán desde la caché mapeada en memoria. Los archivos mayores que &quot;Tamaño máx. de archivo MMAP (bytes)&quot; se servirán mediante lectura/escritura normal o sendfile(). Sendfile() es una llamada de sistema de &quot;cero copias&quot; que puede reducir mucho el uso de CPU al servir archivos estáticos muy grandes. Sendfile() requiere un controlador de kernel de tarjeta de red optimizado y, por lo tanto, puede no ser adecuado para algunos adaptadores de red de proveedores pequeños.', '', 'Seleccionar desde botones de opción', '');

$_tipsdb['userDBCacheTimeout'] = new DAttrHelp("Tiempo de espera de cache de DB de usuarios (seg)", 'Especifica con que frecuencia se comprobara si la base de datos de usuarios backend tiene cambios. Cada entrada de la cache tiene una marca de tiempo. Cuando los datos en cache son mas antiguos que el timeout especificado, se comprobara si la base de datos backend tiene cambios. Si no hay cambios, la marca de tiempo se reiniciara a la hora actual; de lo contrario, se cargaran los datos nuevos. La recarga del servidor y el reinicio graceful limpiaran la cache inmediatamente.', ' Si la base de datos backend no cambia con mucha frecuencia, establezca un timeout mas largo para mejorar el rendimiento.', 'Número entero', '');

$_tipsdb['userDBLocation'] = new DAttrHelp("Ubicacion de DB de usuarios", 'Especifica la ubicacion de la base de datos de usuarios. Se recomienda almacenar la base de datos bajo el directorio $SERVER_ROOT/conf/vhosts/$VH_NAME/.<br/><br/>Para el tipo de DB <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Password File</span>, es la ruta al archivo plano que contiene definiciones de usuario/contrasena. Puede editar este archivo mediante la consola WebAdmin haciendo clic en el nombre de archivo.<br/><br/>Cada linea del archivo de usuarios contiene un nombre de usuario seguido de dos puntos, seguido de una contrasena cifrada con crypt(), opcionalmente seguida de dos puntos y los nombres de grupo a los que pertenece el usuario. Los nombres de grupo se delimitan con comas. Si la informacion de grupo se especifica en la base de datos de usuarios, no se comprobara la base de datos de grupos.<br/><br/>Ejemplo:<blockquote><code>john:HZ.U8kgjnMOHo:admin,user</code></blockquote>', '', 'Ruta al archivo de DB de usuarios.', '');

$_tipsdb['userDBMaxCacheSize'] = new DAttrHelp("Tamano maximo de cache de DB de usuarios", 'Especifica el tamano maximo de cache de la base de datos de usuarios. Los datos de autenticacion de usuarios accedidos recientemente se almacenaran en cache en memoria para proporcionar el maximo rendimiento.', ' Como una cache mas grande consumira mas memoria, un valor mayor puede o no proporcionar mejor rendimiento. Establezcalo en un tamano adecuado segun el tamano de su base de datos de usuarios y el uso del sitio.', 'Número entero', '');

$_tipsdb['uwsgiContext'] = new DAttrHelp("Contexto uWSGI", 'Las aplicaciones uWSGI no pueden usarse directamente. Una aplicacion uWSGI debe configurarse como manejador de scripts o asignarse a una URL mediante un contexto uWSGI. Un contexto uWSGI asocia una URI con una aplicacion uWSGI.', '', '', '');

$_tipsdb['uwsgiapp'] = new DAttrHelp("Aplicacion uWSGI", 'Especifica el nombre de la aplicacion uWSGI. Esta aplicacion debe definirse en la seccion &quot;Aplicaciones externas&quot; a nivel de servidor o virtual host.', '', 'Seleccionar de la lista desplegable', '');

$_tipsdb['vaction'] = new DAttrHelp("Acciones - Host virtual", 'Este campo muestra botones para desactivar, activar o reiniciar el host virtual. Las acciones realizadas en un host virtual no afectan al resto del servidor web.', 'Es buena idea desactivar temporalmente un host virtual al actualizar su contenido.', '', '');

$_tipsdb['vdisable'] = new DAttrHelp("Desactivar", 'La acción <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Disable</span> detiene un host virtual en ejecución. No se aceptarán nuevas solicitudes, pero las solicitudes en proceso terminarán normalmente.', '', '', '');

$_tipsdb['venable'] = new DAttrHelp("Activar", 'La acción <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Enable</span> inicia un host virtual detenido. Esto permite aceptar nuevas solicitudes.', '', '', '');

$_tipsdb['verifyDepth'] = new DAttrHelp("Profundidad de verificacion", ' Especifica que tan profundamente debe verificarse un certificado antes de determinar que el cliente no tiene un certificado valido. El valor predeterminado es &quot;1&quot;.', '', 'Seleccionar de la lista desplegable', '');

$_tipsdb['vhEnableBr'] = new DAttrHelp("Habilitar compresión Brotli", 'Especifica si se habilita la compresión Brotli para este virtual host. Este ajuste solo es efectivo cuando &quot;Nivel de compresión Brotli (archivo estático)&quot; tiene un valor distinto de cero a nivel de servidor.', '', 'Seleccionar desde botones de opción', '');

$_tipsdb['vhEnableGzip'] = new DAttrHelp("Habilitar compresión", 'Especifica si se habilita la compresión GZIP para este virtual host. Este ajuste solo es efectivo cuando &quot;Habilitar compresión&quot; está configurado como <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Yes</span> a nivel de servidor.', '', 'Seleccionar desde botones de opción', '');

$_tipsdb['vhEnableQuic'] = new DAttrHelp("Habilitar HTTP3/QUIC", 'Habilita el protocolo de red HTTP3/QUIC para este virtual host. Para que este ajuste tenga efecto, &quot;Habilitar HTTP3/QUIC&quot; y &quot;Abrir puerto HTTP3/QUIC (UDP)&quot; también deben establecerse en <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Yes</span> a nivel de servidor y listener respectivamente. El valor predeterminado es <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Yes</span>.', 'Cuando este ajuste se establece en <span class=&quot;lst-inline-token lst-inline-token--value&quot;>No</span>, el anuncio HTTP3/QUIC ya no se enviará. Si un navegador aún contiene información HTTP3/QUIC en caché y HTTP3/QUIC sigue habilitado a nivel de servidor y listener, se seguirá usando una conexión HTTP3/QUIC hasta que esta información deje de estar en caché o se encuentre un error de protocolo HTTP3/QUIC.', 'Seleccionar desde botones de opción', '');

$_tipsdb['vhMaxKeepAliveReq'] = new DAttrHelp("Maximo de solicitudes Keep-Alive", 'Especifica el maximo de solicitudes que pueden atenderse mediante una conexion keep-alive (persistente). Las conexiones se cerraran cuando se alcance este limite. Puede especificar un limite distinto para cada virtual host. Este numero no puede superar el limite de nivel de servidor &quot;Máx. solicitudes Keep-Alive&quot;.', ' Establezcalo en un valor razonablemente alto. Un valor de &quot;1&quot; o menos deshabilitara las conexiones keep-alive.', 'Número entero', '');

$_tipsdb['vhModuleUrlFilters'] = new DAttrHelp("Filtros URL de módulo", 'Es un lugar centralizado para personalizar la configuracion de modulos para contextos de host virtual. La configuracion de una URI de contexto sobrescribira la configuracion de nivel de host virtual o de servidor.', '', '', '');

$_tipsdb['vhModules'] = new DAttrHelp("Módulos de host virtual", 'Los datos de configuracion de modulos del host virtual se heredan, de forma predeterminada, de la configuracion de modulos del servidor. Los modulos del host virtual se limitan a los hooks de nivel HTTP.', '', '', '');

$_tipsdb['vhName'] = new DAttrHelp("Nombre del virtual host", 'Un nombre unico para un virtual host. Se recomienda usar el nombre de dominio del virtual host como Nombre del virtual host. El Nombre del virtual host puede referenciarse con la variable $VH_NAME.', '', '', '');

$_tipsdb['vhRoot'] = new DAttrHelp("Raiz del virtual host", 'Especifica el directorio raiz del virtual host. Nota: este <b>NO</b> es el document root. Se recomienda colocar todos los archivos relacionados con el virtual host (como archivos de registro, archivos html, scripts CGI, etc.) bajo este directorio. La Raiz del virtual host puede referenciarse con la variable $VH_ROOT.', ' Coloque distintos virtual hosts en distintos discos duros.', 'Una ruta absoluta o una ruta relativa a $SERVER_ROOT.', '');

$_tipsdb['vhaccessLog_fileName'] = new DAttrHelp("Nombre de archivo", 'Nombre de archivo del registro de acceso.', ' Coloque el archivo de registro de acceso en un disco separado.', 'Nombre de archivo que puede ser una ruta absoluta o una ruta relativa a $SERVER_ROOT, $VH_ROOT.', '');

$_tipsdb['vhadminEmails'] = new DAttrHelp("Correo del administrador", 'Especifica las direcciones de correo de los administradores de este virtual host.', '', 'Lista de direcciones de correo separadas por comas', '');

$_tipsdb['vhlog_fileName'] = new DAttrHelp("Nombre de archivo", 'Especifica la ruta del archivo de registro.', ' Coloque el archivo de registro en un disco separado.', 'Nombre de archivo que puede ser una ruta absoluta o una ruta relativa a $SERVER_ROOT, $VH_ROOT.', '');

$_tipsdb['vhlog_logLevel'] = new DAttrHelp("Nivel de registro", 'Especifica el nivel de registro. Los niveles disponibles (de mayor a menor) son <span class=&quot;lst-inline-token lst-inline-token--value&quot;>ERROR</span>, <span class=&quot;lst-inline-token lst-inline-token--value&quot;>WARNING</span>, <span class=&quot;lst-inline-token lst-inline-token--value&quot;>NOTICE</span>, <span class=&quot;lst-inline-token lst-inline-token--value&quot;>INFO</span> y <span class=&quot;lst-inline-token lst-inline-token--value&quot;>DEBUG</span>. Solo se registrarán los mensajes con un nivel mayor o igual que la configuración actual. Si desea establecerlo en <span class=&quot;lst-inline-token lst-inline-token--value&quot;>DEBUG</span>, también debe establecer el nivel de registro del servidor en <span class=&quot;lst-inline-token lst-inline-token--value&quot;>DEBUG</span>. El nivel de depuración se controla exclusivamente a nivel de servidor mediante &quot;Nivel de depuración&quot;.', ' A menos que &quot;Nivel de depuración&quot; esté configurado con un nivel distinto de <span class=&quot;lst-inline-token lst-inline-token--value&quot;>NONE</span>, el nivel de registro <span class=&quot;lst-inline-token lst-inline-token--value&quot;>DEBUG</span> no tiene impacto en el rendimiento y se recomienda.', 'Seleccionar de la lista desplegable', '');

$_tipsdb['viewlog'] = new DAttrHelp("Visor de registros del servidor", 'El visor de registros del servidor es una herramienta cómoda para examinar el registro actual del servidor y buscar errores o problemas. El visor de registros busca en el archivo de registro del servidor por bloques según el nivel de registro especificado.<br/><br/>El tamaño de bloque predeterminado es 20KB. Puede usar los botones <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Begin</span>, <span class=&quot;lst-inline-token lst-inline-token--value&quot;>End</span>, <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Next</span> y <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Prev</span> para navegar por un archivo de registro grande.', 'El tamaño de una página generada dinámicamente está limitado por &quot;Tamaño máx. del cuerpo de respuesta dinámica (bytes)&quot;. Si el bloque es demasiado grande, la página podría truncarse.', '', '');

$_tipsdb['virtualHostMapping'] = new DAttrHelp("Mapeos de hosts virtuales", 'Especifica la relacion entre el listener y los hosts virtuales. Los listeners y los hosts virtuales se asocian mediante nombres de dominio. Una solicitud HTTP se dirigira a un host virtual con un nombre de dominio coincidente. Un listener puede mapearse a varios hosts virtuales para distintos nombres de dominio. Un host virtual tambien puede mapearse desde listeners diferentes. Un listener puede permitir un host virtual catchall con el valor de nombre de dominio &quot;*&quot;. Cuando no haya ningun nombre de dominio coincidente de forma explicita en el mapeo del listener, el listener reenviara la solicitud a ese host virtual catchall.', ' Agregue solo los mapeos necesarios. Si el listener esta mapeado a un solo host virtual, configure solo un mapeo catchall &quot;*&quot;.', '', '');

$_tipsdb['virtualHostName'] = new DAttrHelp("Host virtual", 'Especifica el nombre de un host virtual.', '', 'Seleccionar de la lista desplegable', '');

$_tipsdb['vname'] = new DAttrHelp("Nombre - Host virtual", 'El nombre único que identifica este host virtual. Es el &quot;Nombre del virtual host&quot; especificado al configurar este host virtual.', '', '', '');

$_tipsdb['vreload'] = new DAttrHelp("Reiniciar - Host virtual", 'La acción Restart hace que el servidor web cargue la configuración más reciente de este host virtual. Las solicitudes en proceso terminarán con la configuración antigua. La nueva configuración solo se aplicará a nuevas solicitudes. Todos los cambios en un host virtual pueden aplicarse sobre la marcha de esta manera.', '', '', '');

$_tipsdb['vstatus'] = new DAttrHelp("Estado - Host virtual", 'El estado actual de un host virtual. El estado puede ser: <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Running</span>, <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Stopped</span>, <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Restart Required</span> o <span class=&quot;lst-inline-token lst-inline-token--value&quot;>Running - Removed from Configuration</span>.  <ul>     <li><span class=&quot;lst-inline-token lst-inline-token--value&quot;>Running</span> significa que el host virtual está cargado y en servicio.</li>     <li><span class=&quot;lst-inline-token lst-inline-token--value&quot;>Stopped</span> significa que el host virtual está cargado pero no está en servicio (desactivado).</li>     <li><span class=&quot;lst-inline-token lst-inline-token--value&quot;> Restart Required</span> significa que es un host virtual recién agregado y que el servidor aún no ha cargado su configuración.</li>     <li><span class=&quot;lst-inline-token lst-inline-token--value&quot;>Running - Removed from Configuration</span> significa que el host virtual se eliminó de la configuración del servidor, pero sigue en servicio.</li> </ul>', '', '', '');

$_tipsdb['wsaddr'] = new DAttrHelp("Dirección", 'Una dirección de socket única usada por el backend WebSocket. Se admiten sockets IPv4, sockets IPv6 y Unix Domain Sockets (UDS). Los sockets IPv4 e IPv6 pueden usarse para comunicación por red. UDS solo puede usarse cuando el backend WebSocket reside en la misma máquina que el servidor.', ' Si el backend WebSocket se ejecuta en la misma máquina, se prefiere UDS. Si debe usar un socket IPv4 o IPv6, establezca la dirección IP en localhost o 127.0.0.1 para que el backend WebSocket no sea accesible desde otras máquinas.<br/> Unix Domain Sockets generalmente ofrecen mayor rendimiento que los sockets IPv4 o IPv6.', 'dirección IPv4/IPv6:puerto, UDS://ruta, o unix:ruta', '127.0.0.1:5434<br/>UDS://tmp/lshttpd/php.sock<br/>unix:/tmp/lshttpd/php.sock');

$_tipsdb['wsgiBin'] = new DAttrHelp("Ruta WSGI", 'Ruta al ejecutable LiteSpeed Python Web Server Gateway Interface (lswsgi).<br/><br/>Este ejecutable se crea al compilar Python con el módulo WSGI LSAPI de LiteSpeed.', '', 'Ruta absoluta', '');

$_tipsdb['wsgiDefaults'] = new DAttrHelp("Ajustes predeterminados de Python WSGI", 'Configuraciones predeterminadas para aplicaciones Python WSGI. Estos ajustes pueden sobrescribirse a nivel de contexto.', '', '', '');

$_tipsdb['wsuri'] = new DAttrHelp("URI", 'Especifica las URI que usarán este backend WebSocket. El tráfico hacia esta URI solo se reenviará al backend WebSocket cuando contenga una solicitud de upgrade WebSocket.<br/><br/>El tráfico sin esta solicitud de upgrade se reenviará automáticamente al contexto al que pertenece esta URI. Si no existe ningún contexto para esta URI, LSWS tratará este tráfico como si accediera a un contexto estático con la ubicación <span class=&quot;lst-inline-token lst-inline-token--value&quot;>$DOC_ROOT/URI</span>.', '', 'Una URI simple (que empiece por &quot;/&quot;). Si la URI termina con &quot;/&quot;, este backend WebSocket incluirá todas las sub-URI bajo esta URI.', 'Usar el proxy WebSocket junto con un contexto permite servir distintos tipos de tráfico de distintas formas en la misma página, optimizando así el rendimiento. Puede enviar el tráfico WebSocket al backend WebSocket y configurar un contexto estático para que LSWS sirva el contenido estático de la página, o un contexto LSAPI para que LSWS sirva contenido PHP (ambas opciones son más eficientes en LSWS que en el backend WebSocket).');

$_tipsdb['EDTP:GroupDBLocation'] = array('Se recomienda almacenar la base de datos bajo el directorio $SERVER_ROOT/conf/vhosts/$VH_NAME/.');
$_tipsdb['EDTP:UDBgroup'] = array('Si se agrega aquí información de grupos, se usará para la autorización de recursos y se ignorará cualquier configuración de base de datos de grupos relacionada con este usuario. Puede introducir varios grupos separados por comas. Los espacios se tratarán como parte del nombre del grupo.');
$_tipsdb['EDTP:accessControl_allow'] = array('Puede configurar control de acceso a nivel de servidor, virtual host y contexto. Si hay control de acceso a nivel de servidor, las reglas del virtual host se aplicarán después de satisfacer las reglas del servidor.');
$_tipsdb['EDTP:accessControl_deny'] = array('Para denegar el acceso desde cierta dirección, ponga &quot;ALL&quot; en la lista permitida y ponga la subred o IP en la lista denegada. Para permitir que solo cierta IP o subred acceda al sitio, ponga &quot;ALL&quot; en la lista denegada y especifique la dirección en la lista permitida.');
$_tipsdb['EDTP:accessDenyDir'] = array('Ingrese una ruta completa si desea denegar el acceso a un directorio específico; ingresar una ruta seguida de * deshabilitará todos los subdirectorios.');
$_tipsdb['EDTP:accessLog_fileName'] = array('La ruta del archivo de registro puede ser absoluta o relativa a $SERVER_ROOT.');
