$_tipsdb['EDTP:compressibleTypes'] = array('Compressible Types es una lista de tipos MIME comprimibles, separados por comas. Puede usar el comodín &quot;*&quot; para tipos MIME, como */*, text/*. Puede poner &quot;!&quot; delante para excluir ciertos tipos. El orden de la lista es importante si usa &quot;!&quot;. Por ejemplo, una lista como &quot;text/*, !text/css, !text/js&quot; comprimirá todos los archivos de texto excepto css y js.');
