$_tipsdb['EDTP:expiresDefault'] = array('La sintaxis Expires, &quot;A|Mseconds&quot;, significa despues del tiempo base (A o M) mas el tiempo especificado en segundos, el archivo expirara. &quot;A&quot; significa tiempo de acceso del cliente, &quot;M&quot; significa tiempo de modificacion del archivo. Puede reemplazar este valor predeterminado por distintos tipos MIME: A86400 significa que el archivo expirara despues de 1 dia segun el tiempo de acceso del cliente.');
$_tipsdb['EDTP:extAppAddress'] = array('La direccion puede ser una direccion de socket IPv4 &quot;IP:PORT&quot;, como 192.168.1.3:7777 y localhost:7777, o una direccion Unix domain socket &quot;UDS://path&quot;, como UDS://tmp/lshttpd/myfcgi.sock. UDS queda dentro del chroot en un entorno chroot. Para aplicaciones locales, se prefiere Unix domain socket por seguridad y mejor rendimiento. Si debe usar un socket IPv4, establezca la parte IP en localhost o 127.0.0.1, para que la aplicacion no sea accesible desde otras maquinas.');
$_tipsdb['EDTP:extAppName'] = array('Asigne un nombre facil de recordar; otros lugares haran referencia a esta app por su nombre.');
