$_tipsdb['EDTP:extraHeaders'] = array('La opcion Header Operations es compatible hacia atras con la antigua sintaxis &#039;header_name: value1,value2,...&#039;, equivalente a establecer el encabezado y los valores con la directiva &#039;Header&#039;.');
